boolean process(Token t, HtmlTreeBuilder tb) {
    ArrayList<Element> stack;
    Element el;

    switch (t.type) {
        case Character: {
            Token.Character c = t.asCharacter();
            if (c.getData().equals(nullString)) {
                // todo confirm that check
                tb.error(this);
                return false;
            } else if (tb.framesetOk() && isWhitespace(c)) { // don't check if whitespace if frames already closed
                tb.reconstructFormattingElements();
                tb.insert(c);
            } else {
                tb.reconstructFormattingElements();
                tb.insert(c);
                tb.framesetOk(false);
            }
            break;
        }
        case Comment: {
            tb.insert(t.asComment());
            break;
        }
        case Doctype: {
            tb.error(this);
            return false;
        }
        case StartTag:
            Token.StartTag startTag = t.asStartTag();
            String name = startTag.normalName();

            switch (name) {
                case "a":
                    if (tb.getActiveFormattingElement("a") != null) {
                        tb.error(this);
                        tb.processEndTag("a");

                        // still on stack?
                        Element remainingA = tb.getFromStack("a");
                        if (remainingA != null) {
                            tb.removeFromActiveFormattingElements(remainingA);
                            tb.removeFromStack(remainingA);
                        }
                    }
                    tb.reconstructFormattingElements();
                    Element a = tb.insert(startTag);
                    tb.pushActiveFormattingElements(a);
                    break;
                case "span":
                    // same as final else, but short circuits lots of checks
                    tb.reconstructFormattingElements();
                    tb.insert(startTag);
                    break;
                case "li":
                    tb.framesetOk(false);
                    stack = tb.getStack();
                    for (int i = stack.size() - 1; i > 0; i--) {
                        el = stack.get(i);
                        if (el.normalName().equals("li")) {
                            tb.processEndTag("li");
                            break;
                        }
                        if (tb.isSpecial(el) && !StringUtil.inSorted(el.normalName(), Constants.InBodyStartLiBreakers))
                            break;
                    }
                    if (tb.inButtonScope("p")) {
                        tb.processEndTag("p");
                    }
                    tb.insert(startTag);
                    break;
                case "html":
                    tb.error(this);
                    // merge attributes onto real html
                    Element html = tb.getStack().get(0);
                    for (Attribute attribute : startTag.getAttributes()) {
                        if (!html.hasAttr(attribute.getKey()))
                            html.attributes().put(attribute);
                    }
                    break;
                case "body":
                    tb.error(this);
                    stack = tb.getStack();
                    if (stack.size() == 1 || (stack.size() > 2 && !stack.get(1).normalName().equals("body"))) {
                        // only in fragment case
                        return false; // ignore
                    } else {
                        tb.framesetOk(false);
                        Element body = stack.get(1);
                        for (Attribute attribute : startTag.getAttributes()) {
                            if (!body.hasAttr(attribute.getKey()))
                                body.attributes().put(attribute);
                        }
                    }
                    break;
                case "frameset":
                    tb.error(this);
                    stack = tb.getStack();
                    if (stack.size() == 1 || (stack.size() > 2 && !stack.get(1).normalName().equals("body"))) {
                        // only in fragment case
                        return false; // ignore
                    } else if (!tb.framesetOk()) {
                        return false; // ignore frameset
                    } else {
                        Element second = stack.get(1);
                        if (second.parent() != null)
                            second.remove();
                        // pop up to html element
                        while (stack.size() > 1)
                            stack.remove(stack.size() - 1);
                        tb.insert(startTag);
                        tb.transition(InFrameset);
                    }
                    break;
                case "form":
                    if (tb.getFormElement() != null) {
                        tb.error(this);
                        return false;
                    }
                    if (tb.inButtonScope("p")) {
                        tb.processEndTag("p");
                    }
                    tb.insertForm(startTag, true);
                    break;
                case "plaintext":
                    if (tb.inButtonScope("p")) {
                        tb.processEndTag("p");
                    }
                    tb.insert(startTag);
                    tb.tokeniser.transition(TokeniserState.PLAINTEXT); // once in, never gets out
                    break;
                case "button":
                    if (tb.inButtonScope("button")) {
                        // close and reprocess
                        tb.error(this);
                        tb.processEndTag("button");
                        tb.process(startTag);
                    } else {
                        tb.reconstructFormattingElements();
                        tb.insert(startTag);
                        tb.framesetOk(false);
                    }
                    break;
                case "nobr":
                    tb.reconstructFormattingElements();
                    if (tb.inScope("nobr")) {
                        tb.error(this);
                        tb.processEndTag("nobr");
                        tb.reconstructFormattingElements();
                    }
                    el = tb.insert(startTag);
                    tb.pushActiveFormattingElements(el);
                    break;
                case "table":
                    if (tb.getDocument().quirksMode() != Document.QuirksMode.quirks && tb.inButtonScope("p")) {
                        tb.processEndTag("p");
                    }
                    tb.insert(startTag);
                    tb.framesetOk(false);
                    tb.transition(InTable);
                    break;
                case "input":
                    tb.reconstructFormattingElements();
                    el = tb.insertEmpty(startTag);
                    if (!el.attr("type").equalsIgnoreCase("hidden"))
                        tb.framesetOk(false);
                    break;
                case "hr":
                    if (tb.inButtonScope("p")) {
                        tb.processEndTag("p");
                    }
                    tb.insertEmpty(startTag);
                    tb.framesetOk(false);
                    break;
                case "image":
                    if (tb.getFromStack("svg") == null)
                        return tb.process(startTag.name("img")); // change <image> to <img>, unless in svg
                    else
                        tb.insert(startTag);
                    break;
                case "isindex":
                    // how much do we care about the early 90s?
                    tb.error(this);
                    if (tb.getFormElement() != null)
                        return false;

                    tb.processStartTag("form");
                    if (startTag.attributes.hasKey("action")) {
                        Element form = tb.getFormElement();
                        form.attr("action", startTag.attributes.get("action"));
                    }
                    tb.processStartTag("hr");
                    tb.processStartTag("label");
                    // hope you like english.
                    String prompt = startTag.attributes.hasKey("prompt") ?
                        startTag.attributes.get("prompt") :
                        "This is a searchable index. Enter search keywords: ";

                    tb.process(new Token.Character().data(prompt));

                    // input
                    Attributes inputAttribs = new Attributes();
                    for (Attribute attr : startTag.attributes) {
                        if (!StringUtil.inSorted(attr.getKey(), Constants.InBodyStartInputAttribs))
                            inputAttribs.put(attr);
                    }
                    inputAttribs.put("name", "isindex");
                    tb.processStartTag("input", inputAttribs);
                    tb.processEndTag("label");
                    tb.processStartTag("hr");
                    tb.processEndTag("form");
                    break;
                case "textarea":
                    tb.insert(startTag);
                    if (!startTag.isSelfClosing()) {
                        tb.tokeniser.transition(TokeniserState.Rcdata);
                        tb.markInsertionMode();
                        tb.framesetOk(false);
                        tb.transition(Text);
                    }
                    break;
                case "xmp":
                    if (tb.inButtonScope("p")) {
                        tb.processEndTag("p");
                    }
                    tb.reconstructFormattingElements();
                    tb.framesetOk(false);
                    handleRawtext(startTag, tb);
                    break;
                case "iframe":
                    tb.framesetOk(false);
                    handleRawtext(startTag, tb);
                    break;
                case "noembed":
                    // also handle noscript if script enabled
                    handleRawtext(startTag, tb);
                    break;
                case "select":
                    tb.reconstructFormattingElements();
                    tb.insert(startTag);
                    tb.framesetOk(false);

                    HtmlTreeBuilderState state = tb.state();
                    if (state.equals(InTable) || state.equals(InCaption) || state.equals(InTableBody) || state.equals(InRow) || state.equals(InCell))
                        tb.transition(InSelectInTable);
                    else
                        tb.transition(InSelect);
                    break;
                case "math":
                    tb.reconstructFormattingElements();
                    // todo: handle A start tag whose tag name is "math" (i.e. foreign, mathml)
                    tb.insert(startTag);
                    break;
                case "svg":
                    tb.reconstructFormattingElements();
                    // todo: handle A start tag whose tag name is "svg" (xlink, svg)
                    tb.insert(startTag);
                    break;
                // static final String[] Headings = new String[]{"h1", "h2", "h3", "h4", "h5", "h6"};
                case "h1":
                case "h2":
                case "h3":
                case "h4":
                case "h5":
                case "h6":
                    if (tb.inButtonScope("p")) {
                        tb.processEndTag("p");
                    }
                    if (StringUtil.inSorted(tb.currentElement().normalName(), Constants.Headings)) {
                        tb.error(this);
                        tb.pop();
                    }
                    tb.insert(startTag);
                    break;
                // static final String[] InBodyStartPreListing = new String[]{"listing", "pre"};
                case "pre":
                case "listing":
                    if (tb.inButtonScope("p")) {
                        tb.processEndTag("p");
                    }
                    tb.insert(startTag);
                    tb.reader.matchConsume("\n"); // ignore LF if next token
                    tb.framesetOk(false);
                    break;
                // static final String[] DdDt = new String[]{"dd", "dt"};
                case "dd":
                case "dt":
                    tb.framesetOk(false);
                    stack = tb.getStack();
                    for (int i = stack.size() - 1; i > 0; i--) {
                        el = stack.get(i);
                        if (StringUtil.inSorted(el.normalName(), Constants.DdDt)) {
                            tb.processEndTag(el.normalName());
                            break;
                        }
                        if (tb.isSpecial(el) && !StringUtil.inSorted(el.normalName(), Constants.InBodyStartLiBreakers))
                            break;
                    }
                    if (tb.inButtonScope("p")) {
                        tb.processEndTag("p");
                    }
                    tb.insert(startTag);
                    break;
                // static final String[] InBodyStartOptions = new String[]{"optgroup", "option"};
                case "optgroup":
                case "option":
                    if (tb.currentElement().normalName().equals("option"))
                        tb.processEndTag("option");
                    tb.reconstructFormattingElements();
                    tb.insert(startTag);
                    break;
                // static final String[] InBodyStartRuby = new String[]{"rp", "rt"};
                case "rp":
                case "rt":
                    if (tb.inScope("ruby")) {
                        tb.generateImpliedEndTags();
                        if (!tb.currentElement().normalName().equals("ruby")) {
                            tb.error(this);
                            tb.popStackToBefore("ruby"); // i.e. close up to but not include name
                        }
                        tb.insert(startTag);
                    }
                    // todo - is this right? drops rp, rt if ruby not in scope?
                    break;
                default:
                    // todo - bring scan groups in if desired
                    if (StringUtil.inSorted(name, Constants.InBodyStartEmptyFormatters)) {
                        tb.reconstructFormattingElements();
                        tb.insertEmpty(startTag);
                        tb.framesetOk(false);
                    } else if (StringUtil.inSorted(name, Constants.InBodyStartPClosers)) {
                        if (tb.inButtonScope("p")) {
                            tb.processEndTag("p");
                        }
                        tb.insert(startTag);
                    } else if (StringUtil.inSorted(name, Constants.InBodyStartToHead)) {
                        return tb.process(t, InHead);
                    } else if (StringUtil.inSorted(name, Constants.Formatters)) {
                        tb.reconstructFormattingElements();
                        el = tb.insert(startTag);
                        tb.pushActiveFormattingElements(el);
                    } else if (StringUtil.inSorted(name, Constants.InBodyStartApplets)) {
                        tb.reconstructFormattingElements();
                        tb.insert(startTag);
                        tb.insertMarkerToFormattingElements();
                        tb.framesetOk(false);
                    } else if (StringUtil.inSorted(name, Constants.InBodyStartMedia)) {
                        tb.insertEmpty(startTag);
                    } else if (StringUtil.inSorted(name, Constants.InBodyStartDrop)) {
                        tb.error(this);
                        return false;
                    } else {
                        tb.reconstructFormattingElements();
                        tb.insert(startTag);
                    }
            }
            break;

        case EndTag:
            Token.EndTag endTag = t.asEndTag();
            name = endTag.normalName();
            switch (name) {
                case "sarcasm": // *sigh*
                case "span":
                    // same as final fall through, but saves short circuit
                    return anyOtherEndTag(t, tb);
                case "li":
                    if (!tb.inListItemScope(name)) {
                        tb.error(this);
                        return false;
                    } else {
                        tb.generateImpliedEndTags(name);
                        if (!tb.currentElement().normalName().equals(name))
                            tb.error(this);
                        tb.popStackToClose(name);
                    }
                    break;
                case "body":
                    if (!tb.inScope("body")) {
                        tb.error(this);
                        return false;
                    } else {
                        // todo: error if stack contains something not dd, dt, li, optgroup, option, p, rp, rt, tbody, td, tfoot, th, thead, tr, body, html
                        tb.transition(AfterBody);
                    }
                    break;
                case "html":
                    boolean notIgnored = tb.processEndTag("body");
                    if (notIgnored)
                        return tb.process(endTag);
                    break;
                case "form":
                    Element currentForm = tb.getFormElement();
                    tb.setFormElement(null);
                    if (currentForm == null || !tb.inScope(name)) {
                        tb.error(this);
                        return false;
                    } else {
                        tb.generateImpliedEndTags();
                        if (!tb.currentElement().normalName().equals(name))
                            tb.error(this);
                        // remove currentForm from stack. will shift anything under up.
                        tb.removeFromStack(currentForm);
                    }
                    break;
                case "p":
                    if (!tb.inButtonScope(name)) {
                        tb.error(this);
                        tb.processStartTag(name); // if no p to close, creates an empty <p></p>
                        return tb.process(endTag);
                    } else {
                        tb.generateImpliedEndTags(name);
                        if (!tb.currentElement().normalName().equals(name))
                            tb.error(this);
                        tb.popStackToClose(name);
                    }
                    break;
                case "dd":
                case "dt":
                    if (!tb.inScope(name)) {
                        tb.error(this);
                        return false;
                    } else {
                        tb.generateImpliedEndTags(name);
                        if (!tb.currentElement().normalName().equals(name))
                            tb.error(this);
                        tb.popStackToClose(name);
                    }
                    break;
                case "h1":
                case "h2":
                case "h3":
                case "h4":
                case "h5":
                case "h6":
                    if (!tb.inScope(Constants.Headings)) {
                        tb.error(this);
                        return false;
                    } else {
                        tb.generateImpliedEndTags(name);
                        if (!tb.currentElement().normalName().equals(name))
                            tb.error(this);
                        tb.popStackToClose(Constants.Headings);
                    }
                    break;
                case "br":
                    tb.error(this);
                    tb.processStartTag("br");
                    return false;
                default:
                    // todo - move rest to switch if desired
                    if (StringUtil.inSorted(name, Constants.InBodyEndAdoptionFormatters)) {
                        // Adoption Agency Algorithm.
                        for (int i = 0; i < 8; i++) {
                            Element formatEl = tb.getActiveFormattingElement(name);
                            if (formatEl == null)
                                return anyOtherEndTag(t, tb);
                            else if (!tb.onStack(formatEl)) {
                                tb.error(this);
                                tb.removeFromActiveFormattingElements(formatEl);
                                return true;
                            } else if (!tb.inScope(formatEl.normalName())) {
                                tb.error(this);
                                return false;
                            } else if (tb.currentElement() != formatEl)
                                tb.error(this);

                            Element furthestBlock = null;
                            Element commonAncestor = null;
                            boolean seenFormattingElement = false;
                            stack = tb.getStack();
                            // the spec doesn't limit to < 64, but in degenerate cases (9000+ stack depth) this prevents
                            // run-aways
                            final int stackSize = stack.size();
                            for (int si = 0; si < stackSize && si < 64; si++) {
                                el = stack.get(si);
                                if (el == formatEl) {
                                    commonAncestor = stack.get(si - 1);
                                    seenFormattingElement = true;
                                } else if (seenFormattingElement && tb.isSpecial(el)) {
                                    furthestBlock = el;
                                    break;
                                }
                            }
                            if (furthestBlock == null) {
                                tb.popStackToClose(formatEl.normalName());
                                tb.removeFromActiveFormattingElements(formatEl);
                                return true;
                            }

                            // todo: Let a bookmark note the position of the formatting element in the list of active formatting elements relative to the elements on either side of it in the list.
                            // does that mean: int pos of format el in list?
                            Element node = furthestBlock;
                            Element lastNode = furthestBlock;
                            for (int j = 0; j < 3; j++) {
                                if (tb.onStack(node))
                                    node = tb.aboveOnStack(node);
                                if (!tb.isInActiveFormattingElements(node)) { // note no bookmark check
                                    tb.removeFromStack(node);
                                    continue;
                                } else if (node == formatEl)
                                    break;

                                Element replacement = new Element(Tag.valueOf(node.nodeName(), ParseSettings.preserveCase), tb.getBaseUri());
                                // case will follow the original node (so honours ParseSettings)
                                tb.replaceActiveFormattingElement(node, replacement);
                                tb.replaceOnStack(node, replacement);
                                node = replacement;

                                //noinspection StatementWithEmptyBody
                                if (lastNode == furthestBlock) {
                                    // todo: move the aforementioned bookmark to be immediately after the new node in the list of active formatting elements.
                                    // not getting how this bookmark both straddles the element above, but is inbetween here...
                                }
                                if (lastNode.parent() != null)
                                    lastNode.remove();
                                node.appendChild(lastNode);

                                lastNode = node;
                            }

                            if (StringUtil.inSorted(commonAncestor.normalName(), Constants.InBodyEndTableFosters)) {
                                if (lastNode.parent() != null)
                                    lastNode.remove();
                                tb.insertInFosterParent(lastNode);
                            } else {
                                if (lastNode.parent() != null)
                                    lastNode.remove();
                                commonAncestor.appendChild(lastNode);
                            }

                            Element adopter = new Element(formatEl.tag(), tb.getBaseUri());
                            adopter.attributes().addAll(formatEl.attributes());
                            Node[] childNodes = furthestBlock.childNodes().toArray(new Node[0]);
                            for (Node childNode : childNodes) {
                                adopter.appendChild(childNode); // append will reparent. thus the clone to avoid concurrent mod.
                            }
                            furthestBlock.appendChild(adopter);
                            tb.removeFromActiveFormattingElements(formatEl);
                            // todo: insert the new element into the list of active formatting elements at the position of the aforementioned bookmark.
                            tb.removeFromStack(formatEl);
                            tb.insertOnStackAfter(furthestBlock, adopter);
                        }
                    } else if (StringUtil.inSorted(name, Constants.InBodyEndClosers)) {
                        if (!tb.inScope(name)) {
                            // nothing to close
                            tb.error(this);
                            return false;
                        } else {
                            tb.generateImpliedEndTags();
                            if (!tb.currentElement().normalName().equals(name))
                                tb.error(this);
                            tb.popStackToClose(name);
                        }
                    } else if (StringUtil.inSorted(name, Constants.InBodyStartApplets)) {
                        if (!tb.inScope("name")) {
                            if (!tb.inScope(name)) {
                                tb.error(this);
                                return false;
                            }
                            tb.generateImpliedEndTags();
                            if (!tb.currentElement().normalName().equals(name))
                                tb.error(this);
                            tb.popStackToClose(name);
                            tb.clearFormattingElementsToLastMarker();
                        }
                    } else {
                        return anyOtherEndTag(t, tb);
                    }
            }
            break;
        case EOF:
            // todo: error if stack contains something not dd, dt, li, p, tbody, td, tfoot, th, thead, tr, body, html
            // stop parsing
            break;
    }
    return true;
}

/**
 * Loads a file to a Document.
 * @param in file to load
 * @param charsetName character set of input
 * @param baseUri base URI of document, to resolve relative links against
 * @return Document
 * @throws IOException on IO error
 */
public static Document load(File in, String charsetName, String baseUri) throws IOException {
    FileInputStream inStream = null;
    try {
        inStream = new FileInputStream(in);
        ByteBuffer byteData = readToByteBuffer(inStream);
        return parseByteData(byteData, charsetName, baseUri, Parser.htmlParser());
    } finally {
        if (inStream != null)
            inStream.close();
    }
}

public void run() {
  running = tryToConnect(new InetSocketAddress(uri.getHost(), getPort()));

  while (this.running) {
    try {
      selector.select();
      Set<SelectionKey> keys = selector.selectedKeys();
      Iterator<SelectionKey> i = keys.iterator();

      while (i.hasNext()) {
        SelectionKey key = i.next();
        i.remove();

        if (key.isConnectable()) {
          finishConnect();
        }

        if (key.isReadable()) {
          conn.handleRead();
        }
      }
    } catch (IOException ex) {
      ex.printStackTrace();
    } catch (NoSuchAlgorithmException ex) {
      ex.printStackTrace();
    }
  }

  //System.err.println("WebSocketClient thread ended!");
}

/**
 * Create a new element by tag name, and add it as the first child.
 *
 * @param tagName the name of the tag (e.g. {@code div}).
 * @return the new element, to allow you to add content to it, e.g.:
 *  {@code parent.prependElement("h1").attr("id", "header").text("Welcome");}
 */
public Element prependElement(String tagName) {
    Element child = new Element(Tag.valueOf(tagName, NodeUtils.parser(this).settings()), baseUri());
    prependChild(child);
    return child;
}

/**
 * Loads and parses a file to a Document. Files that are compressed with gzip (and end in {@code .gz} or {@code .z})
 * are supported in addition to uncompressed files.
 *
 * @param file file to load
 * @param charsetName (optional) character set of input; specify {@code null} to attempt to autodetect. A BOM in
 *     the file will always override this setting.
 * @param baseUri base URI of document, to resolve relative links against
 * @param parser alternate {@link Parser#xmlParser() parser} to use.

 * @return Document
 * @throws IOException on IO error
 * @since 1.14.2
 */
public static Document load(File file, @Nullable String charsetName, String baseUri, Parser parser) throws IOException {
    InputStream stream = new FileInputStream(file);
    String name = Normalizer.lowerCase(file.getName());
    if (name.endsWith(".gz") || name.endsWith(".z")) {
        // unfortunately file input streams don't support marks (why not?), so we will close and reopen after read
        boolean zipped;
        try {
            zipped = (stream.read() == 0x1f && stream.read() == 0x8b); // gzip magic bytes
        } finally {
            stream.close();

        }
        stream = zipped ? new GZIPInputStream(new FileInputStream(file)) : new FileInputStream(file);
    }
    return parseInputStream(stream, charsetName, baseUri, parser);
}

    /**
	 * Process the frame if it is a binary frame
	 * @param webSocketImpl the websocket impl
	 * @param frame the frame
	 */
	private void processFrameBinary(WebSocketImpl webSocketImpl, Framedata frame) {
		try {
			webSocketImpl.getWebSocketListener().onWebsocketMessage( webSocketImpl, frame.getPayloadData() );
		} catch ( RuntimeException e ) {
			logRuntimeException(webSocketImpl, e);
		}
	}

private void text(StringBuilder accum) {
    for (Node child : childNodes) {
        if (child instanceof TextNode) {
            TextNode textNode = (TextNode) child;
            String text = textNode.getWholeText();

            if (!preserveWhitespace()) {
                text = TextNode.normaliseWhitespace(text);
                if (TextNode.lastCharIsWhitespace(accum))
                    text = TextNode.stripLeadingWhitespace(text);
            }
            accum.append(text);

        } else if (child instanceof Element) {
            Element element = (Element) child;
            if (accum.length() > 0 && element.isBlock() && !TextNode.lastCharIsWhitespace(accum))
                accum.append(" ");
            element.text(accum);
        }
    }
}

@Override public Document parse() throws IOException {
    InputStream stream = prepareParse();
    Document doc = DataUtil.parseInputStream(stream, charset, url.toExternalForm(), req.parser());
    doc.connection(new HttpConnection(req, this)); // because we're static, don't have the connection obj. // todo - maybe hold in the req?
    charset = doc.outputSettings().charset().name(); // update charset from meta-equiv, possibly
    safeClose();
    return doc;
}

/**
 * Process the frame if it is the last frame
 * @param webSocketImpl the websocket impl
 * @param frame the frame
 * @throws InvalidDataException if there is a protocol error
 */
private void processFrameIsFin(WebSocketImpl webSocketImpl, Framedata frame) throws InvalidDataException {
	if( currentContinuousFrame == null ) {
		log.trace( "Protocol error: Previous continuous frame sequence not completed." );
		throw new InvalidDataException( CloseFrame.PROTOCOL_ERROR, "Continuous frame sequence was not started." );
	}
	addToBufferList(frame.getPayloadData());
	checkBufferLimit();
	if( currentContinuousFrame.getOpcode() == Opcode.TEXT ) {
		((FramedataImpl1) currentContinuousFrame).setPayload( getPayloadFromByteBufferList() );
		((FramedataImpl1) currentContinuousFrame).isValid();
		try {
			webSocketImpl.getWebSocketListener().onWebsocketMessage( webSocketImpl, Charsetfunctions.stringUtf8( currentContinuousFrame.getPayloadData() ) );
		} catch ( RuntimeException e ) {
			logRuntimeException(webSocketImpl, e);
		}
	} else if( currentContinuousFrame.getOpcode() == Opcode.BINARY ) {
		((FramedataImpl1) currentContinuousFrame).setPayload( getPayloadFromByteBufferList() );
		((FramedataImpl1) currentContinuousFrame).isValid();
		try {
			webSocketImpl.getWebSocketListener().onWebsocketMessage( webSocketImpl, currentContinuousFrame.getPayloadData() );
		} catch ( RuntimeException e ) {
			logRuntimeException(webSocketImpl, e);
		}
	}
	currentContinuousFrame = null;
	clearBufferList();
}

/**
 * Should be called when a Selector has a key that is writable for this
 * WebSocketImpl's SocketChannel connection.
 * 
 * @throws IOException
 *             When socket related I/O errors occur.
 * @throws InterruptedException
 */
public synchronized void decode() throws IOException {
	if( !socketBuffer.hasRemaining() )
		return;
	if( DEBUG )
		System.out.println( "process(" + socketBuffer.remaining() + "): {" + ( socketBuffer.remaining() > 1000 ? "too big to display" : new String( socketBuffer.array(), socketBuffer.position(), socketBuffer.remaining() ) ) + "}" );
	if( !handshakeComplete ) {
		if( draft == null ) {
			HandshakeState isflashedgecase = isFlashEdgeCase( socketBuffer );
			if( isflashedgecase == HandshakeState.MATCHED ) {
				channelWriteDirect( ByteBuffer.wrap( Charsetfunctions.utf8Bytes( wsl.getFlashPolicy( this ) ) ) );
				closeDirect( CloseFrame.FLASHPOLICY, "" );
				return;
			} else if( isflashedgecase == HandshakeState.MATCHING ) {
				return;
			}
		}
		HandshakeState handshakestate = null;
		socketBuffer.mark();
		try {
			if( role == Role.SERVER ) {
				if( draft == null ) {
					for( Draft d : known_drafts ) {
						try {
							d.setParseMode( role );
							socketBuffer.reset();
							Handshakedata tmphandshake = d.translateHandshake( socketBuffer );
							if( tmphandshake instanceof ClientHandshake == false ) {
								closeConnection( CloseFrame.PROTOCOL_ERROR, "wrong http function", false );
								return;
							}
							ClientHandshake handshake = (ClientHandshake) tmphandshake;
							handshakestate = d.acceptHandshakeAsServer( handshake );
							if( handshakestate == HandshakeState.MATCHED ) {
								ServerHandshakeBuilder response;
								try {
									response = wsl.onWebsocketHandshakeReceivedAsServer( this, d, handshake );
								} catch ( InvalidDataException e ) {
									closeConnection( e.getCloseCode(), e.getMessage(), false );
									return;
								}
								writeDirect( d.createHandshake( d.postProcessHandshakeResponseAsServer( handshake, response ), role ) );
								draft = d;
								open( handshake );
								decode();
								return;
							} else if( handshakestate == HandshakeState.MATCHING ) {
								if( draft != null ) {
									throw new InvalidHandshakeException( "multible drafts matching" );
								}
								draft = d;
							}
						} catch ( InvalidHandshakeException e ) {
							// go on with an other draft
						} catch ( IncompleteHandshakeException e ) {
							if( socketBuffer.limit() == socketBuffer.capacity() ) {
								close( CloseFrame.TOOBIG, "handshake is to big" );
							}
							// read more bytes for the handshake
							socketBuffer.position( socketBuffer.limit() );
							socketBuffer.limit( socketBuffer.capacity() );
							return;
						}
					}
					if( draft == null ) {
						close( CloseFrame.PROTOCOL_ERROR, "no draft matches" );
					}
					return;
				} else {
					// special case for multiple step handshakes
					Handshakedata tmphandshake = draft.translateHandshake( socketBuffer );
					if( tmphandshake instanceof ClientHandshake == false ) {
						closeConnection( CloseFrame.PROTOCOL_ERROR, "wrong http function", false );
						return;
					}
					ClientHandshake handshake = (ClientHandshake) tmphandshake;
					handshakestate = draft.acceptHandshakeAsServer( handshake );

					if( handshakestate == HandshakeState.MATCHED ) {
						open( handshake );
						decode();
					} else if( handshakestate != HandshakeState.MATCHING ) {
						close( CloseFrame.PROTOCOL_ERROR, "the handshake did finaly not match" );
					}
					return;
				}
			} else if( role == Role.CLIENT ) {
				draft.setParseMode( role );
				Handshakedata tmphandshake = draft.translateHandshake( socketBuffer );
				if( tmphandshake instanceof ServerHandshake == false ) {
					closeConnection( CloseFrame.PROTOCOL_ERROR, "Wwrong http function", false );
					return;
				}
				ServerHandshake handshake = (ServerHandshake) tmphandshake;
				handshakestate = draft.acceptHandshakeAsClient( handshakerequest, handshake );
				if( handshakestate == HandshakeState.MATCHED ) {
					try {
						wsl.onWebsocketHandshakeReceivedAsClient( this, handshakerequest, handshake );
					} catch ( InvalidDataException e ) {
						closeConnection( e.getCloseCode(), e.getMessage(), false );
						return;
					}
					open( handshake );
					decode();
				} else if( handshakestate == HandshakeState.MATCHING ) {
					return;
				} else {
					close( CloseFrame.PROTOCOL_ERROR, "draft " + draft + " refuses handshake" );
				}
			}
		} catch ( InvalidHandshakeException e ) {
			close( e );
		}
	} else {
		// Receiving frames
		List<Framedata> frames;
		try {
			frames = draft.translateFrame( socketBuffer );
			for( Framedata f : frames ) {
				if( DEBUG )
					System.out.println( "matched frame: " + f );
				Opcode curop = f.getOpcode();
				if( curop == Opcode.CLOSING ) {
					int code = CloseFrame.NOCODE;
					String reason = "";
					if( f instanceof CloseFrame ) {
						CloseFrame cf = (CloseFrame) f;
						code = cf.getCloseCode();
						reason = cf.getMessage();
					}
					if( closeHandshakeSent ) {
						// complete the close handshake by disconnecting
						closeConnection( code, reason, true );
					} else {
						// echo close handshake
						if( draft.getCloseHandshakeType() == CloseHandshakeType.TWOWAY )
							close( code, reason );
						closeConnection( code, reason, false );
					}
					continue;
				} else if( curop == Opcode.PING ) {
					wsl.onWebsocketPing( this, f );
					continue;
				} else if( curop == Opcode.PONG ) {
					wsl.onWebsocketPong( this, f );
					continue;
				} else {
					// process non control frames
					if( currentframe == null ) {
						if( f.getOpcode() == Opcode.CONTINIOUS ) {
							throw new InvalidFrameException( "unexpected continious frame" );
						} else if( f.isFin() ) {
							// receive normal onframe message
							deliverMessage( f );
						} else {
							// remember the frame whose payload is about to be continued
							currentframe = f;
						}
					} else if( f.getOpcode() == Opcode.CONTINIOUS ) {
						currentframe.append( f );
						if( f.isFin() ) {
							deliverMessage( currentframe );
							currentframe = null;
						}
					} else {
						throw new InvalidDataException( CloseFrame.PROTOCOL_ERROR, "non control or continious frame expected" );
					}
				}
			}
		} catch ( InvalidDataException e1 ) {
			wsl.onWebsocketError( this, e1 );
			close( e1 );
			return;
		}
	}

}

protected void initialiseParse(String input, String baseUri, ParseErrorList errors) {
    Validate.notNull(input, "String input must not be null");
    reader = new CharacterReader(input);
    init(baseUri, errors);
}

void outerHtmlHead(final Appendable accum, int depth, final Document.OutputSettings out) throws IOException {
    if (out.prettyPrint() && (tag.formatAsBlock() || (parent() != null && parent().tag().formatAsBlock()) || out.outline())) {
        if (accum instanceof StringBuilder) {
            if (((StringBuilder) accum).length() > 0)
                indent(accum, depth, out);
        } else {
            indent(accum, depth, out);
        }
    }
    accum.append('<').append(tagName());
    if (attributes != null) attributes.html(accum, out);

    // selfclosing includes unknown tags, isEmpty defines tags that are always empty
    if (childNodes.isEmpty() && tag.isSelfClosing()) {
        if (out.syntax() == Document.OutputSettings.Syntax.html && tag.isEmpty())
            accum.append('>');
        else
            accum.append(" />"); // <img> in html, <img /> in xml
    }
    else
        accum.append('>');
}

void runParser() {
    final Tokeniser tokeniser = this.tokeniser;
    final Token.TokenType eof = Token.TokenType.EOF;

    while (true) {
        Token token = tokeniser.read();
        currentToken = token;
        process(token);
        if (token.type == eof)
            break;
        token.reset();
    }

    // once we hit the end, pop remaining items off the stack
    while (!stack.isEmpty()) pop();
}

/**
 Create a new, empty Document.
 @param baseUri base URI of document
 @see org.jsoup.Jsoup#parse
 @see #createShell
 */
public Document(String baseUri) {
    super(Tag.valueOf("#root", ParseSettings.htmlDefault), baseUri);
    this.location = baseUri;
    this.parser = Parser.htmlParser(); // default, but overridable
}

private void matches(boolean own) {
    String query = own ? ":matchesOwn" : ":matches";
    tq.consume(query);
    String regex = tq.chompBalanced('(', ')'); // don't unescape, as regex bits will be escaped
    Validate.notEmpty(regex, query + "(regex) query must not be empty");

    evals.add(own
        ? new Evaluator.MatchesOwn(Pattern.compile(regex))
        : new Evaluator.Matches(Pattern.compile(regex)));
}

Document parse(Reader input, String baseUri, Parser parser) {
    initialiseParse(input, baseUri, parser);
    runParser();

    // tidy up - as the Parser and Treebuilder are retained in document for settings / fragments
    reader.close();
    reader = null;
    tokeniser = null;
    stack = null;
    seenTags = null;

    return doc;
}

/**
 * @return True if all of the text was sent to the client by this thread.
 *    False if some of the text had to be buffered to be sent later.
 */
public boolean send(String text) throws IOException {
  if (!this.handshakeComplete) throw new NotYetConnectedException();
  if (text == null) throw new NullPointerException("Cannot send 'null' data to a WebSocket.");

  // Get 'text' into a WebSocket "frame" of bytes
  byte[] textBytes = text.getBytes(UTF8_CHARSET);
  ByteBuffer b = ByteBuffer.allocate(textBytes.length + 2);
  b.put(START_OF_FRAME);
  b.put(textBytes);
  b.put(END_OF_FRAME);
  b.rewind();

  // See if we have any backlog that needs to be sent first
  if (handleWrite()) {
    // Write the ByteBuffer to the socket
    this.socketChannel.write(b);
  }

  // If we didn't get it all sent, add it to the buffer of buffers
  if (b.remaining() > 0) {
    if (!this.bufferQueue.offer(b)) {
      throw new IOException("Buffers are full, message could not be sent to" +
          this.socketChannel.socket().getRemoteSocketAddress());
    }
    return false;
  }

  return true;
}

@Override
HttpConnection.Response execute() throws IOException {
    try {
        HttpRequest.Builder reqBuilder =
            HttpRequest.newBuilder(req.url.toURI()).method(req.method.name(), requestBody(req));
        if (req.timeout() > 0) reqBuilder.timeout(
            Duration.ofMillis(req.timeout())); // infinite if unset (UrlConnection / jsoup uses 0 for same)
        CookieUtil.applyCookiesToRequest(req, reqBuilder::header);

        // headers:
        req.multiHeaders().forEach((key, values) -> {
            values.forEach(value -> reqBuilder.header(key, value));
        });

        if (req.proxy() != null) perRequestProxy.set(req.proxy()); // set up per request proxy
        HttpRequest hReq = reqBuilder.build();
        HttpClient client = client();
        hRes = client.send(hReq, HttpResponse.BodyHandlers.ofInputStream());
        HttpHeaders headers = hRes.headers();

        // set up the response
        Response res = new Response(req);
        res.executor = this;
        res.method = Connection.Method.valueOf(hRes.request().method());
        res.url = hRes.uri().toURL();
        res.statusCode = hRes.statusCode();
        res.contentType = headers.firstValue("content-type").orElse("");
        long length = headers.firstValueAsLong("content-length").orElse(-1);
        res.contentLength = length < Integer.MAX_VALUE ? (int) length : -1;
        res.prepareResponse(headers.map(), prevRes);

        return res;
    } catch (IOException e) {
        safeClose();
        throw e;
    } catch (InterruptedException e) {
        safeClose();
        Thread.currentThread().interrupt();
        throw new IOException(e);
    } catch (URISyntaxException e) {
        throw new IllegalArgumentException("Malformed URL: " + req.url, e);
    } finally {
        // detach per request proxy
        perRequestProxy.remove();
    }
}

public Framedata translateSingleFrame( ByteBuffer buffer ) throws IncompleteException, InvalidDataException {
	int maxpacketsize = buffer.remaining();
	int realpacketsize = 2;
	if( maxpacketsize < realpacketsize ) {
		log.trace( "Incomplete frame" );
		throw new IncompleteException( realpacketsize );
	}
	byte b1 = buffer.get( /*0*/ );
	boolean FIN = b1 >> 8 != 0;
	boolean rsv1 = false;
	boolean rsv2 = false;
	boolean rsv3 = false;
	if( ( b1 & 0x40 ) != 0 ) {
		rsv1 = true;
	}
	if( ( b1 & 0x20 ) != 0 ) {
		rsv2 = true;
	}
	if( ( b1 & 0x10 ) != 0 ) {
		rsv3 = true;
	}
	byte b2 = buffer.get( /*1*/ );
	boolean MASK = ( b2 & -128 ) != 0;
	int payloadlength = ( byte ) ( b2 & ~( byte ) 128 );
	Opcode optcode = toOpcode( ( byte ) ( b1 & 15 ) );

	if( !( payloadlength >= 0 && payloadlength <= 125 ) ) {

		if( optcode == Opcode.PING || optcode == Opcode.PONG || optcode == Opcode.CLOSING ) {
			log.trace( "Invalid frame: more than 125 octets" );
			throw new InvalidFrameException( "more than 125 octets" );
		}
		if( payloadlength == 126 ) {
			realpacketsize += 2; // additional length bytes
			if( maxpacketsize < realpacketsize ) {
				log.trace( "Incomplete frame" );
				throw new IncompleteException( realpacketsize );
			}
			byte[] sizebytes = new byte[3];
			sizebytes[1] = buffer.get( /*1 + 1*/ );
			sizebytes[2] = buffer.get( /*1 + 2*/ );
			payloadlength = new BigInteger( sizebytes ).intValue();
		} else {
			realpacketsize += 8; // additional length bytes
			if( maxpacketsize < realpacketsize ) {
				log.trace( "Incomplete frame" );
				throw new IncompleteException( realpacketsize );
			}
			byte[] bytes = new byte[8];
			for( int i = 0; i < 8; i++ ) {
				bytes[i] = buffer.get( /*1 + i*/ );
			}
			long length = new BigInteger( bytes ).longValue();
			if( length > Integer.MAX_VALUE ) {
				log.trace( "Limit exedeed: Payloadsize is to big..." );
				throw new LimitExedeedException( "Payloadsize is to big..." );
			} else {
				payloadlength = ( int ) length;
			}
		}
	}

	// int maskskeystart = foff + realpacketsize;
	realpacketsize += ( MASK ? 4 : 0 );
	// int payloadstart = foff + realpacketsize;
	realpacketsize += payloadlength;

	if( maxpacketsize < realpacketsize )
		throw new IncompleteException( realpacketsize );

	ByteBuffer payload = ByteBuffer.allocate( checkAlloc( payloadlength ) );
	if( MASK ) {
		byte[] maskskey = new byte[4];
		buffer.get( maskskey );
		for( int i = 0; i < payloadlength; i++ ) {
			payload.put( ( byte ) ( buffer.get( /*payloadstart + i*/ ) ^ maskskey[i % 4] ) );
		}
	} else {
		payload.put( buffer.array(), buffer.position(), payload.limit() );
		buffer.position( buffer.position() + payload.limit() );
	}

	FramedataImpl1 frame = FramedataImpl1.get( optcode );
	frame.setFin( FIN );
	frame.setRSV1( rsv1 );
	frame.setRSV2( rsv2 );
	frame.setRSV3( rsv3 );
	payload.flip();
	frame.setPayload( payload );
	getExtension().isFrameValid(frame);
	getExtension().decodeFrame(frame);
	log.trace( "afterDecoding({}): {}", frame.getPayloadData().remaining(), ( frame.getPayloadData().remaining() > 1000 ? "too big to display" : new String( frame.getPayloadData().array() ) ) );
	frame.isValid();
	return frame;
}

