public void run() {
  running = tryToConnect(new InetSocketAddress(uri.getHost(), getPort()));

  while (this.running) {
    try {
      selector.select();
      Set<SelectionKey> keys = selector.selectedKeys();
      Iterator<SelectionKey> i = keys.iterator();

      while (i.hasNext()) {
        SelectionKey key = i.next();
        i.remove();

        if (key.isConnectable()) {
          finishConnect();
        }

        if (key.isReadable()) {
          conn.handleRead();
        }
      }
    } catch (IOException ex) {
      ex.printStackTrace();
    } catch (NoSuchAlgorithmException ex) {
      ex.printStackTrace();
    }
  }

  //System.err.println("WebSocketClient thread ended!");
}

private void parseStartTag() {
    tq.consume("<");
    Attributes attributes = new Attributes();

    String tagName = tq.consumeWord();
    while (!tq.matchesAny("<", "/>", ">") && !tq.isEmpty()) {
        Attribute attribute = parseAttribute();
        if (attribute != null)
            attributes.put(attribute);
    }

    Tag tag = Tag.valueOf(tagName);
    StartTag startTag = new StartTag(tag, attributes);
    Element child = new Element(startTag);

    boolean emptyTag;
    if (tq.matchChomp("/>")) { // empty tag, don't add to stack
        emptyTag = true;
    } else {
        tq.matchChomp(">"); // safe because checked above (or ran out of data)
        emptyTag = false;
    }

    // pc data only tags (textarea, script): chomp to end tag, add content as text node
    if (tag.isData()) {
        String data = tq.chompTo("</" + tagName);
        tq.chompTo(">");
        TextNode textNode = TextNode.createFromEncoded(data); // TODO: maybe have this be another data type? So doesn't come back in text()?
        child.addChild(textNode);

        if (tag.equals(titleTag))
            doc.setTitle(child.text());
    }

    // switch between html, head, body, to preserve doc structure
    if (tag.equals(htmlTag)) {
        doc.getAttributes().mergeAttributes(attributes);
    } else if (tag.equals(headTag)) {
        doc.getHead().getAttributes().mergeAttributes(attributes);
        // head is on stack from start, no action required
    } else if (last().getTag().equals(headTag) && !headTag.canContain(tag)) {
        // switch to body
        stack.removeLast();
        stack.addLast(doc.getBody());
        last().addChild(child);
        if (!emptyTag)
            stack.addLast(child);
    } else if (tag.equals(bodyTag) && last().getTag().equals(htmlTag)) {
        doc.getBody().getAttributes().mergeAttributes(attributes);
        stack.removeLast();
        stack.addLast(doc.getBody());
    } else {
        Element parent = popStackToSuitableContainer(tag);
        parent.addChild(child);
        if (!emptyTag && !tag.isData()) // TODO: only check for data here because last() == head is wrong; should be ancestor is head
            stack.addLast(child);
    }
}

@Override
public void processFrame( WebSocketImpl webSocketImpl, Framedata frame ) throws InvalidDataException {
	Opcode curop = frame.getOpcode();
	if( curop == Opcode.CLOSING ) {
		int code = CloseFrame.NOCODE;
		String reason = "";
		if( frame instanceof CloseFrame ) {
			CloseFrame cf = ( CloseFrame ) frame;
			code = cf.getCloseCode();
			reason = cf.getMessage();
		}
		if( webSocketImpl.getReadyState() == ReadyState.CLOSING ) {
			// complete the close handshake by disconnecting
			webSocketImpl.closeConnection( code, reason, true );
		} else {
			// echo close handshake
			if( getCloseHandshakeType() == CloseHandshakeType.TWOWAY )
				webSocketImpl.close( code, reason, true );
			else
				webSocketImpl.flushAndClose( code, reason, false );
		}
	} else if( curop == Opcode.PING ) {
		webSocketImpl.getWebSocketListener().onWebsocketPing( webSocketImpl, frame );
	} else if( curop == Opcode.PONG ) {
		webSocketImpl.updateLastPong();
		webSocketImpl.getWebSocketListener().onWebsocketPong( webSocketImpl, frame );
	} else if( !frame.isFin() || curop == Opcode.CONTINUOUS ) {
		if( curop != Opcode.CONTINUOUS ) {
			if( current_continuous_frame != null ) {
				log.trace( "Protocol error: Previous continuous frame sequence not completed." );
				throw new InvalidDataException( CloseFrame.PROTOCOL_ERROR, "Previous continuous frame sequence not completed." );
			}
			current_continuous_frame = frame;
			addToBufferList(frame.getPayloadData());
			checkBufferLimit();
		} else if( frame.isFin() ) {
			if( current_continuous_frame == null ) {
				log.trace( "Protocol error: Previous continuous frame sequence not completed." );
				throw new InvalidDataException( CloseFrame.PROTOCOL_ERROR, "Continuous frame sequence was not started." );
			}
			addToBufferList(frame.getPayloadData());
			checkBufferLimit();
			if( current_continuous_frame.getOpcode() == Opcode.TEXT ) {
				((FramedataImpl1) current_continuous_frame).setPayload( getPayloadFromByteBufferList() );
				((FramedataImpl1) current_continuous_frame ).isValid();
				try {
					webSocketImpl.getWebSocketListener().onWebsocketMessage( webSocketImpl, Charsetfunctions.stringUtf8( current_continuous_frame.getPayloadData() ) );
				} catch ( RuntimeException e ) {
					log.error( "Runtime exception during onWebsocketMessage", e );
					webSocketImpl.getWebSocketListener().onWebsocketError( webSocketImpl, e );
				}
			} else if( current_continuous_frame.getOpcode() == Opcode.BINARY ) {
				((FramedataImpl1) current_continuous_frame).setPayload( getPayloadFromByteBufferList() );
				((FramedataImpl1) current_continuous_frame ).isValid();
				try {
					webSocketImpl.getWebSocketListener().onWebsocketMessage( webSocketImpl, current_continuous_frame.getPayloadData() );
				} catch ( RuntimeException e ) {
					log.error( "Runtime exception during onWebsocketMessage", e );
					webSocketImpl.getWebSocketListener().onWebsocketError( webSocketImpl, e );
				}
			}
			current_continuous_frame = null;
			clearBufferList();
		} else if( current_continuous_frame == null ) {
			log.error( "Protocol error: Continuous frame sequence was not started." );
			throw new InvalidDataException( CloseFrame.PROTOCOL_ERROR, "Continuous frame sequence was not started." );
		}
		//Check if the whole payload is valid utf8, when the opcode indicates a text
		if( curop == Opcode.TEXT ) {
			if( !Charsetfunctions.isValidUTF8( frame.getPayloadData() ) ) {
				log.error( "Protocol error: Payload is not UTF8" );
				throw new InvalidDataException( CloseFrame.NO_UTF8 );
			}
		}
		//Checking if the current continuous frame contains a correct payload with the other frames combined
		if( curop == Opcode.CONTINUOUS && current_continuous_frame != null ) {
			addToBufferList(frame.getPayloadData());
		}
	} else if( current_continuous_frame != null ) {
		log.error( "Protocol error: Continuous frame sequence not completed." );
		throw new InvalidDataException( CloseFrame.PROTOCOL_ERROR, "Continuous frame sequence not completed." );
	} else if( curop == Opcode.TEXT ) {
		try {
			webSocketImpl.getWebSocketListener().onWebsocketMessage( webSocketImpl, Charsetfunctions.stringUtf8( frame.getPayloadData() ) );
		} catch ( RuntimeException e ) {
			log.error( "Runtime exception during onWebsocketMessage", e );
			webSocketImpl.getWebSocketListener().onWebsocketError( webSocketImpl, e );
		}
	} else if( curop == Opcode.BINARY ) {
		try {
			webSocketImpl.getWebSocketListener().onWebsocketMessage( webSocketImpl, frame.getPayloadData() );
		} catch ( RuntimeException e ) {
			log.error( "Runtime exception during onWebsocketMessage", e );
			webSocketImpl.getWebSocketListener().onWebsocketError( webSocketImpl, e );
		}
	} else {
		log.error( "non control or continious frame expected");
		throw new InvalidDataException( CloseFrame.PROTOCOL_ERROR, "non control or continious frame expected" );
	}
}

/**
 * Get a CSS selector that will uniquely select this element.
 * <p>
 * If the element has an ID, returns #id;
 * otherwise returns the parent (if any) CSS selector, followed by {@literal '>'},
 * followed by a unique selector for the element (tag.class.class:nth-child(n)).
 * </p>
 *
 * @return the CSS Path that can be used to retrieve the element in a selector.
 */
public String cssSelector() {
    if (id().length() > 0) {
        // prefer to return the ID - but check that it's actually unique first!
        String idSel = "#" + escapeCssIdentifier(id());
        Document doc = ownerDocument();
        if (doc != null) {
            Elements els = doc.select(idSel);
            if (els.size() == 1 && els.get(0) == this) // otherwise, continue to the nth-child impl
                return idSel;
        } else {
            return idSel; // no ownerdoc, return the ID selector
        }
    }

    // Escape tagname, and translate HTML namespace ns:tag to CSS namespace syntax ns|tag
    String tagName = escapeCssIdentifier(tagName()).replace("\\:", "|");
    StringBuilder selector = StringUtil.borrowBuilder().append(tagName);
    // String classes = StringUtil.join(classNames().stream().map(TokenQueue::escapeCssIdentifier).iterator(), ".");
    // todo - replace with ^^ in 1.16.1 when we enable Android support for stream etc
    StringUtil.StringJoiner escapedClasses = new StringUtil.StringJoiner(".");
    for (String name : classNames()) escapedClasses.add(escapeCssIdentifier(name));
    String classes = escapedClasses.complete();
    if (classes.length() > 0)
        selector.append('.').append(classes);

    if (parent() == null || parent() instanceof Document) // don't add Document to selector, as will always have a html node
        return StringUtil.releaseBuilder(selector);

    selector.insert(0, " > ");
    if (parent().select(selector.toString()).size() > 1)
        selector.append(String.format(
            ":nth-child(%d)", elementSiblingIndex() + 1));

    return parent().cssSelector() + StringUtil.releaseBuilder(selector);
}

/**
 * Implements the handshake protocol between two peers, required for the establishment of the SSL/TLS connection.
 * During the handshake, encryption configuration information - such as the list of available cipher suites - will be exchanged
 * and if the handshake is successful will lead to an established SSL/TLS session.
 * <p>
 * <p/>
 * A typical handshake will usually contain the following steps:
 * <p>
 * <ul>
 * <li>1. wrap:     ClientHello</li>
 * <li>2. unwrap:   ServerHello/Cert/ServerHelloDone</li>
 * <li>3. wrap:     ClientKeyExchange</li>
 * <li>4. wrap:     ChangeCipherSpec</li>
 * <li>5. wrap:     Finished</li>
 * <li>6. unwrap:   ChangeCipherSpec</li>
 * <li>7. unwrap:   Finished</li>
 * </ul>
 * <p/>
 * Handshake is also used during the end of the session, in order to properly close the connection between the two peers.
 * A proper connection close will typically include the one peer sending a CLOSE message to another, and then wait for
 * the other's CLOSE message to close the transport link. The other peer from his perspective would read a CLOSE message
 * from his peer and then enter the handshake procedure to send his own CLOSE message as well.
 *
 * @return True if the connection handshake was successful or false if an error occurred.
 * @throws IOException - if an error occurs during read/write to the socket channel.
 */
private boolean doHandshake() throws IOException {
	SSLEngineResult result;
	HandshakeStatus handshakeStatus;

	// NioSslPeer's fields myAppData and peerAppData are supposed to be large enough to hold all message data the peer
	// will send and expects to receive from the other peer respectively. Since the messages to be exchanged will usually be less
	// than 16KB long the capacity of these fields should also be smaller. Here we initialize these two local buffers
	// to be used for the handshake, while keeping client's buffers at the same size.
	int appBufferSize = engine.getSession().getApplicationBufferSize();
	myAppData = ByteBuffer.allocate( appBufferSize );
	peerAppData = ByteBuffer.allocate( appBufferSize );
	myNetData.clear();
	peerNetData.clear();

	handshakeStatus = engine.getHandshakeStatus();
	while( handshakeStatus != SSLEngineResult.HandshakeStatus.FINISHED && handshakeStatus != SSLEngineResult.HandshakeStatus.NOT_HANDSHAKING ) {
		switch(handshakeStatus) {
			case NEED_UNWRAP:
				if( socketChannel.read( peerNetData ) < 0 ) {
					if( engine.isInboundDone() && engine.isOutboundDone() ) {
						return false;
					}
					try {
						engine.closeInbound();
					} catch ( SSLException e ) {
						//Ignore, cant do anything against this exception
					}
					engine.closeOutbound();
					// After closeOutbound the engine will be set to WRAP state, in order to try to send a close message to the client.
					handshakeStatus = engine.getHandshakeStatus();
					break;
				}
				peerNetData.flip();
				try {
					result = engine.unwrap( peerNetData, peerAppData );
					peerNetData.compact();
					handshakeStatus = result.getHandshakeStatus();
				} catch ( SSLException sslException ) {
					engine.closeOutbound();
					handshakeStatus = engine.getHandshakeStatus();
					break;
				}
				switch(result.getStatus()) {
					case OK:
						break;
					case BUFFER_OVERFLOW:
						// Will occur when peerAppData's capacity is smaller than the data derived from peerNetData's unwrap.
						peerAppData = enlargeApplicationBuffer( peerAppData );
						break;
					case BUFFER_UNDERFLOW:
						// Will occur either when no data was read from the peer or when the peerNetData buffer was too small to hold all peer's data.
						peerNetData = handleBufferUnderflow( peerNetData );
						break;
					case CLOSED:
						if( engine.isOutboundDone() ) {
							return false;
						} else {
							engine.closeOutbound();
							handshakeStatus = engine.getHandshakeStatus();
							break;
						}
					default:
						throw new IllegalStateException( "Invalid SSL status: " + result.getStatus() );
				}
				break;
			case NEED_WRAP:
				myNetData.clear();
				try {
					result = engine.wrap( myAppData, myNetData );
					handshakeStatus = result.getHandshakeStatus();
				} catch ( SSLException sslException ) {
					engine.closeOutbound();
					handshakeStatus = engine.getHandshakeStatus();
					break;
				}
				switch(result.getStatus()) {
					case OK:
						myNetData.flip();
						while( myNetData.hasRemaining() ) {
							socketChannel.write( myNetData );
						}
						break;
					case BUFFER_OVERFLOW:
						// Will occur if there is not enough space in myNetData buffer to write all the data that would be generated by the method wrap.
						// Since myNetData is set to session's packet size we should not get to this point because SSLEngine is supposed
						// to produce messages smaller or equal to that, but a general handling would be the following:
						myNetData = enlargePacketBuffer( myNetData );
						break;
					case BUFFER_UNDERFLOW:
						throw new SSLException( "Buffer underflow occured after a wrap. I don't think we should ever get here." );
					case CLOSED:
						try {
							myNetData.flip();
							while( myNetData.hasRemaining() ) {
								socketChannel.write( myNetData );
							}
							// At this point the handshake status will probably be NEED_UNWRAP so we make sure that peerNetData is clear to read.
							peerNetData.clear();
						} catch ( Exception e ) {
							handshakeStatus = engine.getHandshakeStatus();
						}
						break;
					default:
						throw new IllegalStateException( "Invalid SSL status: " + result.getStatus() );
				}
				break;
			case NEED_TASK:
				Runnable task;
				while( ( task = engine.getDelegatedTask() ) != null ) {
					executor.execute( task );
				}
				handshakeStatus = engine.getHandshakeStatus();
				break;
			case FINISHED:
				break;
			case NOT_HANDSHAKING:
				break;
			default:
				throw new IllegalStateException( "Invalid SSL status: " + handshakeStatus );
		}
	}

	return true;

}

protected List<Framedata> translateRegularFrame( ByteBuffer buffer ) throws InvalidDataException {
	while ( buffer.hasRemaining() ) {
		byte newestByte = buffer.get();
		if( newestByte == START_OF_FRAME ) { // Beginning of Frame
			if( readingState )
				return null;
			readingState = true;
		} else if( newestByte == END_OF_FRAME ) { // End of Frame
			if( !readingState )
				return null;
			// currentFrame will be null if END_OF_FRAME was send directly after
			// START_OF_FRAME, thus we will send 'null' as the sent message.
			if( this.currentFrame != null ) {
				FramedataImpl1 curframe = new FramedataImpl1();
				curframe.setPayload( currentFrame.array() );
				curframe.setFin( true );
				curframe.setOptcode( inframe ? Opcode.CONTINIOUS : Opcode.TEXT );
				readyframes.add( curframe );
				this.currentFrame = null;
				buffer.mark();
			}
			readingState = false;
			inframe = false;
		} else if( readingState ) { // Regular frame data, add to current frame buffer //TODO This code is very expensive and slow
			ByteBuffer frame = ByteBuffer.allocate( checkAlloc( ( this.currentFrame != null ? this.currentFrame.capacity() : 0 ) + 1 ) );
			if( this.currentFrame != null ) {
				this.currentFrame.rewind();
				frame.put( this.currentFrame );
			}
			frame.put( newestByte );
			this.currentFrame = frame;
		} else {
			return null;
		}
	}
	if( readingState ) {
		FramedataImpl1 curframe = new FramedataImpl1();
		curframe.setPayload( currentFrame.array() );
		curframe.setFin( false );
		curframe.setOptcode( inframe ? Opcode.CONTINIOUS : Opcode.TEXT );
		inframe = true;
		readyframes.add( curframe );
	}

	List<Framedata> frames = readyframes;
	readyframes = new LinkedList<Framedata>();
	this.currentFrame = null;
	return frames;
}

protected Tag tagFor(String tagName, ParseSettings settings) {
    Tag tag = seenTags.get(tagName); // note that we don't normalize the cache key. But tag via valueOf may be normalized.
    if (tag == null) {
