/**
 Get a CSS selector that will uniquely select this element.
 <p>
 If the element has an ID, returns #id; otherwise returns the parent (if any) CSS selector, followed by
 {@literal '>'}, followed by a unique selector for the element (tag.class.class:nth-child(n)).
 </p>

 @return the CSS Path that can be used to retrieve the element in a selector.
 */
public String cssSelector() {
    Document ownerDoc = ownerDocument();
    String idSel = uniqueIdSelector(ownerDoc);
    if (!idSel.isEmpty()) return idSel;

    // No unique ID, work up the parent stack and find either a unique ID to hang from, or just a GP > Parent > Child chain
    StringBuilder selector = StringUtil.borrowBuilder();
    Element el = this;
    while (el != null && !(el instanceof Document)) {
        idSel = el.uniqueIdSelector(ownerDoc);
        if (!idSel.isEmpty()) {
            selector.insert(0, idSel);
            break; // found a unique ID to use as ancestor; stop
        }
        selector.insert(0, el.cssSelectorComponent());
        el = el.parent();
    }
    return StringUtil.releaseBuilder(selector);
}

/**
 * Get this element's child elements.
 * <p>
 * This is effectively a filter on {@link #childNodes()} to get Element nodes.
 * </p>
 * @return child elements. If this element has no children, returns an
 * empty list.
 * @see #childNodes()
 */
public Elements children() {
    // create on the fly rather than maintaining two lists. if gets slow, memoize, and mark dirty on change
    List<Element> elements = new ArrayList<Element>(childNodes.size());
    for (Node node : childNodes) {
        if (node instanceof Element)
            elements.add((Element) node);
    }
    return new Elements(elements);
}

public void head(org.jsoup.nodes.Node source, int depth) {
    namespacesStack.push(new HashMap<>(namespacesStack.peek())); // inherit from above on the stack
    if (source instanceof org.jsoup.nodes.Element) {
        org.jsoup.nodes.Element sourceEl = (org.jsoup.nodes.Element) source;

        String prefix = updateNamespaces(sourceEl);
        String namespace = namespacesStack.peek().get(prefix);
        String tagName = sourceEl.tagName();

        /* Tag names in XML are quite permissive, but less permissive than HTML. Rather than reimplement the validation,
        we just try to use it as-is. If it fails, insert as a text node instead. We don't try to normalize the
        tagname to something safe, because that isn't going to be meaningful downstream. This seems(?) to be
        how browsers handle the situation, also. https://github.com/jhy/jsoup/issues/1093 */
        try {
            Element el = namespace == null && tagName.contains(":") ?
                doc.createElementNS("", tagName) : // doesn't have a real namespace defined
                doc.createElementNS(namespace, tagName);
            copyAttributes(sourceEl, el);
            append(el, sourceEl);
            dest = el; // descend
        } catch (DOMException e) {
            append(doc.createTextNode("<" + tagName + ">"), sourceEl);
        }
    } else if (source instanceof org.jsoup.nodes.TextNode) {
        org.jsoup.nodes.TextNode sourceText = (org.jsoup.nodes.TextNode) source;
        Text text = doc.createTextNode(sourceText.getWholeText());
        append(text, sourceText);
    } else if (source instanceof org.jsoup.nodes.Comment) {
        org.jsoup.nodes.Comment sourceComment = (org.jsoup.nodes.Comment) source;
        Comment comment = doc.createComment(sourceComment.getData());
        append(comment, sourceComment);
    } else if (source instanceof org.jsoup.nodes.DataNode) {
        org.jsoup.nodes.DataNode sourceData = (org.jsoup.nodes.DataNode) source;
        Text node = doc.createTextNode(sourceData.getWholeData());
        append(node, sourceData);
    } else {
        // unhandled. note that doctype is not handled here - rather it is used in the initial doc creation
    }
}

void insert(Token.Character characterToken) {
    final Node node;
    Element el = currentElement(); // will be doc if no current element; allows for whitespace to be inserted into the doc root object (not on the stack)
    final String tagName = el.normalName();
    final String data = characterToken.getData();

    if (characterToken.isCData())
        node = new CDataNode(data);
    else if (isContentForTagData(tagName))
        node = new DataNode(data);
    else
        node = new TextNode(data);
    el.appendChild(node); // doesn't use insertNode, because we don't foster these; and will always have a stack.
    onNodeInserted(node, characterToken);
}

void outerHtmlHead(final Appendable accum, int depth, final Document.OutputSettings out) throws IOException {
    if (out.prettyPrint() && isFormatAsBlock(out) && !isInlineable(out)) {
        if (accum instanceof StringBuilder) {
            if (((StringBuilder) accum).length() > 0)
                indent(accum, depth, out);
        } else {
            indent(accum, depth, out);
        }
    }
    accum.append('<').append(tagName());
    if (attributes != null) attributes.html(accum, out);

    // selfclosing includes unknown tags, isEmpty defines tags that are always empty
    if (childNodes.isEmpty() && tag.isSelfClosing()) {
        if (out.syntax() == Document.OutputSettings.Syntax.html && tag.isEmpty())
            accum.append('>');
        else
            accum.append(" />"); // <img> in html, <img /> in xml
    }
    else
        accum.append('>');
}

@Override
public void processFrame( WebSocketImpl webSocketImpl, Framedata frame ) throws InvalidDataException {
	Opcode curop = frame.getOpcode();
	if( curop == Opcode.CLOSING ) {
		int code = CloseFrame.NOCODE;
		String reason = "";
		if( frame instanceof CloseFrame ) {
			CloseFrame cf = ( CloseFrame ) frame;
			code = cf.getCloseCode();
			reason = cf.getMessage();
		}
		if( webSocketImpl.getReadyState() == ReadyState.CLOSING ) {
			// complete the close handshake by disconnecting
			webSocketImpl.closeConnection( code, reason, true );
		} else {
			// echo close handshake
			if( getCloseHandshakeType() == CloseHandshakeType.TWOWAY )
				webSocketImpl.close( code, reason, true );
			else
				webSocketImpl.flushAndClose( code, reason, false );
		}
	} else if( curop == Opcode.PING ) {
		webSocketImpl.getWebSocketListener().onWebsocketPing( webSocketImpl, frame );
	} else if( curop == Opcode.PONG ) {
		webSocketImpl.updateLastPong();
		webSocketImpl.getWebSocketListener().onWebsocketPong( webSocketImpl, frame );
	} else if( !frame.isFin() || curop == Opcode.CONTINUOUS ) {
		if( curop != Opcode.CONTINUOUS ) {
			if( current_continuous_frame != null ) {
				log.trace( "Protocol error: Previous continuous frame sequence not completed." );
				throw new InvalidDataException( CloseFrame.PROTOCOL_ERROR, "Previous continuous frame sequence not completed." );
			}
			current_continuous_frame = frame;
			addToBufferList(frame.getPayloadData());
			checkBufferLimit();
		} else if( frame.isFin() ) {
			if( current_continuous_frame == null ) {
				log.trace( "Protocol error: Previous continuous frame sequence not completed." );
				throw new InvalidDataException( CloseFrame.PROTOCOL_ERROR, "Continuous frame sequence was not started." );
			}
			addToBufferList(frame.getPayloadData());
			checkBufferLimit();
			if( current_continuous_frame.getOpcode() == Opcode.TEXT ) {
				((FramedataImpl1) current_continuous_frame).setPayload( getPayloadFromByteBufferList() );
				((FramedataImpl1) current_continuous_frame ).isValid();
				try {
					webSocketImpl.getWebSocketListener().onWebsocketMessage( webSocketImpl, Charsetfunctions.stringUtf8( current_continuous_frame.getPayloadData() ) );
				} catch ( RuntimeException e ) {
					log.error( "Runtime exception during onWebsocketMessage", e );
					webSocketImpl.getWebSocketListener().onWebsocketError( webSocketImpl, e );
				}
			} else if( current_continuous_frame.getOpcode() == Opcode.BINARY ) {
				((FramedataImpl1) current_continuous_frame).setPayload( getPayloadFromByteBufferList() );
				((FramedataImpl1) current_continuous_frame ).isValid();
				try {
					webSocketImpl.getWebSocketListener().onWebsocketMessage( webSocketImpl, current_continuous_frame.getPayloadData() );
				} catch ( RuntimeException e ) {
					log.error( "Runtime exception during onWebsocketMessage", e );
					webSocketImpl.getWebSocketListener().onWebsocketError( webSocketImpl, e );
				}
			}
			current_continuous_frame = null;
			clearBufferList();
		} else if( current_continuous_frame == null ) {
			log.error( "Protocol error: Continuous frame sequence was not started." );
			throw new InvalidDataException( CloseFrame.PROTOCOL_ERROR, "Continuous frame sequence was not started." );
		}
		//Check if the whole payload is valid utf8, when the opcode indicates a text
		if( curop == Opcode.TEXT ) {
			if( !Charsetfunctions.isValidUTF8( frame.getPayloadData() ) ) {
				log.error( "Protocol error: Payload is not UTF8" );
				throw new InvalidDataException( CloseFrame.NO_UTF8 );
			}
		}
		//Checking if the current continuous frame contains a correct payload with the other frames combined
		if( curop == Opcode.CONTINUOUS && current_continuous_frame != null ) {
			addToBufferList(frame.getPayloadData());
		}
	} else if( current_continuous_frame != null ) {
		log.error( "Protocol error: Continuous frame sequence not completed." );
		throw new InvalidDataException( CloseFrame.PROTOCOL_ERROR, "Continuous frame sequence not completed." );
	} else if( curop == Opcode.TEXT ) {
		try {
			webSocketImpl.getWebSocketListener().onWebsocketMessage( webSocketImpl, Charsetfunctions.stringUtf8( frame.getPayloadData() ) );
		} catch ( RuntimeException e ) {
			log.error( "Runtime exception during onWebsocketMessage", e );
			webSocketImpl.getWebSocketListener().onWebsocketError( webSocketImpl, e );
		}
	} else if( curop == Opcode.BINARY ) {
		try {
			webSocketImpl.getWebSocketListener().onWebsocketMessage( webSocketImpl, frame.getPayloadData() );
		} catch ( RuntimeException e ) {
			log.error( "Runtime exception during onWebsocketMessage", e );
			webSocketImpl.getWebSocketListener().onWebsocketError( webSocketImpl, e );
		}
	} else {
		log.error( "non control or continious frame expected");
		throw new InvalidDataException( CloseFrame.PROTOCOL_ERROR, "non control or continious frame expected" );
	}
}

