                indent(accum, depth, out);
        } else {
            indent(accum, depth, out);
        }
    }
    accum.append('<').append(safeTagName(out.syntax()));
    if (attributes != null) attributes.html(accum, out);

    // selfclosing includes unknown tags, isEmpty defines tags that are always empty
    if (childNodes.isEmpty() && tag.isSelfClosing()) {
        if (out.syntax() == html && tag.isEmpty())
            accum.append('>');
        else
            accum.append(" />"); // <img> in html, <img /> in xml
    }
    else
        accum.append('>');
}

private Framedata translateSingleFrame( ByteBuffer buffer ) throws IncompleteException, InvalidDataException {
	if (buffer == null)
		throw new IllegalArgumentException();
	int maxpacketsize = buffer.remaining();
	int realpacketsize = 2;
	translateSingleFrameCheckPacketSize(maxpacketsize, realpacketsize);
	byte b1 = buffer.get( /*0*/ );
	boolean fin = b1 >> 8 != 0;
	boolean rsv1 = ( b1 & 0x40 ) != 0;
	boolean rsv2 = ( b1 & 0x20 ) != 0;
	boolean rsv3 = ( b1 & 0x10 ) != 0;
	byte b2 = buffer.get( /*1*/ );
	boolean mask = ( b2 & -128 ) != 0;
	int payloadlength = ( byte ) ( b2 & ~( byte ) 128 );
	Opcode optcode = toOpcode( ( byte ) ( b1 & 15 ) );

	if( !( payloadlength >= 0 && payloadlength <= 125 ) ) {

		if( optcode == Opcode.PING || optcode == Opcode.PONG || optcode == Opcode.CLOSING ) {
			log.trace( "Invalid frame: more than 125 octets" );
			throw new InvalidFrameException( "more than 125 octets" );
		}
		if( payloadlength == 126 ) {
			realpacketsize += 2; // additional length bytes
			translateSingleFrameCheckPacketSize(maxpacketsize, realpacketsize);
			byte[] sizebytes = new byte[3];
			sizebytes[1] = buffer.get( /*1 + 1*/ );
			sizebytes[2] = buffer.get( /*1 + 2*/ );
			payloadlength = new BigInteger( sizebytes ).intValue();
		} else {
			realpacketsize += 8; // additional length bytes
			translateSingleFrameCheckPacketSize(maxpacketsize, realpacketsize);
			byte[] bytes = new byte[8];
			for( int i = 0; i < 8; i++ ) {
				bytes[i] = buffer.get( /*1 + i*/ );
			}
			long length = new BigInteger( bytes ).longValue();
			translateSingleFrameCheckLengthLimit(length);
			payloadlength = ( int ) length;
		}
	}
	realpacketsize += ( mask ? 4 : 0 );
	realpacketsize += payloadlength;
	translateSingleFrameCheckPacketSize(maxpacketsize, realpacketsize);

	ByteBuffer payload = ByteBuffer.allocate( checkAlloc( payloadlength ) );
	if( mask ) {
		byte[] maskskey = new byte[4];
		buffer.get( maskskey );
		for( int i = 0; i < payloadlength; i++ ) {
			payload.put( ( byte ) ( buffer.get( /*payloadstart + i*/ ) ^ maskskey[i % 4] ) );
		}
	} else {
		payload.put( buffer.array(), buffer.position(), payload.limit() );
		buffer.position( buffer.position() + payload.limit() );
	}

	FramedataImpl1 frame = FramedataImpl1.get( optcode );
	frame.setFin( fin );
	frame.setRSV1( rsv1 );
	frame.setRSV2( rsv2 );
	frame.setRSV3( rsv3 );
	payload.flip();
	frame.setPayload( payload );
	getExtension().isFrameValid(frame);
	getExtension().decodeFrame(frame);
	if (log.isTraceEnabled())
		log.trace( "afterDecoding({}): {}", frame.getPayloadData().remaining(), ( frame.getPayloadData().remaining() > 1000 ? "too big to display" : new String( frame.getPayloadData().array() ) ) );
	frame.isValid();
	return frame;
}

  /**
   * Should be called when a Selector has a key that is writable for this
   * WebSocket's SocketChannel connection.
   * @throws IOException When socket related I/O errors occur.
   * @throws NoSuchAlgorithmException 
   */
  void handleRead() throws IOException, NoSuchAlgorithmException {

    int bytesRead = -1;

    socketBuffer.rewind();
    bytesRead = this.socketChannel.read(this.socketBuffer);


    if ( bytesRead == -1 )  {
      close();
    } 
    else if( bytesRead > maxpayloadsize ){
    	wsl.onError ( new RuntimeException("recived packet to big") );
    	abort ( "recived packet to big" );
    }
    else if ( bytesRead > 0) {
		if(DEBUG) System.out.println( "got: {" + new String( socketBuffer.array() , 0 , bytesRead ) + "}" );
		if( !handshakeComplete ){
			if(draft.isFlashEdgeCase( socketBuffer.array() , bytesRead )){
				channelWrite( ByteBuffer.wrap( wsl.getFlashPolicy( this ).getBytes( UTF8_CHARSET ) ) );
				return;
			}
			try{
				Handshakedata handshake = Draft.translateHandshake ( socketBuffer.array () , bytesRead );
				if( handshake == null){
					abort("This valid http header ");
					return;
				}
				if( role == Role.SERVER ){
					for( Draft d : known_drafts ){
						if(  d.acceptHandshakeAsServer( handshake ) ){
							HandshakeBuilder response = wsl.onHandshakeRecievedAsServer ( this , d , handshake  );
							channelWrite ( d.createHandshake ( d.postProcessHandshakeResponseAsServer ( handshake , response ) , role ) );
							draft = d;
							this.handshakeComplete = true;
							wsl.onOpen ( this );
							break;
						}
					}
					if( draft == null ){
						abort( "no draft matches");
						return;
					}
					if(DEBUG) System.out.println ( "Using draft: " + draft.getClass ().getSimpleName () );
				}
				else if( role == Role.CLIENT){
					if( draft.acceptHandshakeAsClient ( handshakerequest , handshake ) 
						&& wsl.onHandshakeRecievedAsClient ( this , handshakerequest , handshake )
					){
						this.handshakeComplete = true;
						wsl.onOpen ( this );
					}
					else{
						abort( "draft "+draft.getClass ().getSimpleName ()+" or server refuses handshake");
					}
				}
			}
			catch (InvalidHandshakeException e) {
				abort( "draft "+draft+" refuses handshake: " + e.getMessage ());
			}
		}
		else{
			List<Framedata> frames = draft.translateFrame ( socketBuffer , bytesRead );
			for( Framedata f : frames){
				Opcode curop = f.getOpcode ();
				if( curop == null )// Ignore undefined opcodes
					continue;
				else if( curop == Opcode.CLOSING){
					sendFrame ( new FramedataImpl1 ( Opcode.CLOSING ) );
					close();
					continue;
				}
				else if( curop == Opcode.PING){
					sendFrame ( new FramedataImpl1 ( Opcode.PONG ) );
					continue;
				}
				else if( curop == Opcode.PONG){
					wsl.onPong ();
					continue;
				}
				if( currentframe == null){
					if( f.isFin () ){
						if( f.getOpcode () == Opcode.TEXT ){
							wsl.onMessage ( this , new String ( f.getPayloadData () , UTF8_CHARSET ) );
						}
						else if( f.getOpcode () == Opcode.BINARY ){
							wsl.onMessage ( this , f.getPayloadData () );
						}
						else{
							if(DEBUG) System.out.println ( "Ignoring frame:" + f.toString() );
						}
					}
					else{
						currentframe = f;
					}
				}
				else if( f.getOpcode() == Opcode.CONTINIOUS ){
					try {
						currentframe.append ( f );
					} catch ( InvalidFrameException e ) {
						wsl.onError ( e );
						abort( "invalid frame: " +e.getMessage () );
					}
					if( f.isFin () ){
						wsl.onMessage ( this , new String ( f.getPayloadData () , UTF8_CHARSET ) );
						currentframe = null;
					}
				}
			}

		}
    }
  }

public void run() {
	if( selectorthread != null )
		throw new IllegalStateException( "This instance of " + getClass().getSimpleName() + " can only be started once the same time." );
	selectorthread = Thread.currentThread();
	selectorthread.setName( "WebsocketSelector" + selectorthread.getId() );
	try {
		server = ServerSocketChannel.open();
		server.configureBlocking( false );
		ServerSocket socket = server.socket();
		socket.setReceiveBufferSize( WebSocket.RCVBUF );
		socket.bind( address );
		selector = Selector.open();
		server.register( selector, server.validOps() );
	} catch ( IOException ex ) {
		onWebsocketError( null, ex );
		return;
	}
	try {
		while ( !selectorthread.isInterrupted() ) {
			SelectionKey key = null;
			WebSocketImpl conn = null;
			try {
				handleWrite();
				selector.select();
				Set<SelectionKey> keys = selector.selectedKeys();
				Iterator<SelectionKey> i = keys.iterator();

				while ( i.hasNext() ) {
					key = i.next();

					if( !key.isValid() ) {
						// Object o = key.attachment();
						continue;
					}

					if( key.isAcceptable() ) {
						SocketChannel channel = server.accept();
						channel.configureBlocking( false );
						WebSocketImpl c = wsf.createWebSocket( this, drafts, channel );
						c.key = channel.register( selector, SelectionKey.OP_READ, c );
						i.remove();
						allocateBuffers( c );
						continue;
					}

					if( key.isReadable() ) {
						conn = (WebSocketImpl) key.attachment();
						ByteBuffer buf = takeBuffer();
						try {
							if( conn.read( buf ) ) {
								conn.in.put( buf );
								queue( conn );
								i.remove();
							} else {
								pushBuffer( buf );
							}
						} catch ( IOException e ) {
							pushBuffer( buf );// TODO handle runtimeexception thrown in this block
							throw e;
						}
					}
					if( key.isWritable() ) {
						conn = (WebSocketImpl) key.attachment();
						if( conn.batch() ) {
							key.channel().register( selector, SelectionKey.OP_READ, key.attachment() );
						}
					}
				}
			} catch ( CancelledKeyException e ) {
				// an other thread may cancel the key
			} catch ( IOException ex ) {
				if( key != null )
					key.cancel();
				handleIOException( conn, ex );
			} catch ( InterruptedException e ) {
				return;
			}
		}
	} catch ( RuntimeException e ) {
		// should hopefully never occur
		handleFatal( null, e );
	}
}

public void run() {
	if( thread != null )
		throw new IllegalStateException( "This instance of " + getClass().getSimpleName() + " can only be started once the same time." );
	thread = Thread.currentThread();
	try {
		server = ServerSocketChannel.open();
		server.configureBlocking( false );
		server.socket().bind( address );
		//InetAddress.getLocalHost()
		selector = Selector.open();
		server.register( selector, server.validOps() );
	} catch ( IOException ex ) {
		onError( null, ex );
		return;
	}

	while ( !thread.isInterrupted() ) {
		SelectionKey key = null;
		WebSocket conn = null;
		try {
			selector.select();
			Set<SelectionKey> keys = selector.selectedKeys();
			Iterator<SelectionKey> i = keys.iterator();

			while ( i.hasNext() ) {
				key = i.next();

				// Remove the current key
				i.remove();

				// if isAcceptable == true
				// then a client required a connection
				if( key.isAcceptable() ) {
					SocketChannel client = server.accept();
					client.configureBlocking( false );
					WebSocket c = new WebSocket( this, Collections.singletonList( draft ), client.socket().getChannel() );
					client.register( selector, SelectionKey.OP_READ, c );
				}

				// if isReadable == true
				// then the server is ready to read
				if( key.isReadable() ) {
					conn = (WebSocket) key.attachment();
					conn.handleRead();
				}

				// if isWritable == true
				// then we need to send the rest of the data to the client
				if( key.isValid() && key.isWritable() ) {
					conn = (WebSocket) key.attachment();
					conn.flush();
					key.channel().register( selector, SelectionKey.OP_READ, conn );
				}
			}
			Iterator<WebSocket> it = this.connections.iterator();
			while ( it.hasNext() ) {
				// We have to do this check here, and not in the thread that
				// adds the buffered data to the WebSocket, because the
				// Selector is not thread-safe, and can only be accessed
				// by this thread.
				conn = it.next();
				if( conn.hasBufferedData() ) {
					conn.flush();
					// key.channel().register( selector, SelectionKey.OP_READ | SelectionKey.OP_WRITE, conn );
				}
			}
		} catch ( IOException ex ) {
			if( key != null )
				key.cancel();
			onError( conn, ex );// conn may be null here
			if( conn != null ) {
				conn.close( CloseFrame.ABNROMAL_CLOSE );
			}
		}
	}
}

static Response execute(Connection.Request req) throws IOException {
    Validate.notNull(req, "Request must not be null");
    URL url = req.url();
    String protocol = url.getProtocol();
    Validate
        .isTrue(protocol.equals("http") || protocol.equals("https"), "Only http & https protocols supported");

    // set up the request for execution
    if (req.method() == Connection.Method.GET && req.data().size() > 0)
        url = getRequestUrl(req); // appends query string
    HttpURLConnection conn = (HttpURLConnection) url.openConnection();
    conn.setRequestMethod(req.method().name());
    conn.setInstanceFollowRedirects(true);
    conn.setConnectTimeout(req.timeout());
    conn.setReadTimeout(req.timeout());
    if (req.method() == Connection.Method.POST)
        conn.setDoOutput(true);
    if (req.cookies().size() > 0)
        conn.addRequestProperty("Cookie", getRequestCookieString(req));
    for (Map.Entry<String, String> header : req.headers().entrySet()) {
        conn.addRequestProperty(header.getKey(), header.getValue());
    }
    conn.connect();
    if (req.method() == Connection.Method.POST)
        writePost(req.data(), conn.getOutputStream());          

    // todo: error handling options, allow user to get !200 without exception
    int status = conn.getResponseCode();
    if (status != HttpURLConnection.HTTP_OK)
        throw new IOException(status + " error loading URL " + url.toString());
    Response res = new Response();
    res.setupFromConnection(conn);

    InputStream inStream = null;
    try {
        inStream = res.hasHeader("Content-Encoding") && res.header("Content-Encoding").equalsIgnoreCase("gzip") ?
                new BufferedInputStream(new GZIPInputStream(conn.getInputStream())) :
                new BufferedInputStream(conn.getInputStream());
        res.byteData = DataUtil.readToByteBuffer(inStream);
        res.charset = getCharsetFromContentType(res.contentType); // may be null, readInputStream deals with it
    } finally {
        if (inStream != null) inStream.close();
    }

    res.executed = true;
    return res;
}

/**
 * Check if the value of the provided range equals the string.
 */
boolean rangeEquals(final int start, int count, final String cached) {
    if (count == cached.length()) {
        char one[] = input;
        int i = start;
        int j = 0;
        while (count-- != 0) {
            if (one[i++] != cached.charAt(j++))
                return false;
        }
        return true;
    }
    return false;
}

/**
 * Returns whether the handshake phase has is completed.
 * In case of a broken handshake this will be never the case.
 **/
private boolean decodeHandshake( ByteBuffer socketBufferNew ) {
	ByteBuffer socketBuffer;
	if( tmpHandshakeBytes.capacity() == 0 ) {
		socketBuffer = socketBufferNew;
	} else {
		if( tmpHandshakeBytes.remaining() < socketBufferNew.remaining() ) {
			ByteBuffer buf = ByteBuffer.allocate( tmpHandshakeBytes.capacity() + socketBufferNew.remaining() );
			tmpHandshakeBytes.flip();
			buf.put( tmpHandshakeBytes );
			tmpHandshakeBytes = buf;
		}

		tmpHandshakeBytes.put( socketBufferNew );
		tmpHandshakeBytes.flip();
		socketBuffer = tmpHandshakeBytes;
	}
	socketBuffer.mark();
	try {
		if( draft == null ) {
			HandshakeState isflashedgecase = isFlashEdgeCase( socketBuffer );
			if( isflashedgecase == HandshakeState.MATCHED ) {
				try {
					write( Collections.singletonList( ByteBuffer.wrap(Charsetfunctions.utf8Bytes(wsl.getFlashPolicy(this)))));
					close(CloseFrame.FLASHPOLICY, "");
				} catch ( InvalidDataException e ) {
					close( CloseFrame.ABNORMAL_CLOSE, "remote peer closed connection before flashpolicy could be transmitted", true );
				}
				return false;
			}
		}
		HandshakeState handshakestate;

		try {
			if( role == Role.SERVER ) {
				if( draft == null ) {
					for( Draft d : knownDrafts ) {
						d = d.copyInstance();
						try {
							d.setParseMode( role );
							socketBuffer.reset();
							Handshakedata tmphandshake = d.translateHandshake( socketBuffer );
							if( !( tmphandshake instanceof ClientHandshake ) ) {
								flushAndClose( CloseFrame.PROTOCOL_ERROR, "wrong http function", false );
								return false;
							}
							ClientHandshake handshake = ( ClientHandshake ) tmphandshake;
							handshakestate = d.acceptHandshakeAsServer( handshake );
							if( handshakestate == HandshakeState.MATCHED ) {
								resourceDescriptor = handshake.getResourceDescriptor();
								ServerHandshakeBuilder response;
								try {
									response = wsl.onWebsocketHandshakeReceivedAsServer( this, d, handshake );
								} catch ( InvalidDataException e ) {
									flushAndClose( e.getCloseCode(), e.getMessage(), false );
									return false;
								} catch ( RuntimeException e ) {
									wsl.onWebsocketError( this, e );
									flushAndClose( CloseFrame.NEVER_CONNECTED, e.getMessage(), false );
									return false;
								}
								write( d.createHandshake( d.postProcessHandshakeResponseAsServer( handshake, response ), role ) );
								draft = d;
								open( handshake );
								return true;
							}
						} catch ( InvalidHandshakeException e ) {
							// go on with an other draft
						}
					}
					if( draft == null ) {
						close( CloseFrame.PROTOCOL_ERROR, "no draft matches" );
					}
					return false;
				} else {
					// special case for multiple step handshakes
					Handshakedata tmphandshake = draft.translateHandshake( socketBuffer );
					if( !( tmphandshake instanceof ClientHandshake ) ) {
						flushAndClose( CloseFrame.PROTOCOL_ERROR, "wrong http function", false );
						return false;
					}
					ClientHandshake handshake = ( ClientHandshake ) tmphandshake;
					handshakestate = draft.acceptHandshakeAsServer( handshake );

					if( handshakestate == HandshakeState.MATCHED ) {
						open( handshake );
						return true;
					} else {
						close( CloseFrame.PROTOCOL_ERROR, "the handshake did finaly not match" );
					}
					return false;
				}
			} else if( role == Role.CLIENT ) {
				draft.setParseMode( role );
				Handshakedata tmphandshake = draft.translateHandshake( socketBuffer );
				if( !( tmphandshake instanceof ServerHandshake ) ) {
					flushAndClose( CloseFrame.PROTOCOL_ERROR, "wrong http function", false );
					return false;
				}
				ServerHandshake handshake = ( ServerHandshake ) tmphandshake;
				handshakestate = draft.acceptHandshakeAsClient( handshakerequest, handshake );
				if( handshakestate == HandshakeState.MATCHED ) {
					try {
						wsl.onWebsocketHandshakeReceivedAsClient( this, handshakerequest, handshake );
					} catch ( InvalidDataException e ) {
						flushAndClose( e.getCloseCode(), e.getMessage(), false );
						return false;
					} catch ( RuntimeException e ) {
						wsl.onWebsocketError( this, e );
						flushAndClose( CloseFrame.NEVER_CONNECTED, e.getMessage(), false );
						return false;
					}
					open( handshake );
					return true;
				} else {
					close( CloseFrame.PROTOCOL_ERROR, "draft " + draft + " refuses handshake" );
				}
			}
		} catch ( InvalidHandshakeException e ) {
			close( e );
		}
	} catch ( IncompleteHandshakeException e ) {
		if( tmpHandshakeBytes.capacity() == 0 ) {
			socketBuffer.reset();
			int newsize = e.getPreferedSize();
			if( newsize == 0 ) {
				newsize = socketBuffer.capacity() + 16;
			} else {
				assert ( e.getPreferedSize() >= socketBuffer.remaining() );
			}
			tmpHandshakeBytes = ByteBuffer.allocate( newsize );

			tmpHandshakeBytes.put( socketBufferNew );
			// tmpHandshakeBytes.flip();
		} else {
			tmpHandshakeBytes.position( tmpHandshakeBytes.limit() );
			tmpHandshakeBytes.limit( tmpHandshakeBytes.capacity() );
		}
	}
	return false;
}

@Override
public void processFrame( WebSocketImpl webSocketImpl, Framedata frame ) throws InvalidDataException {
	Opcode curop = frame.getOpcode();
	if( curop == Opcode.CLOSING ) {
		int code = CloseFrame.NOCODE;
		String reason = "";
		if( frame instanceof CloseFrame ) {
			CloseFrame cf = ( CloseFrame ) frame;
			code = cf.getCloseCode();
			reason = cf.getMessage();
		}
		if( webSocketImpl.getReadyState() == ReadyState.CLOSING ) {
			// complete the close handshake by disconnecting
			webSocketImpl.closeConnection( code, reason, true );
		} else {
			// echo close handshake
			if( getCloseHandshakeType() == CloseHandshakeType.TWOWAY )
				webSocketImpl.close( code, reason, true );
			else
				webSocketImpl.flushAndClose( code, reason, false );
		}
	} else if( curop == Opcode.PING ) {
		webSocketImpl.getWebSocketListener().onWebsocketPing( webSocketImpl, frame );
	} else if( curop == Opcode.PONG ) {
		webSocketImpl.updateLastPong();
		webSocketImpl.getWebSocketListener().onWebsocketPong( webSocketImpl, frame );
	} else if( !frame.isFin() || curop == Opcode.CONTINUOUS ) {
		if( curop != Opcode.CONTINUOUS ) {
			if( current_continuous_frame != null ) {
				log.trace( "Protocol error: Previous continuous frame sequence not completed." );
				throw new InvalidDataException( CloseFrame.PROTOCOL_ERROR, "Previous continuous frame sequence not completed." );
			}
			current_continuous_frame = frame;
			addToBufferList(frame.getPayloadData());
			checkBufferLimit();
		} else if( frame.isFin() ) {
			if( current_continuous_frame == null ) {
				log.trace( "Protocol error: Previous continuous frame sequence not completed." );
				throw new InvalidDataException( CloseFrame.PROTOCOL_ERROR, "Continuous frame sequence was not started." );
			}
			addToBufferList(frame.getPayloadData());
			checkBufferLimit();
			if( current_continuous_frame.getOpcode() == Opcode.TEXT ) {
				((FramedataImpl1) current_continuous_frame).setPayload( getPayloadFromByteBufferList() );
				((FramedataImpl1) current_continuous_frame ).isValid();
				try {
					webSocketImpl.getWebSocketListener().onWebsocketMessage( webSocketImpl, Charsetfunctions.stringUtf8( current_continuous_frame.getPayloadData() ) );
				} catch ( RuntimeException e ) {
					log.error( "Runtime exception during onWebsocketMessage", e );
					webSocketImpl.getWebSocketListener().onWebsocketError( webSocketImpl, e );
				}
			} else if( current_continuous_frame.getOpcode() == Opcode.BINARY ) {
				((FramedataImpl1) current_continuous_frame).setPayload( getPayloadFromByteBufferList() );
				((FramedataImpl1) current_continuous_frame ).isValid();
				try {
					webSocketImpl.getWebSocketListener().onWebsocketMessage( webSocketImpl, current_continuous_frame.getPayloadData() );
				} catch ( RuntimeException e ) {
					log.error( "Runtime exception during onWebsocketMessage", e );
					webSocketImpl.getWebSocketListener().onWebsocketError( webSocketImpl, e );
				}
			}
			current_continuous_frame = null;
			clearBufferList();
		} else if( current_continuous_frame == null ) {
			log.error( "Protocol error: Continuous frame sequence was not started." );
			throw new InvalidDataException( CloseFrame.PROTOCOL_ERROR, "Continuous frame sequence was not started." );
		}
		//Check if the whole payload is valid utf8, when the opcode indicates a text
		if( curop == Opcode.TEXT ) {
			if( !Charsetfunctions.isValidUTF8( frame.getPayloadData() ) ) {
				log.error( "Protocol error: Payload is not UTF8" );
				throw new InvalidDataException( CloseFrame.NO_UTF8 );
			}
		}
		//Checking if the current continuous frame contains a correct payload with the other frames combined
		if( curop == Opcode.CONTINUOUS && current_continuous_frame != null ) {
			addToBufferList(frame.getPayloadData());
		}
	} else if( current_continuous_frame != null ) {
		log.error( "Protocol error: Continuous frame sequence not completed." );
		throw new InvalidDataException( CloseFrame.PROTOCOL_ERROR, "Continuous frame sequence not completed." );
	} else if( curop == Opcode.TEXT ) {
		try {
			webSocketImpl.getWebSocketListener().onWebsocketMessage( webSocketImpl, Charsetfunctions.stringUtf8( frame.getPayloadData() ) );
		} catch ( RuntimeException e ) {
			log.error( "Runtime exception during onWebsocketMessage", e );
			webSocketImpl.getWebSocketListener().onWebsocketError( webSocketImpl, e );
		}
	} else if( curop == Opcode.BINARY ) {
		try {
			webSocketImpl.getWebSocketListener().onWebsocketMessage( webSocketImpl, frame.getPayloadData() );
		} catch ( RuntimeException e ) {
			log.error( "Runtime exception during onWebsocketMessage", e );
			webSocketImpl.getWebSocketListener().onWebsocketError( webSocketImpl, e );
		}
	} else {
		log.error( "non control or continious frame expected");
		throw new InvalidDataException( CloseFrame.PROTOCOL_ERROR, "non control or continious frame expected" );
	}
}

