@Override
public void processFrame( WebSocketImpl webSocketImpl, Framedata frame ) throws InvalidDataException {
	Opcode curop = frame.getOpcode();
	if( curop == Opcode.CLOSING ) {
		processFrameClosing(webSocketImpl, frame);
	} else if( curop == Opcode.PING ) {
		webSocketImpl.getWebSocketListener().onWebsocketPing( webSocketImpl, frame );
	} else if( curop == Opcode.PONG ) {
		webSocketImpl.updateLastPong();
		webSocketImpl.getWebSocketListener().onWebsocketPong( webSocketImpl, frame );
	} else if( !frame.isFin() || curop == Opcode.CONTINUOUS ) {
		if( curop != Opcode.CONTINUOUS ) {
			processFrameIsNotFin(frame);
		} else if( frame.isFin() ) {
			processFrameIsFin(webSocketImpl, frame);
		} else if( current_continuous_frame == null ) {
			log.error( "Protocol error: Continuous frame sequence was not started." );
			throw new InvalidDataException( CloseFrame.PROTOCOL_ERROR, "Continuous frame sequence was not started." );
		}
		//Check if the whole payload is valid utf8, when the opcode indicates a text
		if( curop == Opcode.TEXT ) {
			if( !Charsetfunctions.isValidUTF8( frame.getPayloadData() ) ) {
				log.error( "Protocol error: Payload is not UTF8" );
				throw new InvalidDataException( CloseFrame.NO_UTF8 );
			}
		}
		//Checking if the current continuous frame contains a correct payload with the other frames combined
		if( curop == Opcode.CONTINUOUS && current_continuous_frame != null ) {
			byteBufferList.add( frame.getPayloadData() );
		}
	} else if( current_continuous_frame != null ) {
		log.error( "Protocol error: Continuous frame sequence not completed." );
		throw new InvalidDataException( CloseFrame.PROTOCOL_ERROR, "Continuous frame sequence not completed." );
	} else if( curop == Opcode.TEXT ) {
		processFrameText(webSocketImpl, frame);
	} else if( curop == Opcode.BINARY ) {
		processFrameBinary(webSocketImpl, frame);
	} else {
		log.error( "non control or continious frame expected");
		throw new InvalidDataException( CloseFrame.PROTOCOL_ERROR, "non control or continious frame expected" );
	}
}

/**
 * Should be called when a Selector has a key that is writable for this
 * WebSocketImpl's SocketChannel connection.
 * 
 * @throws IOException
 *             When socket related I/O errors occur.
 * @throws InterruptedException
 */
public synchronized void decode() throws IOException {
	if( !socketBuffer.hasRemaining() )
		return;
	if( DEBUG )
		System.out.println( "process(" + socketBuffer.remaining() + "): {" + ( socketBuffer.remaining() > 1000 ? "too big to display" : new String( socketBuffer.array(), socketBuffer.position(), socketBuffer.remaining() ) ) + "}" );
	if( !handshakeComplete ) {
		if( draft == null ) {
			HandshakeState isflashedgecase = isFlashEdgeCase( socketBuffer );
			if( isflashedgecase == HandshakeState.MATCHED ) {
				channelWriteDirect( ByteBuffer.wrap( Charsetfunctions.utf8Bytes( wsl.getFlashPolicy( this ) ) ) );
				closeDirect( CloseFrame.FLASHPOLICY, "" );
				return;
			} else if( isflashedgecase == HandshakeState.MATCHING ) {
				return;
			}
		}
		HandshakeState handshakestate = null;
		socketBuffer.mark();
		try {
			if( role == Role.SERVER ) {
				if( draft == null ) {
					for( Draft d : known_drafts ) {
						try {
							d.setParseMode( role );
							socketBuffer.reset();
							Handshakedata tmphandshake = d.translateHandshake( socketBuffer );
							if( tmphandshake instanceof ClientHandshake == false ) {
								closeConnection( CloseFrame.PROTOCOL_ERROR, "wrong http function", false );
								return;
							}
							ClientHandshake handshake = (ClientHandshake) tmphandshake;
							handshakestate = d.acceptHandshakeAsServer( handshake );
							if( handshakestate == HandshakeState.MATCHED ) {
								ServerHandshakeBuilder response;
								try {
									response = wsl.onWebsocketHandshakeReceivedAsServer( this, d, handshake );
								} catch ( InvalidDataException e ) {
									closeConnection( e.getCloseCode(), e.getMessage(), false );
									return;
								}
								writeDirect( d.createHandshake( d.postProcessHandshakeResponseAsServer( handshake, response ), role ) );
								draft = d;
								open( handshake );
								decode();
								return;
							} else if( handshakestate == HandshakeState.MATCHING ) {
								if( draft != null ) {
									throw new InvalidHandshakeException( "multible drafts matching" );
								}
								draft = d;
							}
						} catch ( InvalidHandshakeException e ) {
							// go on with an other draft
						} catch ( IncompleteHandshakeException e ) {
							if( socketBuffer.limit() == socketBuffer.capacity() ) {
								close( CloseFrame.TOOBIG, "handshake is to big" );
							}
							// read more bytes for the handshake
							socketBuffer.position( socketBuffer.limit() );
							socketBuffer.limit( socketBuffer.capacity() );
							return;
						}
					}
					if( draft == null ) {
						close( CloseFrame.PROTOCOL_ERROR, "no draft matches" );
					}
					return;
				} else {
					// special case for multiple step handshakes
					Handshakedata tmphandshake = draft.translateHandshake( socketBuffer );
					if( tmphandshake instanceof ClientHandshake == false ) {
						closeConnection( CloseFrame.PROTOCOL_ERROR, "wrong http function", false );
						return;
					}
					ClientHandshake handshake = (ClientHandshake) tmphandshake;
					handshakestate = draft.acceptHandshakeAsServer( handshake );

					if( handshakestate == HandshakeState.MATCHED ) {
						open( handshake );
						decode();
					} else if( handshakestate != HandshakeState.MATCHING ) {
						close( CloseFrame.PROTOCOL_ERROR, "the handshake did finaly not match" );
					}
					return;
				}
			} else if( role == Role.CLIENT ) {
				draft.setParseMode( role );
				Handshakedata tmphandshake = draft.translateHandshake( socketBuffer );
				if( tmphandshake instanceof ServerHandshake == false ) {
					closeConnection( CloseFrame.PROTOCOL_ERROR, "Wwrong http function", false );
					return;
				}
				ServerHandshake handshake = (ServerHandshake) tmphandshake;
				handshakestate = draft.acceptHandshakeAsClient( handshakerequest, handshake );
				if( handshakestate == HandshakeState.MATCHED ) {
					try {
						wsl.onWebsocketHandshakeReceivedAsClient( this, handshakerequest, handshake );
					} catch ( InvalidDataException e ) {
						closeConnection( e.getCloseCode(), e.getMessage(), false );
						return;
					}
					open( handshake );
					decode();
				} else if( handshakestate == HandshakeState.MATCHING ) {
					return;
				} else {
					close( CloseFrame.PROTOCOL_ERROR, "draft " + draft + " refuses handshake" );
				}
			}
		} catch ( InvalidHandshakeException e ) {
			close( e );
		}
	} else {
		// Receiving frames
		List<Framedata> frames;
		try {
			frames = draft.translateFrame( socketBuffer );
			for( Framedata f : frames ) {
				if( DEBUG )
					System.out.println( "matched frame: " + f );
				Opcode curop = f.getOpcode();
				if( curop == Opcode.CLOSING ) {
					int code = CloseFrame.NOCODE;
					String reason = "";
					if( f instanceof CloseFrame ) {
						CloseFrame cf = (CloseFrame) f;
						code = cf.getCloseCode();
						reason = cf.getMessage();
					}
					if( closeHandshakeSent ) {
						// complete the close handshake by disconnecting
						closeConnection( code, reason, true );
					} else {
						// echo close handshake
						if( draft.getCloseHandshakeType() == CloseHandshakeType.TWOWAY )
							close( code, reason );
						closeConnection( code, reason, false );
					}
					continue;
				} else if( curop == Opcode.PING ) {
					wsl.onWebsocketPing( this, f );
					continue;
				} else if( curop == Opcode.PONG ) {
					wsl.onWebsocketPong( this, f );
					continue;
				} else {
					// process non control frames
					if( currentframe == null ) {
						if( f.getOpcode() == Opcode.CONTINIOUS ) {
							throw new InvalidFrameException( "unexpected continious frame" );
						} else if( f.isFin() ) {
							// receive normal onframe message
							deliverMessage( f );
						} else {
							// remember the frame whose payload is about to be continued
							currentframe = f;
						}
					} else if( f.getOpcode() == Opcode.CONTINIOUS ) {
						currentframe.append( f );
						if( f.isFin() ) {
							deliverMessage( currentframe );
							currentframe = null;
						}
					} else {
						throw new InvalidDataException( CloseFrame.PROTOCOL_ERROR, "non control or continious frame expected" );
					}
				}
			}
		} catch ( InvalidDataException e1 ) {
			wsl.onWebsocketError( this, e1 );
			close( e1 );
			return;
		}
	}

}

public DefaultSSLWebSocketServerFactory( SSLContext sslContext ) {
	this( sslContext, Executors.newSingleThreadScheduledExecutor() );
}

public void close( int code, String message, boolean remote ) {
	if( getReadyState()  != READYSTATE.CLOSING && readystate != READYSTATE.CLOSED ) {
		if( getReadyState()  == READYSTATE.OPEN ) {
			if( code == CloseFrame.ABNORMAL_CLOSE ) {
				assert ( !remote );
				setReadyState(READYSTATE.CLOSING);
				flushAndClose( code, message, false );
				return;
			}
			if( draft.getCloseHandshakeType() != CloseHandshakeType.NONE ) {
				try {
					if( !remote ) {
						try {
							wsl.onWebsocketCloseInitiated( this, code, message );
						} catch ( RuntimeException e ) {
							wsl.onWebsocketError( this, e );
						}
					}
					CloseFrame closeFrame = new CloseFrame();
					closeFrame.setReason( message );
					closeFrame.setCode( code );
					closeFrame.isValid();
					sendFrame( closeFrame );
				} catch ( InvalidDataException e ) {
					wsl.onWebsocketError( this, e );
					flushAndClose( CloseFrame.ABNORMAL_CLOSE, "generated frame is invalid", false );
				}
			}
			flushAndClose( code, message, remote );
		} else if( code == CloseFrame.FLASHPOLICY ) {
			assert ( remote );
			flushAndClose( CloseFrame.FLASHPOLICY, message, true );
		} else if( code == CloseFrame.PROTOCOL_ERROR ) { // this endpoint found a PROTOCOL_ERROR
			flushAndClose( code, message, remote );
		} else {
			flushAndClose( CloseFrame.NEVER_CONNECTED, message, false );
		}
		setReadyState(READYSTATE.CLOSING);
		tmpHandshakeBytes = null;
		return;
	}
}

public void run() {
	synchronized ( this ) {
		if( selectorthread != null )
			throw new IllegalStateException( getClass().getName() + " can only be started once." );
		selectorthread = Thread.currentThread();
		if( isclosed.get() ) {
			return;
		}
	}
	selectorthread.setName( "WebSocketSelector-" + selectorthread.getId() );
	try {
		server = ServerSocketChannel.open();
		server.configureBlocking( false );
		ServerSocket socket = server.socket();
		socket.setReceiveBufferSize( WebSocketImpl.RCVBUF );
		socket.setReuseAddress( isReuseAddr() );
		socket.bind( address );
		selector = Selector.open();
		server.register( selector, server.validOps() );
		startConnectionLostTimer();
		onStart();
	} catch ( IOException ex ) {
		handleFatal( null, ex );
		return;
	}
	try {
		int iShutdownCount = 5;
		int selectTimeout = 0;
		while ( !selectorthread.isInterrupted() && iShutdownCount != 0) {
			SelectionKey key = null;
			WebSocketImpl conn = null;
			try {
				if (isclosed.get()) {
					selectTimeout = 5;
				}
				int keyCount = selector.select( selectTimeout );
				if (keyCount == 0 && isclosed.get()) {
					iShutdownCount--;
				}
				Set<SelectionKey> keys = selector.selectedKeys();
				Iterator<SelectionKey> i = keys.iterator();

				while ( i.hasNext() ) {
					key = i.next();
					conn = null;

					if( !key.isValid() ) {
						// Object o = key.attachment();
						continue;
					}

					if( key.isAcceptable() ) {
						if( !onConnect( key ) ) {
							key.cancel();
							continue;
						}

						SocketChannel channel = server.accept();
						if(channel==null){
							continue;
						}
						channel.configureBlocking( false );
						Socket socket = channel.socket();
						socket.setTcpNoDelay( isTcpNoDelay() );
						socket.setKeepAlive( true );
						WebSocketImpl w = wsf.createWebSocket( this, drafts );
						w.setSelectionKey(channel.register( selector, SelectionKey.OP_READ, w ));
						try {
							w.channel = wsf.wrapChannel( channel, w.getSelectionKey() );
							i.remove();
							allocateBuffers( w );
							continue;
						} catch (IOException ex) {
							if( w.getSelectionKey() != null )
								w.getSelectionKey().cancel();

							handleIOException( w.getSelectionKey(), null, ex );
						}
						continue;
					}

					if( key.isReadable() ) {
						conn = (WebSocketImpl) key.attachment();
						ByteBuffer buf = takeBuffer();
						if(conn.channel == null){
							if( key != null )
								key.cancel();

							handleIOException( key, conn, new IOException() );
							continue;
						}
						try {
							if( SocketChannelIOHelper.read( buf, conn, conn.channel ) ) {
								if( buf.hasRemaining() ) {
									conn.inQueue.put( buf );
									queue( conn );
									i.remove();
									if( conn.channel instanceof WrappedByteChannel ) {
										if( ( (WrappedByteChannel) conn.channel ).isNeedRead() ) {
											iqueue.add( conn );
										}
									}
								} else
									pushBuffer( buf );
							} else {
								pushBuffer( buf );
							}
						} catch ( IOException e ) {
							pushBuffer( buf );
							throw e;
						}
					}
					if( key.isWritable() ) {
						conn = (WebSocketImpl) key.attachment();
						if( SocketChannelIOHelper.batch( conn, conn.channel ) ) {
							if( key.isValid() )
								key.interestOps( SelectionKey.OP_READ );
						}
					}
				}
				while ( !iqueue.isEmpty() ) {
					conn = iqueue.remove( 0 );
					WrappedByteChannel c = ( (WrappedByteChannel) conn.channel );
					ByteBuffer buf = takeBuffer();
					try {
						if( SocketChannelIOHelper.readMore( buf, conn, c ) )
							iqueue.add( conn );
						if( buf.hasRemaining() ) {
							conn.inQueue.put( buf );
							queue( conn );
						} else {
							pushBuffer( buf );
						}
					} catch ( IOException e ) {
						pushBuffer( buf );
						throw e;
					}

				}
			} catch ( CancelledKeyException e ) {
				// an other thread may cancel the key
			} catch ( ClosedByInterruptException e ) {
				return; // do the same stuff as when InterruptedException is thrown
			} catch ( IOException ex ) {
				if( key != null )
					key.cancel();
				handleIOException( key, conn, ex );
			} catch ( InterruptedException e ) {
				return;// FIXME controlled shutdown (e.g. take care of buffermanagement)
			}
		}

	} catch ( RuntimeException e ) {
		// should hopefully never occur
		handleFatal( null, e );
	} finally {
		stopConnectionLostTimer();
		if( decoders != null ) {
			for( WebSocketWorker w : decoders ) {
				w.interrupt();
			}
		}
		if( selector != null ) {
			try {
				selector.close();
			} catch ( IOException e ) {
				log.error( "IOException during selector.close", e );
				onError( null, e );
			}
		}
		if( server != null ) {
			try {
				server.close();
			} catch ( IOException e ) {
				log.error( "IOException during server.close", e );
				onError( null, e );
			}
		}
	}
}

/**
 * Implements the handshake protocol between two peers, required for the establishment of the SSL/TLS connection.
 * During the handshake, encryption configuration information - such as the list of available cipher suites - will be exchanged
 * and if the handshake is successful will lead to an established SSL/TLS session.
 * <p>
 * <p/>
 * A typical handshake will usually contain the following steps:
 * <p>
 * <ul>
 * <li>1. wrap:     ClientHello</li>
 * <li>2. unwrap:   ServerHello/Cert/ServerHelloDone</li>
 * <li>3. wrap:     ClientKeyExchange</li>
 * <li>4. wrap:     ChangeCipherSpec</li>
 * <li>5. wrap:     Finished</li>
 * <li>6. unwrap:   ChangeCipherSpec</li>
 * <li>7. unwrap:   Finished</li>
 * </ul>
 * <p/>
 * Handshake is also used during the end of the session, in order to properly close the connection between the two peers.
 * A proper connection close will typically include the one peer sending a CLOSE message to another, and then wait for
 * the other's CLOSE message to close the transport link. The other peer from his perspective would read a CLOSE message
 * from his peer and then enter the handshake procedure to send his own CLOSE message as well.
 *
 * @return True if the connection handshake was successful or false if an error occurred.
 * @throws IOException - if an error occurs during read/write to the socket channel.
 */
private boolean doHandshake() throws IOException {
	SSLEngineResult result;
	HandshakeStatus handshakeStatus;

	// NioSslPeer's fields myAppData and peerAppData are supposed to be large enough to hold all message data the peer
	// will send and expects to receive from the other peer respectively. Since the messages to be exchanged will usually be less
	// than 16KB long the capacity of these fields should also be smaller. Here we initialize these two local buffers
	// to be used for the handshake, while keeping client's buffers at the same size.
	int appBufferSize = engine.getSession().getApplicationBufferSize();
	myAppData = ByteBuffer.allocate( appBufferSize );
	peerAppData = ByteBuffer.allocate( appBufferSize );
	myNetData.clear();
	peerNetData.clear();

	handshakeStatus = engine.getHandshakeStatus();
	while( handshakeStatus != SSLEngineResult.HandshakeStatus.FINISHED && handshakeStatus != SSLEngineResult.HandshakeStatus.NOT_HANDSHAKING ) {
		switch(handshakeStatus) {
			case NEED_UNWRAP:
				if( socketChannel.read( peerNetData ) < 0 ) {
					if( engine.isInboundDone() && engine.isOutboundDone() ) {
						return false;
					}
					try {
						engine.closeInbound();
					} catch ( SSLException e ) {
						//Ignore, cant do anything against this exception
					}
					engine.closeOutbound();
					// After closeOutbound the engine will be set to WRAP state, in order to try to send a close message to the client.
					handshakeStatus = engine.getHandshakeStatus();
					break;
				}
				peerNetData.flip();
				try {
					result = engine.unwrap( peerNetData, peerAppData );
					peerNetData.compact();
					handshakeStatus = result.getHandshakeStatus();
				} catch ( SSLException sslException ) {
					engine.closeOutbound();
					handshakeStatus = engine.getHandshakeStatus();
					break;
				}
				switch(result.getStatus()) {
					case OK:
						break;
					case BUFFER_OVERFLOW:
						// Will occur when peerAppData's capacity is smaller than the data derived from peerNetData's unwrap.
						peerAppData = enlargeApplicationBuffer( peerAppData );
						break;
					case BUFFER_UNDERFLOW:
						// Will occur either when no data was read from the peer or when the peerNetData buffer was too small to hold all peer's data.
						peerNetData = handleBufferUnderflow( peerNetData );
						break;
					case CLOSED:
						if( engine.isOutboundDone() ) {
							return false;
						} else {
							engine.closeOutbound();
							handshakeStatus = engine.getHandshakeStatus();
							break;
						}
					default:
						throw new IllegalStateException( "Invalid SSL status: " + result.getStatus() );
				}
				break;
			case NEED_WRAP:
				myNetData.clear();
				try {
					result = engine.wrap( myAppData, myNetData );
					handshakeStatus = result.getHandshakeStatus();
				} catch ( SSLException sslException ) {
					engine.closeOutbound();
					handshakeStatus = engine.getHandshakeStatus();
					break;
				}
				switch(result.getStatus()) {
					case OK:
						myNetData.flip();
						while( myNetData.hasRemaining() ) {
							socketChannel.write( myNetData );
						}
						break;
					case BUFFER_OVERFLOW:
						// Will occur if there is not enough space in myNetData buffer to write all the data that would be generated by the method wrap.
						// Since myNetData is set to session's packet size we should not get to this point because SSLEngine is supposed
						// to produce messages smaller or equal to that, but a general handling would be the following:
						myNetData = enlargePacketBuffer( myNetData );
						break;
					case BUFFER_UNDERFLOW:
						throw new SSLException( "Buffer underflow occured after a wrap. I don't think we should ever get here." );
					case CLOSED:
						try {
							myNetData.flip();
							while( myNetData.hasRemaining() ) {
								socketChannel.write( myNetData );
							}
							// At this point the handshake status will probably be NEED_UNWRAP so we make sure that peerNetData is clear to read.
							peerNetData.clear();
						} catch ( Exception e ) {
							handshakeStatus = engine.getHandshakeStatus();
						}
						break;
					default:
						throw new IllegalStateException( "Invalid SSL status: " + result.getStatus() );
				}
				break;
			case NEED_TASK:
				Runnable task;
				while( ( task = engine.getDelegatedTask() ) != null ) {
					executor.execute( task );
				}
				handshakeStatus = engine.getHandshakeStatus();
				break;
			case FINISHED:
				break;
			case NOT_HANDSHAKING:
				break;
			default:
				throw new IllegalStateException( "Invalid SSL status: " + handshakeStatus );
		}
	}

	return true;

}

public void run() {
	if (!doEnsureSingleThread()) {
		return;
	}
	if (!doSetupSelectorAndServerThread()) {
		return;
	}
	try {
		int iShutdownCount = 5;
		int selectTimeout = 0;
		while ( !selectorthread.isInterrupted() && iShutdownCount != 0) {
			SelectionKey key = null;
			WebSocketImpl conn = null;
			try {
				if (isclosed.get()) {
					selectTimeout = 5;
				}
				int keyCount = selector.select( selectTimeout );
				if (keyCount == 0 && isclosed.get()) {
					iShutdownCount--;
				}
				Set<SelectionKey> keys = selector.selectedKeys();
				Iterator<SelectionKey> i = keys.iterator();

				while ( i.hasNext() ) {
					key = i.next();
					conn = null;

					if( !key.isValid() ) {
						continue;
					}

					if( key.isAcceptable() ) {
						doAccept(key, i);
						continue;
					}

					if( key.isReadable() ) {
						if (!doRead(key, i)) {
							continue;
						}
					}

					if( key.isWritable() ) {
						doWrite(key);
					}
				}
				doAdditionalRead();
			} catch ( CancelledKeyException e ) {
				// an other thread may cancel the key
			} catch ( ClosedByInterruptException e ) {
				return; // do the same stuff as when InterruptedException is thrown
			} catch ( IOException ex ) {
				if( key != null )
					key.cancel();
				handleIOException( key, conn, ex );
			} catch ( InterruptedException e ) {
				// FIXME controlled shutdown (e.g. take care of buffermanagement)
				return;
			}
		}
	} catch ( RuntimeException e ) {
		// should hopefully never occur
		handleFatal( null, e );
	} finally {
		doServerShutdown();
	}
}

