/** Store the Result cookies into the cookie manager, and place relevant cookies into the Response object. */
static void storeCookies(HttpConnection.Request req, HttpConnection.Response res, URL url, Map<String, List<String>> resHeaders) throws IOException {
    CookieManager manager = req.cookieManager();
    URI uri = CookieUtil.asUri(url);
    manager.put(uri, resHeaders); // stores cookies for session

    // set up the simple cookies() map
    // the response may include cookies that are not relevant to this request, but users may require them if they are not using the cookie manager (setting request cookies only from the simple cookies() response):
    for (Map.Entry<String, List<String>> entry : resHeaders.entrySet()) {
        String name = entry.getKey();
        List<String> values = entry.getValue();
        if (name.equalsIgnoreCase("Set-Cookie")) {
            for (String value : values) {
                parseCookie(value, res);
            }
        }
    }
}

/**
 * This methods allows the reset of the connection lost timer in case of a changed parameter
 * @since 1.3.4
 */
private void restartConnectionLostTimer() {
	cancelConnectionLostTimer();
	connectionLostTimer = new Timer("WebSocketTimer");
	connectionLostTimerTask = new TimerTask() {

		/**
		 * Keep the connections in a separate list to not cause deadlocks
		 */
		private ArrayList<WebSocket> connections = new ArrayList<WebSocket>(  );
		@Override
		public void run() {
			connections.clear();
			try {
				connections.addAll( getConnections() );
				long current = ( System.currentTimeMillis() - ( connectionLostTimeout * 1500 ) );
				for( WebSocket conn : connections ) {
					executeConnectionLostDetection(conn, current);
				}
			} catch ( Exception e ) {
				//Ignore this exception
			}
			connections.clear();
		}
	};
	connectionLostTimer.scheduleAtFixedRate( connectionLostTimerTask,1000L*connectionLostTimeout , 1000L*connectionLostTimeout );

}

private void text(StringBuilder accum) {
    for (Node child : childNodes) {
        if (child instanceof TextNode) {
            TextNode textNode = (TextNode) child;
            String text = textNode.getWholeText();

            if (!tag.preserveWhitespace()) {
                text = TextNode.normaliseWhitespace(text);
                if (TextNode.lastCharIsWhitespace(accum))
                    text = TextNode.stripLeadingWhitespace(text);
            }
            accum.append(text);

        } else if (child instanceof Element) {
            Element element = (Element) child;
            if (accum.length() > 0 && element.isBlock() && !TextNode.lastCharIsWhitespace(accum))
                accum.append(" ");
            element.text(accum);
        }
    }
}

