public Framedata translateSingleFrame( ByteBuffer buffer ) throws IncompleteException, InvalidDataException {
	int maxpacketsize = buffer.remaining();
	int realpacketsize = 2;
	if( maxpacketsize < realpacketsize ) {
		log.trace( "Incomplete frame" );
		throw new IncompleteException( realpacketsize );
	}
	byte b1 = buffer.get( /*0*/ );
	boolean FIN = b1 >> 8 != 0;
	boolean rsv1 = false;
	boolean rsv2 = false;
	boolean rsv3 = false;
	if( ( b1 & 0x40 ) != 0 ) {
		rsv1 = true;
	}
	if( ( b1 & 0x20 ) != 0 ) {
		rsv2 = true;
	}
	if( ( b1 & 0x10 ) != 0 ) {
		rsv3 = true;
	}
	byte b2 = buffer.get( /*1*/ );
	boolean MASK = ( b2 & -128 ) != 0;
	int payloadlength = ( byte ) ( b2 & ~( byte ) 128 );
	Opcode optcode = toOpcode( ( byte ) ( b1 & 15 ) );

	if( !( payloadlength >= 0 && payloadlength <= 125 ) ) {

		if( optcode == Opcode.PING || optcode == Opcode.PONG || optcode == Opcode.CLOSING ) {
			log.trace( "Invalid frame: more than 125 octets" );
			throw new InvalidFrameException( "more than 125 octets" );
		}
		if( payloadlength == 126 ) {
			realpacketsize += 2; // additional length bytes
			if( maxpacketsize < realpacketsize ) {
				log.trace( "Incomplete frame" );
				throw new IncompleteException( realpacketsize );
			}
			byte[] sizebytes = new byte[3];
			sizebytes[1] = buffer.get( /*1 + 1*/ );
			sizebytes[2] = buffer.get( /*1 + 2*/ );
			payloadlength = new BigInteger( sizebytes ).intValue();
		} else {
			realpacketsize += 8; // additional length bytes
			if( maxpacketsize < realpacketsize ) {
				log.trace( "Incomplete frame" );
				throw new IncompleteException( realpacketsize );
			}
			byte[] bytes = new byte[8];
			for( int i = 0; i < 8; i++ ) {
				bytes[i] = buffer.get( /*1 + i*/ );
			}
			long length = new BigInteger( bytes ).longValue();
			if( length > Integer.MAX_VALUE ) {
				log.trace( "Limit exedeed: Payloadsize is to big..." );
				throw new LimitExedeedException( "Payloadsize is to big..." );
			} else {
				payloadlength = ( int ) length;
			}
		}
	}

	// int maskskeystart = foff + realpacketsize;
	realpacketsize += ( MASK ? 4 : 0 );
	// int payloadstart = foff + realpacketsize;
	realpacketsize += payloadlength;

	if( maxpacketsize < realpacketsize )
		throw new IncompleteException( realpacketsize );

	ByteBuffer payload = ByteBuffer.allocate( checkAlloc( payloadlength ) );
	if( MASK ) {
		byte[] maskskey = new byte[4];
		buffer.get( maskskey );
		for( int i = 0; i < payloadlength; i++ ) {
			payload.put( ( byte ) ( buffer.get( /*payloadstart + i*/ ) ^ maskskey[i % 4] ) );
		}
	} else {
		payload.put( buffer.array(), buffer.position(), payload.limit() );
		buffer.position( buffer.position() + payload.limit() );
	}

	FramedataImpl1 frame = FramedataImpl1.get( optcode );
	frame.setFin( FIN );
	frame.setRSV1( rsv1 );
	frame.setRSV2( rsv2 );
	frame.setRSV3( rsv3 );
	payload.flip();
	frame.setPayload( payload );
	getExtension().isFrameValid(frame);
	getExtension().decodeFrame(frame);
	log.trace( "afterDecoding({}): {}", frame.getPayloadData().remaining(), ( frame.getPayloadData().remaining() > 1000 ? "too big to display" : new String( frame.getPayloadData().array() ) ) );
	frame.isValid();
	return frame;
}

/**
 * Start a depth-first traverse of the root and all of its descendants.
 * @param root the root node point to traverse.
 */
public void traverse(Node root) {
    Node node = root;
    int depth = 0;

    while (node != null) {
        visitor.head(node, depth);
        if (node.childNodeSize() > 0) {
            node = node.childNode(0);
            depth++;
        } else {
            while (node.nextSibling() == null && depth > 0) {
                visitor.tail(node, depth);
                node = node.parentNode();
                depth--;
            }
            visitor.tail(node, depth);
            if (node == root)
                break;
            node = node.nextSibling();
        }
    }
}

static void escape(Appendable accum, String string, OutputSettings out,
                   boolean forText, boolean forAttribute, boolean normaliseWhite, boolean stripLeadingWhite, boolean trimTrailing) throws IOException {

    boolean lastWasWhite = false;
    boolean reachedNonWhite = false;
    final EscapeMode escapeMode = out.escapeMode();
    final CharsetEncoder encoder = out.encoder();
    final CoreCharset coreCharset = out.coreCharset; // init in out.prepareEncoder()
    final int length = string.length();

    int codePoint;
    boolean skipped = false;
    for (int offset = 0; offset < length; offset += Character.charCount(codePoint)) {
        codePoint = string.codePointAt(offset);

        if (normaliseWhite) {
            if (StringUtil.isWhitespace(codePoint)) {
                if (stripLeadingWhite && !reachedNonWhite) continue;
                if (lastWasWhite) continue;
                if (trimTrailing) {
                    skipped = true;
                    continue;
                }
                accum.append(' ');
                lastWasWhite = true;
                continue;
            } else {
                lastWasWhite = false;
                reachedNonWhite = true;
                if (skipped) {
                    accum.append(' '); // wasn't the end, so need to place a normalized space
                    skipped = false;
                }
            }
        }
        // surrogate pairs, split implementation for efficiency on single char common case (saves creating strings, char[]):
        if (codePoint < Character.MIN_SUPPLEMENTARY_CODE_POINT) {
            final char c = (char) codePoint;
            // html specific and required escapes:
            switch (c) {
                case '&':
                    accum.append("&amp;");
                    break;
                case 0xA0:
                    if (escapeMode != EscapeMode.xhtml)
                        accum.append("&nbsp;");
                    else
                        accum.append("&#xa0;");
                    break;
                case '<':
                    // escape when in character data or when in a xml attribute val or XML syntax; not needed in html attr val
                    if (forText || escapeMode == EscapeMode.xhtml || out.syntax() == Syntax.xml)
                        accum.append("&lt;");
                    else
                        accum.append(c);
                    break;
                case '>':
                    if (forText)
                        accum.append("&gt;");
                    else
                        accum.append(c);
                    break;
                case '"':
                    if (forAttribute)
                        accum.append("&quot;");
                    else
                        accum.append(c);
                    break;
                case '\'':
                    if (forAttribute && forText) { // special case for the Entities.escape(string) method when we are maximally escaping. Otherwise, because we output attributes in "", there's no need to escape.
                        if (escapeMode == EscapeMode.xhtml)
                            accum.append("&#x27;");
                        else
                            accum.append("&apos;");
                    }
                    else
                        accum.append(c);
                    break;
                // we escape ascii control <x20 (other than tab, line-feed, carriage return)  for XML compliance (required) and HTML ease of reading (not required) - https://www.w3.org/TR/xml/#charsets
                case 0x9:
                case 0xA:
                case 0xD:
                    accum.append(c);
                    break;
                default:
                    if (c < 0x20 || !canEncode(coreCharset, c, encoder))
                        appendEncoded(accum, escapeMode, codePoint);
                    else
                        accum.append(c);
            }
        } else {
            final String c = new String(Character.toChars(codePoint));
            if (encoder.canEncode(c)) // uses fallback encoder for simplicity
                accum.append(c);
            else
                appendEncoded(accum, escapeMode, codePoint);
        }
    }
}

