public int read( ByteBuffer dst ) throws IOException {
	if( !isHandShakeComplete() ) {
		processHandshake();
		return 0;
	}

	int purged = readRemaining( dst );
	if( purged != 0 )
		return purged;

	assert ( inData.position() == 0 );
	inData.clear();

	if( !inCrypt.hasRemaining() )
		inCrypt.clear();
	else
		inCrypt.compact();

	if( sc.read( inCrypt ) == -1 ) {
		return -1;
	}
	inCrypt.flip();
	unwrap();
	return transfereTo( inData, dst );

}

