@Override
public void processFrame( WebSocketImpl webSocketImpl, Framedata frame ) throws InvalidDataException {
	Opcode curop = frame.getOpcode();
	if( curop == Opcode.CLOSING ) {
		processFrameClosing(webSocketImpl, frame);
	} else if( curop == Opcode.PING ) {
		webSocketImpl.getWebSocketListener().onWebsocketPing( webSocketImpl, frame );
	} else if( curop == Opcode.PONG ) {
		webSocketImpl.updateLastPong();
		webSocketImpl.getWebSocketListener().onWebsocketPong( webSocketImpl, frame );
	} else if( !frame.isFin() || curop == Opcode.CONTINUOUS ) {
		if( curop != Opcode.CONTINUOUS ) {
			processFrameIsNotFin(frame);
		} else if( frame.isFin() ) {
			processFrameIsFin(webSocketImpl, frame);
		} else if( current_continuous_frame == null ) {
			log.error( "Protocol error: Continuous frame sequence was not started." );
			throw new InvalidDataException( CloseFrame.PROTOCOL_ERROR, "Continuous frame sequence was not started." );
		}
		//Check if the whole payload is valid utf8, when the opcode indicates a text
		if( curop == Opcode.TEXT ) {
			if( !Charsetfunctions.isValidUTF8( frame.getPayloadData() ) ) {
				log.error( "Protocol error: Payload is not UTF8" );
				throw new InvalidDataException( CloseFrame.NO_UTF8 );
			}
		}
		//Checking if the current continuous frame contains a correct payload with the other frames combined
		if( curop == Opcode.CONTINUOUS && current_continuous_frame != null ) {
			addToBufferList(frame.getPayloadData());
		}
	} else if( current_continuous_frame != null ) {
		log.error( "Protocol error: Continuous frame sequence not completed." );
		throw new InvalidDataException( CloseFrame.PROTOCOL_ERROR, "Continuous frame sequence not completed." );
	} else if( curop == Opcode.TEXT ) {
		processFrameText(webSocketImpl, frame);
	} else if( curop == Opcode.BINARY ) {
		processFrameBinary(webSocketImpl, frame);
	} else {
		log.error( "non control or continious frame expected");
		throw new InvalidDataException( CloseFrame.PROTOCOL_ERROR, "non control or continious frame expected" );
	}
}

/**
 * Method to generate a full bytebuffer out of all the fragmented frame payload
 * @return a bytebuffer containing all the data
 * @throws LimitExedeedException will be thrown when the totalSize is bigger then Integer.MAX_VALUE due to not being able to allocate more
 */
private ByteBuffer getPayloadFromByteBufferList() throws LimitExedeedException {
	long totalSize = 0;
	ByteBuffer resultingByteBuffer;
	synchronized (byteBufferList) {
		for (ByteBuffer buffer : byteBufferList) {
			totalSize += buffer.limit();
		}
		checkBufferLimit();
		resultingByteBuffer = ByteBuffer.allocate( (int) totalSize );
		for (ByteBuffer buffer : byteBufferList) {
			resultingByteBuffer.put( buffer );
		}
	}
	resultingByteBuffer.flip();
	return resultingByteBuffer;
}

  /**
   * Should be called when a Selector has a key that is writable for this
   * WebSocket's SocketChannel connection.
   * @throws IOException When socket related I/O errors occur.
   * @throws NoSuchAlgorithmException 
   */
  void handleRead() throws IOException, NoSuchAlgorithmException {

    int bytesRead = -1;

    socketBuffer.rewind();
    bytesRead = this.socketChannel.read(this.socketBuffer);


    if ( bytesRead == -1 )  {
      close();
    } 
    else if( bytesRead > maxpayloadsize ){
    	wsl.onError ( new RuntimeException("recived packet to big") );
    	abort ( "recived packet to big" );
    }
    else if ( bytesRead > 0) {
		if(DEBUG) System.out.println( "got: {" + new String( socketBuffer.array() , 0 , bytesRead ) + "}" );
		if( !handshakeComplete ){
			if(draft.isFlashEdgeCase( socketBuffer.array() , bytesRead )){
				channelWrite( ByteBuffer.wrap( wsl.getFlashPolicy( this ).getBytes( UTF8_CHARSET ) ) );
				return;
			}
			try{
				Handshakedata handshake;
				HandshakeState handshakestate = null;

				if( role == Role.SERVER ){
					if( draft == null ){
						handshake = Draft.translateHandshakeHttp( socketBuffer.array () , bytesRead );
						for( Draft d : known_drafts ){
							handshakestate = d.acceptHandshakeAsServer( handshake );
							if( handshakestate == HandshakeState.MATCHED ){
								HandshakeBuilder response = wsl.onHandshakeRecievedAsServer ( this , d , handshake  );
								channelWrite ( d.createHandshake ( d.postProcessHandshakeResponseAsServer ( handshake , response ) , role ) );
								draft = d;
								this.handshakeComplete = true;
								open();
								return;
							}
							else if ( handshakestate == HandshakeState.MATCHING ){
								if( draft != null ){
									throw new InvalidHandshakeException( "multible drafts matching" );
								}
								draft = d;
							}
						}
						if( draft == null ){
							abort( "no draft matches");
						}
						return;
					}
					else{
						//special case for multiple step handshakes
						handshake = draft.translateHandshake( socketBuffer.array () , bytesRead );
						handshakestate = draft.acceptHandshakeAsServer( handshake );

						if( handshakestate == HandshakeState.MATCHED ){
							open();
						}
						else if ( handshakestate != HandshakeState.MATCHING) {
							abort( "the handshake did finaly not match" );
						}
						return;
					}
				}
				else if( role == Role.CLIENT){
					handshake= draft.translateHandshake( socketBuffer.array () , bytesRead );
					handshakestate = draft.acceptHandshakeAsClient ( handshakerequest , handshake );
					if( handshakestate == HandshakeState.MATCHED ){
						this.handshakeComplete = true;
						open();
					}
					else if ( handshakestate == HandshakeState.MATCHING ) {
						return;
					}
					else{
						abort( "draft "+draft.getClass ().getSimpleName ()+" or server refuses handshake");
					}
				}
			}
			catch (InvalidHandshakeException e) {
				abort( "draft "+draft+" refuses handshake: " + e.getMessage ());
			}
		}
		else{
			//Receiving frames
			List<Framedata> frames = draft.translateFrame ( socketBuffer , bytesRead );
			for( Framedata f : frames){
				Opcode curop = f.getOpcode ();
				if( curop == null )// Ignore undefined opcodes
					continue;
				else if( curop == Opcode.CLOSING){
					sendFrame ( new FramedataImpl1 ( Opcode.CLOSING ) );
					close();
					continue;
				}
				else if( curop == Opcode.PING){
					sendFrame ( new FramedataImpl1 ( Opcode.PONG ) );
					continue;
				}
				else if( curop == Opcode.PONG){
					wsl.onPong ();
					continue;
				}
				if( currentframe == null){
					if( f.isFin () ){
						if( f.getOpcode () == Opcode.TEXT ){
							wsl.onMessage ( this , new String ( f.getPayloadData () , UTF8_CHARSET ) );
						}
						else if( f.getOpcode () == Opcode.BINARY ){
							wsl.onMessage ( this , f.getPayloadData () );
						}
						else{
							if(DEBUG) System.out.println ( "Ignoring frame:" + f.toString() );
						}
					}
					else{
						currentframe = f;
					}
				}
				else if( f.getOpcode() == Opcode.CONTINIOUS ){
					try {
						currentframe.append ( f );
					} catch ( InvalidFrameException e ) {
						wsl.onError ( e );
						abort( "invalid frame: " +e.getMessage () );
					}
					if( f.isFin () ){
						wsl.onMessage ( this , new String ( f.getPayloadData () , UTF8_CHARSET ) );
						currentframe = null;
					}
				}
			}
		}
	}
  }

@Override
public HandshakeState acceptHandshakeAsServer( ClientHandshake handshakedata ) throws InvalidHandshakeException {
	int v = readVersion( handshakedata );
	if( v != 13 ) {
		log.trace("acceptHandshakeAsServer - Wrong websocket version.");
		return HandshakeState.NOT_MATCHED;
	}
	HandshakeState extensionState = HandshakeState.NOT_MATCHED;
	String requestedExtension = handshakedata.getFieldValue(SEC_WEB_SOCKET_EXTENSIONS);
	for( IExtension knownExtension : knownExtensions ) {
		if( knownExtension.acceptProvidedExtensionAsServer( requestedExtension ) ) {
			extension = knownExtension;
			extensionState = HandshakeState.MATCHED;
			log.trace("acceptHandshakeAsServer - Matching extension found: {}", extension);
			break;
		}
	}
	HandshakeState protocolState = HandshakeState.NOT_MATCHED;
	String requestedProtocol = handshakedata.getFieldValue(SEC_WEB_SOCKET_PROTOCOL);
	for( IProtocol knownProtocol : knownProtocols ) {
		if( knownProtocol.acceptProvidedProtocol( requestedProtocol ) ) {
			protocol = knownProtocol;
			protocolState = HandshakeState.MATCHED;
			log.trace("acceptHandshakeAsServer - Matching protocol found: {}", protocol);
			break;
		}
	}
	if (protocolState == HandshakeState.MATCHED && extensionState == HandshakeState.MATCHED) {
		return HandshakeState.MATCHED;
	}
	log.trace("acceptHandshakeAsServer - No matching extension or protocol found.");
	return HandshakeState.NOT_MATCHED;
}

