public Document parse() {
    while (!queue.isEmpty()) {
        if (matches("<!--")) {
            parseComment();
        } else if (matches("<?") || matches("<!")) {
            parseXmlDecl();
        } else if (matches("</")) {
            parseEndTag();
        } else if (matches("<")) {
            parseStartTag();
        } else {
            parseText();
        }
    }
    return doc;
}

public void head(org.jsoup.nodes.Node source, int depth) {
    namespacesStack.push(new HashMap<>(namespacesStack.peek())); // inherit from above on the stack
    if (source instanceof org.jsoup.nodes.Element) {
        org.jsoup.nodes.Element sourceEl = (org.jsoup.nodes.Element) source;

        String prefix = updateNamespaces(sourceEl);
        String namespace = namespacesStack.peek().get(prefix);
        String tagName = sourceEl.tagName();

        /* Tag names in XML are quite, but less, permissive than HTML. Rather than reimplement the validation,
        we just try to use it as-is. If it fails, insert as a text node instead. We don't try to normalize the
        tagname to something safe, because that isn't going to be meaningful downstream. This seems(?) to be
        how browsers handle the situation, also. https://github.com/jhy/jsoup/issues/1093 */
        try {
            Element el = namespace == null && tagName.contains(":") ?
                doc.createElementNS("", tagName) : // doesn't have a real namespace defined
                doc.createElementNS(namespace, tagName);
            copyAttributes(sourceEl, el);
            dest.appendChild(el);
            dest = el; // descend
        } catch (DOMException e) {
            dest.appendChild(doc.createTextNode("<" + tagName + ">"));
        }
    } else if (source instanceof org.jsoup.nodes.TextNode) {
        org.jsoup.nodes.TextNode sourceText = (org.jsoup.nodes.TextNode) source;
        Text text = doc.createTextNode(sourceText.getWholeText());
        dest.appendChild(text);
    } else if (source instanceof org.jsoup.nodes.Comment) {
        org.jsoup.nodes.Comment sourceComment = (org.jsoup.nodes.Comment) source;
        Comment comment = doc.createComment(sourceComment.getData());
        dest.appendChild(comment);
    } else if (source instanceof org.jsoup.nodes.DataNode) {
        org.jsoup.nodes.DataNode sourceData = (org.jsoup.nodes.DataNode) source;
        Text node = doc.createTextNode(sourceData.getWholeData());
        dest.appendChild(node);
    } else {
        // unhandled
        // not that doctype is not handled here - rather it is used in the initial doc creation
    }
}

@Override
public List<Framedata> translateFrame( ByteBuffer buffer ) throws InvalidDataException {
	List<Framedata> frames = translateRegularFrame( buffer );
	if( frames == null ) {
		throw new InvalidDataException( CloseFrame.PROTOCOL_ERROR );
	}
	return frames;
}

    @Override
    public void setPayload(ByteBuffer payload) {
		code = CloseFrame.NOCODE;
		reason = "";
		payload.mark();
		if( payload.remaining() == 0 ) {
			code = CloseFrame.NORMAL;
		} else if( payload.remaining() == 1 ) {
			code = CloseFrame.PROTOCOL_ERROR;
		} else {
			if( payload.remaining() >= 2 ) {
				ByteBuffer bb = ByteBuffer.allocate( 4 );
				bb.position( 2 );
				bb.putShort( payload.getShort() );
				bb.position( 0 );
				code = bb.getInt();
			}
			payload.reset();
			try {
				int mark = payload.position();// because stringUtf8 also creates a mark
				try {
					payload.position( payload.position() + 2 );
					reason = Charsetfunctions.stringUtf8( payload );
				} catch ( IllegalArgumentException e ) {
					throw new InvalidDataException( CloseFrame.NO_UTF8 );
				} finally {
					payload.position( mark );
				}
			} catch ( InvalidDataException e ) {
				code = CloseFrame.NO_UTF8;
				reason = null;
			}
		}
	}

