	public void run() {
		if(thread == null)
			thread = Thread.currentThread();
		try {
			tryToConnect( new InetSocketAddress( uri.getHost(), getPort() ) );
		} 
		catch (ClosedByInterruptException e) {
			onError( null, e );
			return;
		}catch ( IOException e ) {//
			onError( conn, e );
			conn.close();
			return;
		} catch ( SecurityException e ) {
			onError( conn, e );
			conn.close();
			return;
        } catch ( UnresolvedAddressException e ) {
            onError( conn, e );
            conn.close();
            return;
		}

		while ( !Thread.interrupted() ) {
			SelectionKey key = null;
			try {
				conn.handleWrite();
				selector.select();
				Set<SelectionKey> keys = selector.selectedKeys();
				Iterator<SelectionKey> i = keys.iterator();

				while ( i.hasNext() ) {
					key = i.next();
					i.remove();
					if( key.isReadable() ) {
						conn.handleRead();
					}
					if(!key.isValid()){
						continue;
					}
					if( key.isWritable() ) {
						conn.handleWrite();
					}
					if( key.isConnectable() ) {
						finishConnect();
					}
				}
			} catch ( InvalidHandshakeException e ) {
				onError( e );
				close();
				return;
			} catch ( IOException e ) {
				// if(e instanceof ConnectException == false)
				onError( e );
				close();
				return;
			} catch ( InterruptedException e ) {
				onError( e );
				close();
				return;
			} catch ( RuntimeException /*| CharacterCodingException*/ e ) {
				// this catch case covers internal errors only and indicates a bug in this websocket implementation
				onError( e );
				close();
				return;
			}
		}
		conn.close(); // close() is synchronously calling onClose(conn) so we don't have to
		try {
			selector.close();
		} catch ( IOException e ) {
			onError( e );
		}
		selector = null;
		try {
			client.close();
		} catch ( IOException e ) {
			onError( e );
		}
		client = null;
	}

    private Evaluator consumeEvaluator() {
        if (tq.matchChomp("#"))
            return byId();
        else if (tq.matchChomp("."))
            return byClass();
        else if (tq.matchesWord() || tq.matches("*|"))
            return byTag();
        else if (tq.matches("["))
            return byAttribute();
        else if (tq.matchChomp("*"))
            return new Evaluator.AllElements();
        else if (tq.matchChomp(":"))
            return parsePseudoSelector();
		else // unhandled
            throw new Selector.SelectorParseException("Could not parse query '%s': unexpected token at '%s'", query, tq.remainder());
    }

public void run() {
	if( thread != null )
		throw new IllegalStateException( "This instance of " + getClass().getSimpleName() + " can only be started once the same time." );
	thread = Thread.currentThread();
	try {
		server = ServerSocketChannel.open();
		server.configureBlocking( false );
		server.socket().bind( address );
		//InetAddress.getLocalHost()
		selector = Selector.open();
		server.register( selector, server.validOps() );
	} catch ( IOException ex ) {
		onWebsocketError( null, ex );
		return;
	}

	while ( !thread.isInterrupted() ) {
		SelectionKey key = null;
		WebSocket conn = null;
		try {
			selector.select();
			Set<SelectionKey> keys = selector.selectedKeys();
			Iterator<SelectionKey> i = keys.iterator();

			while ( i.hasNext() ) {
				key = i.next();

				// Remove the current key
				i.remove();

				// if isAcceptable == true
				// then a client required a connection
				if( key.isAcceptable() ) {
					SocketChannel client = server.accept();
					client.configureBlocking( false );
					WebSocket c = new WebSocket( this, Collections.singletonList( draft ), client.socket().getChannel() );
					client.register( selector, SelectionKey.OP_READ, c );
				}

				// if isReadable == true
				// then the server is ready to read
				if( key.isReadable() ) {
					conn = (WebSocket) key.attachment();
					conn.handleRead();
				}

				// if isWritable == true
				// then we need to send the rest of the data to the client
				if( key.isValid() && key.isWritable() ) {
					conn = (WebSocket) key.attachment();
					conn.flush();
					key.channel().register( selector, SelectionKey.OP_READ, conn );
				}
			}
			Iterator<WebSocket> it = this.connections.iterator();
			while ( it.hasNext() ) {
				// We have to do this check here, and not in the thread that
				// adds the buffered data to the WebSocket, because the
				// Selector is not thread-safe, and can only be accessed
				// by this thread.
				conn = it.next();
				if( conn.hasBufferedData() ) {
					conn.flush();
					// key.channel().register( selector, SelectionKey.OP_READ | SelectionKey.OP_WRITE, conn );
				}
			}
		} catch ( IOException ex ) {
			if( key != null )
				key.cancel();
			onWebsocketError( conn, ex );// conn may be null here
			if( conn != null ) {
				conn.close( CloseFrame.ABNROMAL_CLOSE );
			}
		}
	}
}

/**
 * Process the frame if it is the last frame
 * @param webSocketImpl the websocket impl
 * @param frame the frame
 * @throws InvalidDataException if there is a protocol error
 */
private void processFrameIsFin(WebSocketImpl webSocketImpl, Framedata frame) throws InvalidDataException {
	if( current_continuous_frame == null ) {
		log.trace( "Protocol error: Previous continuous frame sequence not completed." );
		throw new InvalidDataException( CloseFrame.PROTOCOL_ERROR, "Continuous frame sequence was not started." );
	}
	addToBufferList(frame.getPayloadData());
	checkBufferLimit();
	if( current_continuous_frame.getOpcode() == Opcode.TEXT ) {
		((FramedataImpl1) current_continuous_frame).setPayload( getPayloadFromByteBufferList() );
		((FramedataImpl1) current_continuous_frame ).isValid();
		try {
			webSocketImpl.getWebSocketListener().onWebsocketMessage( webSocketImpl, Charsetfunctions.stringUtf8( current_continuous_frame.getPayloadData() ) );
		} catch ( RuntimeException e ) {
			log.error( "Runtime exception during onWebsocketMessage", e );
			webSocketImpl.getWebSocketListener().onWebsocketError( webSocketImpl, e );
		}
	} else if( current_continuous_frame.getOpcode() == Opcode.BINARY ) {
		((FramedataImpl1) current_continuous_frame).setPayload( getPayloadFromByteBufferList() );
		((FramedataImpl1) current_continuous_frame ).isValid();
		try {
			webSocketImpl.getWebSocketListener().onWebsocketMessage( webSocketImpl, current_continuous_frame.getPayloadData() );
		} catch ( RuntimeException e ) {
			log.error( "Runtime exception during onWebsocketMessage", e );
			webSocketImpl.getWebSocketListener().onWebsocketError( webSocketImpl, e );
		}
	}
	current_continuous_frame = null;
	clearBufferList();
}

