static void escape(Appendable accum, String string, Document.OutputSettings out,
                   boolean inAttribute, boolean normaliseWhite, boolean stripLeadingWhite) throws IOException {

    boolean lastWasWhite = false;
    boolean reachedNonWhite = false;
    final EscapeMode escapeMode = out.escapeMode();
    final CharsetEncoder encoder = out.encoder();
    final CoreCharset coreCharset = CoreCharset.byName(encoder.charset().name());
    final Map<Character, String> map = escapeMode.getMap();
    final int length = string.length();

    int codePoint;
    for (int offset = 0; offset < length; offset += Character.charCount(codePoint)) {
        codePoint = string.codePointAt(offset);

        if (normaliseWhite) {
            if (StringUtil.isWhitespace(codePoint)) {
                if ((stripLeadingWhite && !reachedNonWhite) || lastWasWhite)
                    continue;
                accum.append(' ');
                lastWasWhite = true;
                continue;
            } else {
                lastWasWhite = false;
                reachedNonWhite = true;
            }
        }
        // surrogate pairs, split implementation for efficiency on single char common case (saves creating strings, char[]):
        if (codePoint < Character.MIN_SUPPLEMENTARY_CODE_POINT) {
            final char c = (char) codePoint;
            // html specific and required escapes:
            switch (c) {
                case '&':
                    accum.append("&amp;");
                    break;
                case 0xA0:
                    if (escapeMode != EscapeMode.xhtml)
                        accum.append("&nbsp;");
                    else
                        accum.append("&#xa0;");
                    break;
                case '<':
                    // escape when in character data or when in a xml attribue val; not needed in html attr val
                    if (!inAttribute || escapeMode == EscapeMode.xhtml)
                        accum.append("&lt;");
                    else
                        accum.append(c);
                    break;
                case '>':
                    if (!inAttribute)
                        accum.append("&gt;");
                    else
                        accum.append(c);
                    break;
                case '"':
                    if (inAttribute)
                        accum.append("&quot;");
                    else
                        accum.append(c);
                    break;
                default:
                    if (canEncode(coreCharset, c, encoder))
                        accum.append(c);
                    else if (map.containsKey(c))
                        accum.append('&').append(map.get(c)).append(';');
                    else
                        accum.append("&#x").append(Integer.toHexString(codePoint)).append(';');
            }
        } else {
            final String c = new String(Character.toChars(codePoint));
            if (encoder.canEncode(c)) // uses fallback encoder for simplicity
                accum.append(c);
            else
                accum.append("&#x").append(Integer.toHexString(codePoint)).append(';');
        }
    }
}

/**
 * Parse out a charset from a content type header. If the charset is not supported, returns null (so the default
 * will kick in.)
 * @param contentType e.g. "text/html; charset=EUC-JP"
 * @return "EUC-JP", or null if not found. Charset is trimmed and uppercased.
 */
static String getCharsetFromContentType(String contentType) {
    if (contentType == null) return null;
    Matcher m = charsetPattern.matcher(contentType);
    if (m.find()) {
        String charset = m.group(1).trim();
        charset = charset.replace("charset=", "");
        if (charset.length() == 0) return null;
        try {
            if (Charset.isSupported(charset)) return charset;
            charset = charset.toUpperCase(Locale.ENGLISH);
            if (Charset.isSupported(charset)) return charset;
        } catch (IllegalCharsetNameException e) {
            // if our advanced charset matching fails.... we just take the default
            return null;
        }
    }
    return null;
}

public void run() {
  try {
    server = ServerSocketChannel.open();
    server.configureBlocking(false);
    server.socket().bind(new java.net.InetSocketAddress(port));

    selector = Selector.open();
    server.register(selector, server.validOps());
  } catch (IOException ex) {
    ex.printStackTrace();
    return;
  }

  while(true) {
    try {
      selector.select();
      Set<SelectionKey> keys = selector.selectedKeys();
      Iterator<SelectionKey> i = keys.iterator();

      while(i.hasNext()) {
        SelectionKey key = i.next();

        // Remove the current key
        i.remove();

        // if isAcceptable == true
        // then a client required a connection
        if (key.isAcceptable()) {
          SocketChannel client = server.accept();
          client.configureBlocking(false);
          WebSocket c = new WebSocket(client, new LinkedBlockingQueue<ByteBuffer>(), this);
          client.register(selector, SelectionKey.OP_READ, c);
        }

        // if isReadable == true
        // then the server is ready to read
        if (key.isReadable()) {
          WebSocket conn = (WebSocket)key.attachment();
          conn.handleRead();
        }

        // if isWritable == true
        // then we need to send the rest of the data to the client
        if (key.isValid() && key.isWritable()) {
          WebSocket conn = (WebSocket)key.attachment();
          if (conn.handleWrite()) {
            conn.socketChannel().register(selector,
                SelectionKey.OP_READ, conn);
          }
        }
      }

      for (WebSocket conn : this.connections) {
        // We have to do this check here, and not in the thread that
        // adds the buffered data to the WebSocket, because the
        // Selector is not thread-safe, and can only be accessed
        // by this thread.
        if (conn.hasBufferedData()) {
          conn.socketChannel().register(selector,
              SelectionKey.OP_READ | SelectionKey.OP_WRITE, conn);
        }
      }
    } catch (IOException ex) {
      ex.printStackTrace();
    } catch (RuntimeException ex) {
      ex.printStackTrace();
    } catch (NoSuchAlgorithmException ex) {
      ex.printStackTrace();
    }
  }

  //System.err.println("WebSocketServer thread ended!");
}

@Override
public void processFrame( WebSocketImpl webSocketImpl, Framedata frame ) throws InvalidDataException {
	Opcode curop = frame.getOpcode();
	if( curop == Opcode.CLOSING ) {
		processFrameClosing(webSocketImpl, frame);
	} else if( curop == Opcode.PING ) {
		webSocketImpl.getWebSocketListener().onWebsocketPing( webSocketImpl, frame );
	} else if( curop == Opcode.PONG ) {
		webSocketImpl.updateLastPong();
		webSocketImpl.getWebSocketListener().onWebsocketPong( webSocketImpl, frame );
	} else if( !frame.isFin() || curop == Opcode.CONTINUOUS ) {
		if( curop != Opcode.CONTINUOUS ) {
			processFrameIsNotFin(frame);
		} else if( frame.isFin() ) {
			processFrameIsFin(webSocketImpl, frame);
		} else if( current_continuous_frame == null ) {
			log.error( "Protocol error: Continuous frame sequence was not started." );
			throw new InvalidDataException( CloseFrame.PROTOCOL_ERROR, "Continuous frame sequence was not started." );
		}
		//Check if the whole payload is valid utf8, when the opcode indicates a text
		if( curop == Opcode.TEXT ) {
			if( !Charsetfunctions.isValidUTF8( frame.getPayloadData() ) ) {
				log.error( "Protocol error: Payload is not UTF8" );
				throw new InvalidDataException( CloseFrame.NO_UTF8 );
			}
		}
		//Checking if the current continuous frame contains a correct payload with the other frames combined
		if( curop == Opcode.CONTINUOUS && current_continuous_frame != null ) {
			byteBufferList.add( frame.getPayloadData() );
		}
	} else if( current_continuous_frame != null ) {
		log.error( "Protocol error: Continuous frame sequence not completed." );
		throw new InvalidDataException( CloseFrame.PROTOCOL_ERROR, "Continuous frame sequence not completed." );
	} else if( curop == Opcode.TEXT ) {
		processFrameText(webSocketImpl, frame);
	} else if( curop == Opcode.BINARY ) {
		processFrameBinary(webSocketImpl, frame);
	} else {
		log.error( "non control or continious frame expected");
		throw new InvalidDataException( CloseFrame.PROTOCOL_ERROR, "non control or continious frame expected" );
	}
}

  /**
   * Should be called when a Selector has a key that is writable for this
   * WebSocket's SocketChannel connection.
   * @throws IOException When socket related I/O errors occur.
   * @throws NoSuchAlgorithmException 
   */
  void handleRead() throws IOException, NoSuchAlgorithmException {

    int bytesRead = -1;

    socketBuffer.rewind();
    bytesRead = this.socketChannel.read(this.socketBuffer);


    if ( bytesRead == -1 )  {
      close();
    } 
    else if( bytesRead > maxpayloadsize ){
    	wsl.onError ( new RuntimeException("recived packet to big") );
    	abort ( "recived packet to big" );
    }
    else if ( bytesRead > 0) {
		if(DEBUG) System.out.println( "got: {" + new String( socketBuffer.array() , 0 , bytesRead ) + "}" );
		if( !handshakeComplete ){
			if(draft.isFlashEdgeCase( socketBuffer.array() , bytesRead )){
				channelWrite( ByteBuffer.wrap( wsl.getFlashPolicy( this ).getBytes( UTF8_CHARSET ) ) );
				return;
			}
			try{
				Handshakedata handshake;
				HandshakeState handshakestate = null;

				if( role == Role.SERVER ){
					if( draft == null ){
						handshake = Draft.translateHandshakeHttp( socketBuffer.array () , bytesRead );
						for( Draft d : known_drafts ){
							handshakestate = d.acceptHandshakeAsServer( handshake );
							if( handshakestate == HandshakeState.MATCHED ){
								HandshakeBuilder response = wsl.onHandshakeRecievedAsServer ( this , d , handshake  );
								channelWrite ( d.createHandshake ( d.postProcessHandshakeResponseAsServer ( handshake , response ) , role ) );
								draft = d;
								this.handshakeComplete = true;
								open();
								return;
							}
							else if ( handshakestate == HandshakeState.MATCHING ){
								if( draft != null ){
									throw new InvalidHandshakeException( "multible drafts matching" );
								}
								draft = d;
							}
						}
						if( draft == null ){
							abort( "no draft matches");
						}
						return;
					}
					else{
						//special case for multiple step handshakes
						handshake = draft.translateHandshake( socketBuffer.array () , bytesRead );
						handshakestate = draft.acceptHandshakeAsServer( handshake );

						if( handshakestate == HandshakeState.MATCHED ){
							open();
						}
						else if ( handshakestate != HandshakeState.MATCHING) {
							abort( "the handshake did finaly not match" );
						}
						return;
					}
				}
				else if( role == Role.CLIENT){
					handshake= draft.translateHandshake( socketBuffer.array () , bytesRead );
					handshakestate = draft.acceptHandshakeAsClient ( handshakerequest , handshake );
					if( handshakestate == HandshakeState.MATCHED ){
						this.handshakeComplete = true;
						open();
					}
					else if ( handshakestate == HandshakeState.MATCHING ) {
						return;
					}
					else{
						abort( "draft "+draft.getClass ().getSimpleName ()+" or server refuses handshake");
					}
				}
			}
			catch (InvalidHandshakeException e) {
				abort( "draft "+draft+" refuses handshake: " + e.getMessage ());
			}
		}
		else{
			//Receiving frames
			List<Framedata> frames = draft.translateFrame ( socketBuffer , bytesRead );
			for( Framedata f : frames){
				Opcode curop = f.getOpcode ();
				if( curop == null )// Ignore undefined opcodes
					continue;
				else if( curop == Opcode.CLOSING){
					sendFrame ( new FramedataImpl1 ( Opcode.CLOSING ) );
					close();
					continue;
				}
				else if( curop == Opcode.PING){
					sendFrame ( new FramedataImpl1 ( Opcode.PONG ) );
					continue;
				}
				else if( curop == Opcode.PONG){
					wsl.onPong ();
					continue;
				}
				if( currentframe == null){
					if( f.isFin () ){
						if( f.getOpcode () == Opcode.TEXT ){
							wsl.onMessage ( this , new String ( f.getPayloadData () , UTF8_CHARSET ) );
						}
						else if( f.getOpcode () == Opcode.BINARY ){
							wsl.onMessage ( this , f.getPayloadData () );
						}
						else{
							if(DEBUG) System.out.println ( "Ignoring frame:" + f.toString() );
						}
					}
					else{
						currentframe = f;
					}
				}
				else if( f.getOpcode() == Opcode.CONTINIOUS ){
					try {
						currentframe.append ( f );
					} catch ( InvalidFrameException e ) {
						wsl.onError ( e );
						abort( "invalid frame: " +e.getMessage () );
					}
					if( f.isFin () ){
						wsl.onMessage ( this , new String ( f.getPayloadData () , UTF8_CHARSET ) );
						currentframe = null;
					}
				}
			}
		}
	}
  }

static ByteBuffer readToByteBuffer(InputStream inStream) throws IOException {
    byte[] buffer = new byte[bufferSize];
    ByteArrayOutputStream outStream = new ByteArrayOutputStream(bufferSize);
    int read;
    while(true) {
        read  = inStream.read(buffer);
        if (read == -1) break;
        outStream.write(buffer, 0, read);
    }
    ByteBuffer byteData = ByteBuffer.wrap(outStream.toByteArray());
    return byteData;
}

