/**
 Get the source ranges (start to end position) in the original input source from which this attribute's <b>name</b>
 and <b>value</b> were parsed.
 <p>Position tracking must be enabled prior to parsing the content.</p>
 @param key the attribute name
 @return the ranges for the attribute's name and value, or {@code untracked} if the attribute does not exist or its range
 was not tracked.
 @see org.jsoup.parser.Parser#setTrackPosition(boolean)
 @see Attribute#sourceRange()
 @see Node#sourceRange()
 @see Element#endSourceRange()
 @since 1.17.1
 */
public Range.AttributeRange sourceRange(String key) {
    if (!hasKey(key)) return UntrackedAttr;
    Map<String, Range.AttributeRange> ranges = getRanges();
    if (ranges == null) return Range.AttributeRange.UntrackedAttr;
    Range.AttributeRange range = ranges.get(key);
    return range != null ? range : Range.AttributeRange.UntrackedAttr;
}

public void run() {
	synchronized ( this ) {
		if( selectorthread != null )
			throw new IllegalStateException( getClass().getName() + " can only be started once." );
		selectorthread = Thread.currentThread();
		if( isclosed.get() ) {
			return;
		}
	}
	selectorthread.setName( "WebSocketSelector-" + selectorthread.getId() );
	try {
		server = ServerSocketChannel.open();
		server.configureBlocking( false );
		ServerSocket socket = server.socket();
		socket.setReceiveBufferSize( WebSocketImpl.RCVBUF );
		socket.setReuseAddress( isReuseAddr() );
		socket.bind( address );
		selector = Selector.open();
		server.register( selector, server.validOps() );
		startConnectionLostTimer();
		onStart();
	} catch ( IOException ex ) {
		handleFatal( null, ex );
		return;
	}
	try {
		int iShutdownCount = 5;
		int selectTimeout = 0;
		while ( !selectorthread.isInterrupted() && iShutdownCount != 0) {
			SelectionKey key = null;
			WebSocketImpl conn = null;
			try {
				if (isclosed.get()) {
					selectTimeout = 5;
				}
				int keyCount = selector.select( selectTimeout );
				if (keyCount == 0 && isclosed.get()) {
					iShutdownCount--;
				}
				Set<SelectionKey> keys = selector.selectedKeys();
				Iterator<SelectionKey> i = keys.iterator();

				while ( i.hasNext() ) {
					key = i.next();
					conn = null;

					if( !key.isValid() ) {
						// Object o = key.attachment();
						continue;
					}

					if( key.isAcceptable() ) {
						if( !onConnect( key ) ) {
							key.cancel();
							continue;
						}

						SocketChannel channel = server.accept();
						if(channel==null){
							continue;
						}
						channel.configureBlocking( false );
						Socket socket = channel.socket();
						socket.setTcpNoDelay( isTcpNoDelay() );
						socket.setKeepAlive( true );
						WebSocketImpl w = wsf.createWebSocket( this, drafts );
						w.setSelectionKey(channel.register( selector, SelectionKey.OP_READ, w ));
						try {
							w.channel = wsf.wrapChannel( channel, w.getSelectionKey() );
							i.remove();
							allocateBuffers( w );
							continue;
						} catch (IOException ex) {
							if( w.getSelectionKey() != null )
								w.getSelectionKey().cancel();

							handleIOException( w.getSelectionKey(), null, ex );
						}
						continue;
					}

					if( key.isReadable() ) {
						conn = (WebSocketImpl) key.attachment();
						ByteBuffer buf = takeBuffer();
						if(conn.channel == null){
							if( key != null )
								key.cancel();

							handleIOException( key, conn, new IOException() );
							continue;
						}
						try {
							if( SocketChannelIOHelper.read( buf, conn, conn.channel ) ) {
								if( buf.hasRemaining() ) {
									conn.inQueue.put( buf );
									queue( conn );
									i.remove();
									if( conn.channel instanceof WrappedByteChannel ) {
										if( ( (WrappedByteChannel) conn.channel ).isNeedRead() ) {
											iqueue.add( conn );
										}
									}
								} else
									pushBuffer( buf );
							} else {
								pushBuffer( buf );
							}
						} catch ( IOException e ) {
							pushBuffer( buf );
							throw e;
						}
					}
					if( key.isWritable() ) {
						conn = (WebSocketImpl) key.attachment();
						if( SocketChannelIOHelper.batch( conn, conn.channel ) ) {
							if( key.isValid() )
								key.interestOps( SelectionKey.OP_READ );
						}
					}
				}
				while ( !iqueue.isEmpty() ) {
					conn = iqueue.remove( 0 );
					WrappedByteChannel c = ( (WrappedByteChannel) conn.channel );
					ByteBuffer buf = takeBuffer();
					try {
						if( SocketChannelIOHelper.readMore( buf, conn, c ) )
							iqueue.add( conn );
						if( buf.hasRemaining() ) {
							conn.inQueue.put( buf );
							queue( conn );
						} else {
							pushBuffer( buf );
						}
					} catch ( IOException e ) {
						pushBuffer( buf );
						throw e;
					}

				}
			} catch ( CancelledKeyException e ) {
				// an other thread may cancel the key
			} catch ( ClosedByInterruptException e ) {
				return; // do the same stuff as when InterruptedException is thrown
			} catch ( IOException ex ) {
				if( key != null )
					key.cancel();
				handleIOException( key, conn, ex );
			} catch ( InterruptedException e ) {
				return;// FIXME controlled shutdown (e.g. take care of buffermanagement)
			}
		}

	} catch ( RuntimeException e ) {
		// should hopefully never occur
		handleFatal( null, e );
	} finally {
		stopConnectionLostTimer();
		if( decoders != null ) {
			for( WebSocketWorker w : decoders ) {
				w.interrupt();
			}
		}
		if( selector != null ) {
			try {
				selector.close();
			} catch ( IOException e ) {
				log.error( "IOException during selector.close", e );
				onError( null, e );
			}
		}
		if( server != null ) {
			try {
				server.close();
			} catch ( IOException e ) {
				log.error( "IOException during server.close", e );
				onError( null, e );
			}
		}
	}
}

/**
 * Process the frame if it is the last frame
 * @param webSocketImpl the websocket impl
 * @param frame the frame
 * @throws InvalidDataException if there is a protocol error
 */
private void processFrameIsFin(WebSocketImpl webSocketImpl, Framedata frame) throws InvalidDataException {
	if( current_continuous_frame == null ) {
		log.trace( "Protocol error: Previous continuous frame sequence not completed." );
		throw new InvalidDataException( CloseFrame.PROTOCOL_ERROR, "Continuous frame sequence was not started." );
	}
	addToBufferList(frame.getPayloadData());
	checkBufferLimit();
	if( current_continuous_frame.getOpcode() == Opcode.TEXT ) {
		((FramedataImpl1) current_continuous_frame).setPayload( getPayloadFromByteBufferList() );
		((FramedataImpl1) current_continuous_frame ).isValid();
		try {
			webSocketImpl.getWebSocketListener().onWebsocketMessage( webSocketImpl, Charsetfunctions.stringUtf8( current_continuous_frame.getPayloadData() ) );
		} catch ( RuntimeException e ) {
			log.error( "Runtime exception during onWebsocketMessage", e );
			webSocketImpl.getWebSocketListener().onWebsocketError( webSocketImpl, e );
		}
	} else if( current_continuous_frame.getOpcode() == Opcode.BINARY ) {
		((FramedataImpl1) current_continuous_frame).setPayload( getPayloadFromByteBufferList() );
		((FramedataImpl1) current_continuous_frame ).isValid();
		try {
			webSocketImpl.getWebSocketListener().onWebsocketMessage( webSocketImpl, current_continuous_frame.getPayloadData() );
		} catch ( RuntimeException e ) {
			log.error( "Runtime exception during onWebsocketMessage", e );
			webSocketImpl.getWebSocketListener().onWebsocketError( webSocketImpl, e );
		}
	}
	current_continuous_frame = null;
	clearBufferList();
}

public void run() {
  running = tryToConnect(new InetSocketAddress(uri.getHost(), getPort()));

  while (this.running) {
    try {
      selector.select();
      Set<SelectionKey> keys = selector.selectedKeys();
      Iterator<SelectionKey> i = keys.iterator();

      while (i.hasNext()) {
        SelectionKey key = i.next();
        i.remove();

        if (key.isConnectable()) {
          finishConnect();
        }

        if (key.isReadable()) {
          conn.handleRead();
        }
      }
    } catch (IOException ex) {
  	  onIOError(ex);
    } catch (NoSuchAlgorithmException ex) {
      ex.printStackTrace();
    }
  }

  //System.err.println("WebSocketClient thread ended!");
}

public static Handshakedata translateHandshake( byte[] buffer, int readcount ){
	HandshakedataImpl1 draft = new HandshakedataImpl1();

	ByteBuffer message = ByteBuffer.allocate ( readcount );
	message.put ( buffer , 0 , readcount );
	byte[] lines = message.array ();
	int previndex = 0;
	int index = findNewLine ( lines , previndex );
	if ( index == lines.length )
		return null;
	String line = new String ( lines , previndex , index - previndex );
	String[] firstLineTokens = line.split(" ");
	String path = firstLineTokens[1];
	draft.setResourceDescriptor( path );
	//TODO Care about resources here like: GET /chat HTTP/1.1 
	//if ( line.startsWith ( "GET" ) == false ) 
	//if ( line.startsWith ( "HTTP" ) == false ) 

	previndex = index + 2;
	index = findNewLine ( lines , previndex );
	int length = index - previndex;
	while ( length != 0 ) {
		line = new String ( lines , previndex , length );
		if ( index != previndex ) {
			String[] pair = line.split ( ":" , 2 );
			if ( pair.length != 2 )
				return null;
			draft.put ( pair[ 0 ] , pair[ 1 ].replaceFirst( "^ +" , "" ) );
		}
		previndex = index + 2;
		index = findNewLine ( lines , previndex );
		length = index - previndex;
	}
	previndex = index + 2;
	length = lines.length - previndex;
	draft.setContent ( ByteBuffer.allocate ( length ).put ( lines, previndex , length ).array () );
	return draft;
}

public int read( ByteBuffer dst ) throws IOException {
	if( !isHandShakeComplete() ) {
		processHandshake();
		return 0;
	}
	int amount = 0, limit;
	// test if there was a buffer overflow in dst
	if( inData.hasRemaining() ) {
		return transfereTo( inData, dst );
	}
	// test if some bytes left from last read (e.g. BUFFER_UNDERFLOW)
	if( inCrypt.hasRemaining() ) {
		unwrap();
		amount += transfereTo( inData, dst );
	}
	if( !inCrypt.hasRemaining() )
		inCrypt.clear();
	else
		inCrypt.compact();

	if( sc.read( inCrypt ) == -1 ) {
		return -1;
	}
	inCrypt.flip();
	unwrap();
	amount += transfereTo( inData, dst );
	return amount;

}

public void head(org.jsoup.nodes.Node source, int depth) {
    namespacesStack.push(new HashMap<>(namespacesStack.peek())); // inherit from above on the stack
    if (source instanceof org.jsoup.nodes.Element) {
        org.jsoup.nodes.Element sourceEl = (org.jsoup.nodes.Element) source;

        String prefix = updateNamespaces(sourceEl);
        String namespace = namespacesStack.peek().get(prefix);
        String tagName = sourceEl.tagName();

        /* Tag names in XML are quite permissive, but less permissive than HTML. Rather than reimplement the validation,
        we just try to use it as-is. If it fails, insert as a text node instead. We don't try to normalize the
        tagname to something safe, because that isn't going to be meaningful downstream. This seems(?) to be
        how browsers handle the situation, also. https://github.com/jhy/jsoup/issues/1093 */
        try {
            Element el = namespace == null && tagName.contains(":") ?
                doc.createElementNS("", tagName) : // doesn't have a real namespace defined
                doc.createElementNS(namespace, tagName);
            copyAttributes(sourceEl, el);
            append(el, sourceEl);
            dest = el; // descend
        } catch (DOMException e) {
            append(doc.createTextNode("<" + tagName + ">"), sourceEl);
        }
    } else if (source instanceof org.jsoup.nodes.TextNode) {
        org.jsoup.nodes.TextNode sourceText = (org.jsoup.nodes.TextNode) source;
        Text text = doc.createTextNode(sourceText.getWholeText());
        append(text, sourceText);
    } else if (source instanceof org.jsoup.nodes.Comment) {
        org.jsoup.nodes.Comment sourceComment = (org.jsoup.nodes.Comment) source;
        Comment comment = doc.createComment(sourceComment.getData());
        append(comment, sourceComment);
    } else if (source instanceof org.jsoup.nodes.DataNode) {
        org.jsoup.nodes.DataNode sourceData = (org.jsoup.nodes.DataNode) source;
        Text node = doc.createTextNode(sourceData.getWholeData());
        append(node, sourceData);
    } else {
        // unhandled. note that doctype is not handled here - rather it is used in the initial doc creation
    }
}

