/**
 * This will close the connection immediately without a proper close handshake.
 * The code and the message therefore won't be transfered over the wire also they will be forwarded to onClose/onWebsocketClose.
 *
 * @param code    the closing code
 * @param message the closing message
 * @param remote  Indicates who "generated" <code>code</code>.<br>
 *                <code>true</code> means that this endpoint received the <code>code</code> from the other endpoint.<br>
 *                false means this endpoint decided to send the given code,<br>
 *                <code>remote</code> may also be true if this endpoint started the closing handshake since the other endpoint may not simply echo the <code>code</code> but close the connection the same time this endpoint does do but with an other <code>code</code>. <br>
 **/
public synchronized void closeConnection( int code, String message, boolean remote ) {
	if( readystate == READYSTATE.CLOSED ) {
		return;
	}

	if( key != null ) {
		// key.attach( null ); //see issue #114
		key.cancel();
	}
	if( channel != null ) {
		try {
			channel.close();
		} catch ( IOException e ) {
			if( e.getMessage().equals( "Broken pipe" ) ) {
				if( WebSocketImpl.DEBUG ) {
					System.out.println( "Caught IOException: Broken pipe during closeConnection()" );
				}
			} else {
				wsl.onWebsocketError( this, e );
			}
		}
	}
	try {
		this.wsl.onWebsocketClose( this, code, message, remote );
	} catch ( RuntimeException e ) {
		wsl.onWebsocketError( this, e );
	}
	if( draft != null )
		draft.reset();
	handshakerequest = null;

	readystate = READYSTATE.CLOSED;
	this.outQueue.clear();
}

public void run() {
	if( thread != null )
		throw new IllegalStateException( "This instance of " + getClass().getSimpleName() + " can only be started once the same time." );
	thread = Thread.currentThread();
	try {
		server = ServerSocketChannel.open();
		server.configureBlocking( false );
		server.socket().bind( address );
		//InetAddress.getLocalHost()
		selector = Selector.open();
		server.register( selector, server.validOps() );
	} catch ( IOException ex ) {
		onError( null, ex );
		return;
	}

	while ( !thread.isInterrupted() ) {
		SelectionKey key = null;
		WebSocket conn = null;
		try {
			selector.select();
			Set<SelectionKey> keys = selector.selectedKeys();
			Iterator<SelectionKey> i = keys.iterator();

			while ( i.hasNext() ) {
				key = i.next();

				// Remove the current key
				i.remove();

				// if isAcceptable == true
				// then a client required a connection
				if( key.isAcceptable() ) {
					SocketChannel client = server.accept();
					client.configureBlocking( false );
					WebSocket c = new WebSocket( this, Collections.singletonList( draft ), client.socket().getChannel() );
					client.register( selector, SelectionKey.OP_READ, c );
				}

				// if isReadable == true
				// then the server is ready to read
				if( key.isReadable() ) {
					conn = (WebSocket) key.attachment();
					conn.handleRead();
				}

				// if isWritable == true
				// then we need to send the rest of the data to the client
				if( key.isValid() && key.isWritable() ) {
					conn = (WebSocket) key.attachment();
					conn.flush();
					key.channel().register( selector, SelectionKey.OP_READ, conn );
				}
			}
			Iterator<WebSocket> it = this.connections.iterator();
			while ( it.hasNext() ) {
				// We have to do this check here, and not in the thread that
				// adds the buffered data to the WebSocket, because the
				// Selector is not thread-safe, and can only be accessed
				// by this thread.
				conn = it.next();
				if( conn.hasBufferedData() ) {
					conn.flush();
					// key.channel().register( selector, SelectionKey.OP_READ | SelectionKey.OP_WRITE, conn );
				}
			}
		} catch ( IOException ex ) {
			if( key != null )
				key.cancel();
			onError( conn, ex );// conn may be null here
			if( conn != null ) {
				conn.close( CloseFrame.ABNROMAL_CLOSE );
			}
		}
	}
}

@Override
void outerHtmlHead(StringBuilder accum, int depth, Document.OutputSettings out) {
    if (out.syntax() == Syntax.html && !has(PUBLIC_ID) && !has(SYSTEM_ID)) {
        // looks like a html5 doctype, go lowercase for aesthetics
        accum.append("<!doctype");
    } else {
        accum.append("<!DOCTYPE");
    }
    if (has(NAME))
        accum.append(" ").append(attr(NAME));
    if (has(PUBLIC_ID))
        accum.append(" PUBLIC \"").append(attr(PUBLIC_ID)).append('"');
    if (has(SYSTEM_ID))
        accum.append(" \"").append(attr(SYSTEM_ID)).append('"');
    accum.append('>');
}

/**
 * Private method to cache all the frames to improve memory footprint and conversion time
 * @param data the data to broadcast
 * @param clients the clients to send the message to
 */
private void doBroadcast(Object data, Collection<WebSocket> clients) {
	String sData = null;
	if (data instanceof String) {
		sData = (String)data;
	}
	ByteBuffer bData = null;
	if (data instanceof ByteBuffer) {
		bData = (ByteBuffer)data;
	}
	if (sData == null && bData == null) {
		return;
	}
	Map<Draft, List<Framedata>> draftFrames = new HashMap<Draft, List<Framedata>>();
	for( WebSocket client : clients ) {
		if( client != null ) {
			Draft draft = client.getDraft();
			fillFrames(draft, draftFrames, sData, bData);
			try {
				client.sendFrame( draftFrames.get( draft ) );
			} catch ( WebsocketNotConnectedException e ) {
				//Ignore this exception in this case
			}
		}
	}
}

private synchronized ByteBuffer unwrap() throws SSLException {
	inData.compact();
	while ( inCrypt.hasRemaining() ) {
		res = sslEngine.unwrap( inCrypt, inData );
		if( res.getHandshakeStatus() == SSLEngineResult.HandshakeStatus.NEED_TASK ) {
			Runnable task;
			while ( ( task = sslEngine.getDelegatedTask() ) != null ) {
				task.run();
			}
		} else if( res.getHandshakeStatus() == SSLEngineResult.HandshakeStatus.FINISHED ) {
			break;
		} else if( res.getStatus() == SSLEngineResult.Status.BUFFER_UNDERFLOW ) {
			break;
		} else if( res.getStatus() == SSLEngineResult.Status.BUFFER_OVERFLOW ) {
			throw new RuntimeException( "destenation buffer to small" );
		}
	}
	inData.flip();
	return inData;
}

