/**
 * Should be called when a Selector has a key that is writable for this
 * WebSocketImpl's SocketChannel connection.
 * 
 * @throws IOException
 *             When socket related I/O errors occur.
 * @throws InterruptedException
 */
public void decode( ByteBuffer socketBuffer ) throws IOException {
	if( !socketBuffer.hasRemaining() )
		return;
	if( DEBUG )
		System.out.println( "process(" + socketBuffer.remaining() + "): {" + ( socketBuffer.remaining() > 1000 ? "too big to display" : new String( socketBuffer.array(), socketBuffer.position(), socketBuffer.remaining() ) ) + "}" );

	if( handshakeComplete ) {
		decodeFrames( socketBuffer );
	} else {
		if( decodeHandshake( socketBuffer ) ) {
			decodeFrames( socketBuffer );
		}
	}
	assert ( isClosing() || isClosed() || !socketBuffer.hasRemaining() );
}

static Document parseInputStream(@Nullable InputStream input, @Nullable String charsetName, String baseUri, Parser parser) throws IOException  {
    if (input == null) // empty body
        return new Document(baseUri);

    @Nullable Document doc = null;

    // read the start of the stream and look for a BOM or meta charset
    try (InputStream wrappedInputStream = ControllableInputStream.wrap(input, DefaultBufferSize, 0)) {
        wrappedInputStream.mark(DefaultBufferSize);
        ByteBuffer firstBytes = readToByteBuffer(wrappedInputStream, firstReadBufferSize - 1); // -1 because we read one more to see if completed. First read is < buffer size, so can't be invalid.
        boolean fullyRead = (wrappedInputStream.read() == -1);
        wrappedInputStream.reset();

        // look for BOM - overrides any other header or input
        BomCharset bomCharset = detectCharsetFromBom(firstBytes);
        if (bomCharset != null)
            charsetName = bomCharset.charset;

        if (charsetName == null) { // determine from meta. safe first parse as UTF-8
            try {
                CharBuffer defaultDecoded = UTF_8.decode(firstBytes);
                if (defaultDecoded.hasArray())
                    doc = parser.parseInput(new CharArrayReader(defaultDecoded.array(), defaultDecoded.arrayOffset(), defaultDecoded.limit()), baseUri);
                else
                    doc = parser.parseInput(defaultDecoded.toString(), baseUri);
            } catch (UncheckedIOException e) {
                throw e.getCause();
            }

            // look for <meta http-equiv="Content-Type" content="text/html;charset=gb2312"> or HTML5 <meta charset="gb2312">
            Elements metaElements = doc.select("meta[http-equiv=content-type], meta[charset]");
            String foundCharset = null; // if not found, will keep utf-8 as best attempt
            for (Element meta : metaElements) {
                if (meta.hasAttr("http-equiv"))
                    foundCharset = getCharsetFromContentType(meta.attr("content"));
                if (foundCharset == null && meta.hasAttr("charset"))
                    foundCharset = meta.attr("charset");
                if (foundCharset != null)
                    break;
            }

            // look for <?xml encoding='ISO-8859-1'?>
            if (foundCharset == null && doc.childNodeSize() > 0) {
                Node first = doc.childNode(0);
                XmlDeclaration decl = null;
                if (first instanceof XmlDeclaration)
                    decl = (XmlDeclaration) first;
                else if (first instanceof Comment) {
                    Comment comment = (Comment) first;
                    if (comment.isXmlDeclaration())
                        decl = comment.asXmlDeclaration();
                }
                if (decl != null && decl.name().equalsIgnoreCase("xml")) {
                    foundCharset = decl.attr("encoding");
                }
            }
            foundCharset = validateCharset(foundCharset);
            if (foundCharset != null && !foundCharset.equalsIgnoreCase(defaultCharsetName)) { // need to re-decode. (case insensitive check here to match how validate works)
                foundCharset = foundCharset.trim().replaceAll("[\"']", "");
                charsetName = foundCharset;
                doc = null;
            } else if (!fullyRead) {
                doc = null;
            }
        } else { // specified by content type header (or by user on file load)
            Validate.notEmpty(charsetName, "Must set charset arg to character set of file to parse. Set to null to attempt to detect from HTML");
        }
        if (doc == null) {
            if (charsetName == null)
                charsetName = defaultCharsetName;
            try (BufferedReader reader = new BufferedReader(new InputStreamReader(wrappedInputStream, Charset.forName(charsetName)), DefaultBufferSize)) {
                if (bomCharset != null && bomCharset.offset) { // creating the buffered reader ignores the input pos, so must skip here
                    long skipped = reader.skip(1);
                    Validate.isTrue(skipped == 1); // WTF if this fails.
                }
                try {
                    doc = parser.parseInput(reader, baseUri);
                } catch (UncheckedIOException e) {
                    // io exception when parsing (not seen before because reading the stream as we go)
                    throw e.getCause();
                }
                Charset charset = charsetName.equals(defaultCharsetName) ? UTF_8 : Charset.forName(charsetName);
                doc.outputSettings().charset(charset);
                if (!charset.canEncode()) {
                    // some charsets can read but not encode; switch to an encodable charset and update the meta el
                    doc.charset(UTF_8);
                }
            }
        }
    }
    return doc;
}

public void run() {

	try {
		boolean isNewSocket = false;

		if( socket == null ) {
			socket = new Socket( proxy );
			isNewSocket = true;

		} else if( socket.isClosed() ) {
			throw new IOException();
		}

		socket.setTcpNoDelay( isTcpNoDelay() );
		socket.setReuseAddress( isReuseAddr() );

		if( !socket.isBound() ) {
			socket.connect( new InetSocketAddress( uri.getHost(), getPort() ), connectTimeout );
		}

		// if the socket is set by others we don't apply any TLS wrapper
		if (isNewSocket && uri.getScheme().equals("wss")) {

			SSLContext sslContext = SSLContext.getInstance("TLS");
			sslContext.init(null, null, null);
			SSLSocketFactory factory = sslContext.getSocketFactory();
			socket = factory.createSocket(socket, uri.getHost(), getPort(), true);
		}

		istream = socket.getInputStream();
		ostream = socket.getOutputStream();

		sendHandshake();
	} catch ( /*IOException | SecurityException | UnresolvedAddressException | InvalidHandshakeException | ClosedByInterruptException | SocketTimeoutException */Exception e ) {
		onWebsocketError( engine, e );
		engine.closeConnection( CloseFrame.NEVER_CONNECTED, e.getMessage() );
		return;
	}

	writeThread = new Thread( new WebsocketWriteThread() );
	writeThread.start();

	byte[] rawbuffer = new byte[ WebSocketImpl.RCVBUF ];
	int readBytes;

	try {
		while ( !isClosing() && !isClosed() && ( readBytes = istream.read( rawbuffer ) ) != -1 ) {
			engine.decode( ByteBuffer.wrap( rawbuffer, 0, readBytes ) );
		}
		engine.eot();
	} catch ( IOException e ) {
		handleIOException(e);
	} catch ( RuntimeException e ) {
		// this catch case covers internal errors only and indicates a bug in this websocket implementation
		onError( e );
		engine.closeConnection( CloseFrame.ABNORMAL_CLOSE, e.getMessage() );
	}
	assert ( socket.isClosed() );
}

static Document parseByteData(ByteBuffer byteData, String charsetName, String baseUri, Parser parser) {
    String docData;
    Document doc = null;

    // look for BOM - overrides any other header or input
    byteData.mark();
    byte[] bom = new byte[4];
    if (byteData.remaining() >= bom.length) {
        byteData.get(bom);
        byteData.rewind();
    }
    if (bom[0] == 0x00 && bom[1] == 0x00 && bom[2] == (byte) 0xFE && bom[3] == (byte) 0xFF || // BE
            bom[0] == (byte) 0xFF && bom[1] == (byte) 0xFE && bom[2] == 0x00 && bom[3] == 0x00) { // LE
        charsetName = "UTF-32"; // and I hope it's on your system
    } else if (bom[0] == (byte) 0xFE && bom[1] == (byte) 0xFF || // BE
            bom[0] == (byte) 0xFF && bom[1] == (byte) 0xFE) {
        charsetName = "UTF-16"; // in all Javas
    } else if (bom[0] == (byte) 0xEF && bom[1] == (byte) 0xBB && bom[2] == (byte) 0xBF) {
        charsetName = "UTF-8"; // in all Javas
        byteData.position(3); // 16 and 32 decoders consume the BOM to determine be/le; utf-8 should be consumed
    }

    if (charsetName == null) { // determine from meta. safe parse as UTF-8
        // look for <meta http-equiv="Content-Type" content="text/html;charset=gb2312"> or HTML5 <meta charset="gb2312">
        docData = Charset.forName(defaultCharset).decode(byteData).toString();
        doc = parser.parseInput(docData, baseUri);
        Element meta = doc.select("meta[http-equiv=content-type], meta[charset]").first();
        if (meta != null) { // if not found, will keep utf-8 as best attempt
            String foundCharset = null;
            if (meta.hasAttr("http-equiv")) {
                foundCharset = getCharsetFromContentType(meta.attr("content"));
            }
            if (foundCharset == null && meta.hasAttr("charset")) {
                try {
                    if (Charset.isSupported(meta.attr("charset"))) {
                        foundCharset = meta.attr("charset");
                    }
                } catch (IllegalCharsetNameException e) {
                    foundCharset = null;
                }
            }

            if (foundCharset != null && foundCharset.length() != 0 && !foundCharset.equals(defaultCharset)) { // need to re-decode
                foundCharset = foundCharset.trim().replaceAll("[\"']", "");
                charsetName = foundCharset;
                byteData.rewind();
                docData = Charset.forName(foundCharset).decode(byteData).toString();
                doc = null;
            }
        }
    } else { // specified by content type header (or by user on file load)
        Validate.notEmpty(charsetName, "Must set charset arg to character set of file to parse. Set to null to attempt to detect from HTML");
        docData = Charset.forName(charsetName).decode(byteData).toString();
    }
    if (doc == null) {
        doc = parser.parseInput(docData, baseUri);
        doc.outputSettings().charset(charsetName);
    }
    return doc;
}

@Override
public void processFrame( WebSocketImpl webSocketImpl, Framedata frame ) throws InvalidDataException {
	Opcode curop = frame.getOpcode();
	if( curop == Opcode.CLOSING ) {
		int code = CloseFrame.NOCODE;
		String reason = "";
		if( frame instanceof CloseFrame ) {
			CloseFrame cf = ( CloseFrame ) frame;
			code = cf.getCloseCode();
			reason = cf.getMessage();
		}
		if( webSocketImpl.getReadyState() == ReadyState.CLOSING ) {
			// complete the close handshake by disconnecting
			webSocketImpl.closeConnection( code, reason, true );
		} else {
			// echo close handshake
			if( getCloseHandshakeType() == CloseHandshakeType.TWOWAY )
				webSocketImpl.close( code, reason, true );
			else
				webSocketImpl.flushAndClose( code, reason, false );
		}
	} else if( curop == Opcode.PING ) {
		webSocketImpl.getWebSocketListener().onWebsocketPing( webSocketImpl, frame );
	} else if( curop == Opcode.PONG ) {
		webSocketImpl.updateLastPong();
		webSocketImpl.getWebSocketListener().onWebsocketPong( webSocketImpl, frame );
	} else if( !frame.isFin() || curop == Opcode.CONTINUOUS ) {
		if( curop != Opcode.CONTINUOUS ) {
			if( current_continuous_frame != null ) {
				log.trace( "Protocol error: Previous continuous frame sequence not completed." );
				throw new InvalidDataException( CloseFrame.PROTOCOL_ERROR, "Previous continuous frame sequence not completed." );
			}
			current_continuous_frame = frame;
			byteBufferList.add( frame.getPayloadData() );
		} else if( frame.isFin() ) {
			if( current_continuous_frame == null ) {
				log.trace( "Protocol error: Previous continuous frame sequence not completed." );
				throw new InvalidDataException( CloseFrame.PROTOCOL_ERROR, "Continuous frame sequence was not started." );
			}
			byteBufferList.add( frame.getPayloadData() );
			if( current_continuous_frame.getOpcode() == Opcode.TEXT ) {
				((FramedataImpl1) current_continuous_frame).setPayload( getPayloadFromByteBufferList() );
				((FramedataImpl1) current_continuous_frame ).isValid();
				try {
					webSocketImpl.getWebSocketListener().onWebsocketMessage( webSocketImpl, Charsetfunctions.stringUtf8( current_continuous_frame.getPayloadData() ) );
				} catch ( RuntimeException e ) {
					log.error( "Runtime exception during onWebsocketMessage", e );
					webSocketImpl.getWebSocketListener().onWebsocketError( webSocketImpl, e );
				}
			} else if( current_continuous_frame.getOpcode() == Opcode.BINARY ) {
				((FramedataImpl1) current_continuous_frame).setPayload( getPayloadFromByteBufferList() );
				((FramedataImpl1) current_continuous_frame ).isValid();
				try {
					webSocketImpl.getWebSocketListener().onWebsocketMessage( webSocketImpl, current_continuous_frame.getPayloadData() );
				} catch ( RuntimeException e ) {
					log.error( "Runtime exception during onWebsocketMessage", e );
					webSocketImpl.getWebSocketListener().onWebsocketError( webSocketImpl, e );
				}
			}
			current_continuous_frame = null;
			byteBufferList.clear();
		} else if( current_continuous_frame == null ) {
			log.error( "Protocol error: Continuous frame sequence was not started." );
			throw new InvalidDataException( CloseFrame.PROTOCOL_ERROR, "Continuous frame sequence was not started." );
		}
		//Check if the whole payload is valid utf8, when the opcode indicates a text
		if( curop == Opcode.TEXT ) {
			if( !Charsetfunctions.isValidUTF8( frame.getPayloadData() ) ) {
				log.error( "Protocol error: Payload is not UTF8" );
				throw new InvalidDataException( CloseFrame.NO_UTF8 );
			}
		}
		//Checking if the current continuous frame contains a correct payload with the other frames combined
		if( curop == Opcode.CONTINUOUS && current_continuous_frame != null ) {
			byteBufferList.add( frame.getPayloadData() );
		}
	} else if( current_continuous_frame != null ) {
		log.error( "Protocol error: Continuous frame sequence not completed." );
		throw new InvalidDataException( CloseFrame.PROTOCOL_ERROR, "Continuous frame sequence not completed." );
	} else if( curop == Opcode.TEXT ) {
		try {
			webSocketImpl.getWebSocketListener().onWebsocketMessage( webSocketImpl, Charsetfunctions.stringUtf8( frame.getPayloadData() ) );
		} catch ( RuntimeException e ) {
			log.error( "Runtime exception during onWebsocketMessage", e );
			webSocketImpl.getWebSocketListener().onWebsocketError( webSocketImpl, e );
		}
	} else if( curop == Opcode.BINARY ) {
		try {
			webSocketImpl.getWebSocketListener().onWebsocketMessage( webSocketImpl, frame.getPayloadData() );
		} catch ( RuntimeException e ) {
			log.error( "Runtime exception during onWebsocketMessage", e );
			webSocketImpl.getWebSocketListener().onWebsocketError( webSocketImpl, e );
		}
	} else {
		log.error( "non control or continious frame expected");
		throw new InvalidDataException( CloseFrame.PROTOCOL_ERROR, "non control or continious frame expected" );
	}
}

