private Framedata translateSingleFrame( ByteBuffer buffer ) throws IncompleteException, InvalidDataException {
	if (buffer == null)
		throw new IllegalArgumentException();
	int maxpacketsize = buffer.remaining();
	int realpacketsize = 2;
	translateSingleFrameCheckPacketSize(maxpacketsize, realpacketsize);
	byte b1 = buffer.get( /*0*/ );
	boolean fin = b1 >> 8 != 0;
	boolean rsv1 = ( b1 & 0x40 ) != 0;
	boolean rsv2 = ( b1 & 0x20 ) != 0;
	boolean rsv3 = ( b1 & 0x10 ) != 0;
	byte b2 = buffer.get( /*1*/ );
	boolean mask = ( b2 & -128 ) != 0;
	int payloadlength = ( byte ) ( b2 & ~( byte ) 128 );
	Opcode optcode = toOpcode( ( byte ) ( b1 & 15 ) );

	if( !( payloadlength >= 0 && payloadlength <= 125 ) ) {

		if( optcode == Opcode.PING || optcode == Opcode.PONG || optcode == Opcode.CLOSING ) {
			log.trace( "Invalid frame: more than 125 octets" );
			throw new InvalidFrameException( "more than 125 octets" );
		}
		if( payloadlength == 126 ) {
			realpacketsize += 2; // additional length bytes
			translateSingleFrameCheckPacketSize(maxpacketsize, realpacketsize);
			byte[] sizebytes = new byte[3];
			sizebytes[1] = buffer.get( /*1 + 1*/ );
			sizebytes[2] = buffer.get( /*1 + 2*/ );
			payloadlength = new BigInteger( sizebytes ).intValue();
		} else {
			realpacketsize += 8; // additional length bytes
			translateSingleFrameCheckPacketSize(maxpacketsize, realpacketsize);
			byte[] bytes = new byte[8];
			for( int i = 0; i < 8; i++ ) {
				bytes[i] = buffer.get( /*1 + i*/ );
			}
			long length = new BigInteger( bytes ).longValue();
			translateSingleFrameCheckLengthLimit(length);
			payloadlength = ( int ) length;
		}
	}
	realpacketsize += ( mask ? 4 : 0 );
	realpacketsize += payloadlength;
	translateSingleFrameCheckPacketSize(maxpacketsize, realpacketsize);

	ByteBuffer payload = ByteBuffer.allocate( checkAlloc( payloadlength ) );
	if( mask ) {
		byte[] maskskey = new byte[4];
		buffer.get( maskskey );
		for( int i = 0; i < payloadlength; i++ ) {
			payload.put( ( byte ) ( buffer.get( /*payloadstart + i*/ ) ^ maskskey[i % 4] ) );
		}
	} else {
		payload.put( buffer.array(), buffer.position(), payload.limit() );
		buffer.position( buffer.position() + payload.limit() );
	}

	FramedataImpl1 frame = FramedataImpl1.get( optcode );
	frame.setFin( fin );
	frame.setRSV1( rsv1 );
	frame.setRSV2( rsv2 );
	frame.setRSV3( rsv3 );
	payload.flip();
	frame.setPayload( payload );
	getExtension().isFrameValid(frame);
	getExtension().decodeFrame(frame);
	if (log.isTraceEnabled())
		log.trace( "afterDecoding({}): {}", frame.getPayloadData().remaining(), ( frame.getPayloadData().remaining() > 1000 ? "too big to display" : new String( frame.getPayloadData().array() ) ) );
	frame.isValid();
	return frame;
}

/**
 * Get the (unencoded) text of all children of this element, including any newlines and spaces present in the
 * original.
 *
 * @return unencoded, un-normalized text
 * @see #text()
 */
public String wholeText() {
    final StringBuilder accum = StringUtil.borrowBuilder();
    NodeTraversor.traverse(new NodeVisitor() {
        public void head(Node node, int depth) {
            appendWholeText(node, accum);
        }

        public void tail(Node node, int depth) {}
    }, this);

    return StringUtil.releaseBuilder(accum);
}

public void run() {
  try {
    server = ServerSocketChannel.open();
    server.configureBlocking(false);
    server.socket().bind(new java.net.InetSocketAddress(port));

    selector = Selector.open();
    server.register(selector, server.validOps());
  } catch (IOException ex) {
  	onIOError(ex);
    return;
  }

  while(true) {
    try {
      selector.select();
      Set<SelectionKey> keys = selector.selectedKeys();
      Iterator<SelectionKey> i = keys.iterator();

      while(i.hasNext()) {
        SelectionKey key = i.next();

        // Remove the current key
        i.remove();

        // if isAcceptable == true
        // then a client required a connection
        if (key.isAcceptable()) {
          SocketChannel client = server.accept();
          client.configureBlocking(false);
          WebSocket c = new WebSocket(client, new LinkedBlockingQueue<ByteBuffer>(), this);
          client.register(selector, SelectionKey.OP_READ, c);
        }

        // if isReadable == true
        // then the server is ready to read
        if (key.isReadable()) {
          WebSocket conn = (WebSocket)key.attachment();
          conn.handleRead();
        }

        // if isWritable == true
        // then we need to send the rest of the data to the client
        if (key.isValid() && key.isWritable()) {
          WebSocket conn = (WebSocket)key.attachment();
          if (conn.handleWrite()) {
            conn.socketChannel().register(selector,
                SelectionKey.OP_READ, conn);
          }
        }
      }

      for (WebSocket conn : this.connections) {
        // We have to do this check here, and not in the thread that
        // adds the buffered data to the WebSocket, because the
        // Selector is not thread-safe, and can only be accessed
        // by this thread.
        if (conn.hasBufferedData()) {
          conn.socketChannel().register(selector,
              SelectionKey.OP_READ | SelectionKey.OP_WRITE, conn);
        }
      }
    } catch (IOException ex) {
  	  onIOError(ex);
    } catch (RuntimeException ex) {
      ex.printStackTrace();
    } catch (NoSuchAlgorithmException ex) {
      ex.printStackTrace();
    }
  }

  //System.err.println("WebSocketServer thread ended!");
}

