public static HandshakeBuilder translateHandshakeHttp( ByteBuffer buf, Role role ) throws InvalidHandshakeException , IncompleteHandshakeException {
	HandshakeBuilder handshake;

	String line = readStringLine( buf );
	if( line == null )
		throw new IncompleteHandshakeException( buf.capacity() + 128 );

	String[] firstLineTokens = line.split( " ", 3 );// eg. HTTP/1.1 101 Switching the Protocols
	if( firstLineTokens.length != 3 ) {
		throw new InvalidHandshakeException();
	}

	if( role == Role.CLIENT ) {
		// translating/parsing the response from the SERVER
		if (!"101".equals(firstLineTokens[1])) {
			throw new InvalidHandshakeException( "Invalid status code received: " + firstLineTokens[1] + " Status line: " + line);
		}
		if (!"HTTP/1.1".equalsIgnoreCase(firstLineTokens[0])) {
			throw new InvalidHandshakeException( "Invalid status line received: " + firstLineTokens[0] + " Status line: " + line);
		}

		handshake = new HandshakeImpl1Server();
		ServerHandshakeBuilder serverhandshake = (ServerHandshakeBuilder) handshake;
		serverhandshake.setHttpStatus( Short.parseShort( firstLineTokens[ 1 ] ) );
		serverhandshake.setHttpStatusMessage( firstLineTokens[ 2 ] );
	} else {
		// translating/parsing the request from the CLIENT
		if (!"GET".equalsIgnoreCase(firstLineTokens[0])) {
			throw new InvalidHandshakeException( "Invalid request method received: " + firstLineTokens[0] + " Status line: " + line);
		}
		if (!"HTTP/1.1".equalsIgnoreCase(firstLineTokens[2])) {
			throw new InvalidHandshakeException( "Invalid status line received: " + firstLineTokens[2] + " Status line: " + line);
		}
		ClientHandshakeBuilder clienthandshake = new HandshakeImpl1Client();
		clienthandshake.setResourceDescriptor( firstLineTokens[ 1 ] );
		handshake = clienthandshake;
	}

	line = readStringLine( buf );
	while ( line != null && line.length() > 0 ) {
		String[] pair = line.split( ":", 2 );
		if( pair.length != 2 )
			throw new InvalidHandshakeException( "not an http header" );
		// If the handshake contains already a specific key, append the new value
		if ( handshake.hasFieldValue( pair[ 0 ] ) ) {
			handshake.put( pair[0], handshake.getFieldValue( pair[ 0 ] ) + "; " + pair[1].replaceFirst( "^ +", "" ) );
		} else {
			handshake.put( pair[0], pair[1].replaceFirst( "^ +", "" ) );
		}
		line = readStringLine( buf );
	}
	if( line == null )
		throw new IncompleteHandshakeException();
	return handshake;
}

private static void appendEscaped(Appendable accum, OutputSettings out, int options,
    int codePoint, EscapeMode escapeMode, CharsetEncoder encoder, CoreCharset coreCharset) throws IOException {

    // surrogate pairs, split implementation for efficiency on single char common case (saves creating strings, char[]):
    final char c = (char) codePoint;
    if (codePoint < Character.MIN_SUPPLEMENTARY_CODE_POINT) {
        // html specific and required escapes:
        switch (c) {
            case '&':
                accum.append("&amp;");
                break;
            case 0xA0:
                appendNbsp(accum, escapeMode);
                break;
            case '<':
                // escape when in character data or when in a xml attribute val or XML syntax; not needed in html attr val
                appendLt(accum, options, escapeMode, out);
                break;
            case '>':
                if ((options & ForText) != 0) accum.append("&gt;");
                else accum.append(c);
                break;
            case '"':
                if ((options & ForAttribute) != 0) accum.append("&quot;");
                else accum.append(c);
                break;
            case '\'':
                // special case for the Entities.escape(string) method when we are maximally escaping. Otherwise, because we output attributes in "", there's no need to escape.
                appendApos(accum, options, escapeMode);
                break;
            // we escape ascii control <x20 (other than tab, line-feed, carriage return) for XML compliance (required) and HTML ease of reading (not required) - https://www.w3.org/TR/xml/#charsets
            case 0x9:
            case 0xA:
            case 0xD:
                accum.append(c);
                break;
            default:
                if (c < 0x20 || !canEncode(coreCharset, c, encoder)) appendEncoded(accum, escapeMode, codePoint);
                else accum.append(c);
        }
    } else {
        if (canEncode(coreCharset, c, encoder)) {
            String s = new String(Character.toChars(codePoint));
            accum.append(s);
        } else appendEncoded(accum, escapeMode, codePoint);
    }
}

@Override
public final void onWebsocketClose( WebSocket conn, int code, String reason, boolean remote ) {
	oqueue.add( (WebSocketImpl) conn );// because the ostream will close the channel
	selector.wakeup();
	try {
		if( removeConnection( conn ) ) {
			onClose( conn, code, reason, remote );
		}
	} finally {
		try {
			releaseBuffers( conn );
		} catch ( InterruptedException e ) {
			Thread.currentThread().interrupt();
		}
	}

}

