static void escape(Appendable accum, String string, OutputSettings out,
                   boolean forText, boolean forAttribute, boolean normaliseWhite, boolean stripLeadingWhite, boolean trimTrailing) throws IOException {

    boolean lastWasWhite = false;
    boolean reachedNonWhite = false;
    final EscapeMode escapeMode = out.escapeMode();
    final CharsetEncoder encoder = out.encoder();
    final CoreCharset coreCharset = out.coreCharset; // init in out.prepareEncoder()
    final int length = string.length();

    int codePoint;
    boolean skipped = false;
    for (int offset = 0; offset < length; offset += Character.charCount(codePoint)) {
        codePoint = string.codePointAt(offset);

        if (normaliseWhite) {
            if (StringUtil.isWhitespace(codePoint)) {
                if (stripLeadingWhite && !reachedNonWhite) continue;
                if (lastWasWhite) continue;
                if (trimTrailing) {
                    skipped = true;
                    continue;
                }
                accum.append(' ');
                lastWasWhite = true;
                continue;
            } else {
                lastWasWhite = false;
                reachedNonWhite = true;
                if (skipped) {
                    accum.append(' '); // wasn't the end, so need to place a normalized space
                    skipped = false;
                }
            }
        }
        // surrogate pairs, split implementation for efficiency on single char common case (saves creating strings, char[]):
        if (codePoint < Character.MIN_SUPPLEMENTARY_CODE_POINT) {
            final char c = (char) codePoint;
            // html specific and required escapes:
            switch (c) {
                case '&':
                    accum.append("&amp;");
                    break;
                case 0xA0:
                    if (escapeMode != EscapeMode.xhtml)
                        accum.append("&nbsp;");
                    else
                        accum.append("&#xa0;");
                    break;
                case '<':
                    // escape when in character data or when in a xml attribute val or XML syntax; not needed in html attr val
                    if (forText || escapeMode == EscapeMode.xhtml || out.syntax() == Syntax.xml)
                        accum.append("&lt;");
                    else
                        accum.append(c);
                    break;
                case '>':
                    if (forText)
                        accum.append("&gt;");
                    else
                        accum.append(c);
                    break;
                case '"':
                    if (forAttribute)
                        accum.append("&quot;");
                    else
                        accum.append(c);
                    break;
                case '\'':
                    if (forAttribute && forText) { // special case for the Entities.escape(string) method when we are maximally escaping. Otherwise, because we output attributes in "", there's no need to escape.
                        if (escapeMode == EscapeMode.xhtml)
                            accum.append("&#x27;");
                        else
                            accum.append("&apos;");
                    }
                    else
                        accum.append(c);
                    break;
                // we escape ascii control <x20 (other than tab, line-feed, carriage return)  for XML compliance (required) and HTML ease of reading (not required) - https://www.w3.org/TR/xml/#charsets
                case 0x9:
                case 0xA:
                case 0xD:
                    accum.append(c);
                    break;
                default:
                    if (c < 0x20 || !canEncode(coreCharset, c, encoder))
                        appendEncoded(accum, escapeMode, codePoint);
                    else
                        accum.append(c);
            }
        } else {
            final String c = new String(Character.toChars(codePoint));
            if (encoder.canEncode(c)) // uses fallback encoder for simplicity
                accum.append(c);
            else
                appendEncoded(accum, escapeMode, codePoint);
        }
    }
}

public void head(org.jsoup.nodes.Node source, int depth) {
    namespacesStack.push(new HashMap<>(namespacesStack.peek())); // inherit from above on the stack
    if (source instanceof org.jsoup.nodes.Element) {
        org.jsoup.nodes.Element sourceEl = (org.jsoup.nodes.Element) source;

        String prefix = updateNamespaces(sourceEl);
        String namespace = namespacesStack.peek().get(prefix);
        String tagName = sourceEl.tagName();

        /* Tag names in XML are quite, but less, permissive than HTML. Rather than reimplement the validation,
        we just try to use it as-is. If it fails, insert as a text node instead. We don't try to normalize the
        tagname to something safe, because that isn't going to be meaningful downstream. This seems(?) to be
        how browsers handle the situation, also. https://github.com/jhy/jsoup/issues/1093 */
        try {
            Element el = namespace == null && tagName.contains(":") ?
                doc.createElementNS("", tagName) : // doesn't have a real namespace defined
                doc.createElementNS(namespace, tagName);
            copyAttributes(sourceEl, el);
            dest.appendChild(el);
            dest = el; // descend
        } catch (DOMException e) {
            dest.appendChild(doc.createTextNode("<" + tagName + ">"));
        }
    } else if (source instanceof org.jsoup.nodes.TextNode) {
        org.jsoup.nodes.TextNode sourceText = (org.jsoup.nodes.TextNode) source;
        Text text = doc.createTextNode(sourceText.getWholeText());
        dest.appendChild(text);
    } else if (source instanceof org.jsoup.nodes.Comment) {
        org.jsoup.nodes.Comment sourceComment = (org.jsoup.nodes.Comment) source;
        Comment comment = doc.createComment(sourceComment.getData());
        dest.appendChild(comment);
    } else if (source instanceof org.jsoup.nodes.DataNode) {
        org.jsoup.nodes.DataNode sourceData = (org.jsoup.nodes.DataNode) source;
        Text node = doc.createTextNode(sourceData.getWholeData());
        dest.appendChild(node);
    } else {
        // unhandled
        // not that doctype is not handled here - rather it is used in the initial doc creation
    }
}

/**
 * Normalise the whitespace within this string; multiple spaces collapse to a single, and all whitespace characters
 * (e.g. newline, tab) convert to a simple space
 * @param string content to normalise
 * @return normalised string
 */
public static String normaliseWhitespace(String string) {
    StringBuilder sb = new StringBuilder(string.length());
    appendNormalisedWhitespace(sb, string, false);
    return sb.toString();
