public Range.AttributeRange sourceRange(String key) {
    if (!hasKey(key)) return UntrackedAttr;
    //noinspection unchecked
    Map<String, Range.AttributeRange> ranges = (Map<String, Range.AttributeRange>) userData(AttrRangeKey);
