/**
 * Constructor for the websocket protocol specified by RFC 6455 with custom extensions and protocols
 *
 * @param inputExtensions the extensions which should be used for this draft
 * @param inputProtocols the protocols which should be used for this draft
 *
 * @since 1.3.7
 */
public Draft_6455( List<IExtension> inputExtensions , List<IProtocol> inputProtocols ) {
	if (inputExtensions == null || inputProtocols == null) {
		throw new IllegalArgumentException();
	}
	knownExtensions = new ArrayList<IExtension>( inputExtensions.size());
	knownProtocols = new ArrayList<IProtocol>( inputProtocols.size());
	boolean hasDefault = false;
	byteBufferList = new ArrayList<ByteBuffer>();
	for( IExtension inputExtension : inputExtensions ) {
		if( inputExtension.getClass().equals( DefaultExtension.class ) ) {
			hasDefault = true;
		}
	}
	knownExtensions.addAll( inputExtensions );
	//We always add the DefaultExtension to implement the normal RFC 6455 specification
	if( !hasDefault ) {
		knownExtensions.add( this.knownExtensions.size(), extension );
	}
	knownProtocols.addAll( inputProtocols );
}

public void run() {
  running = tryToConnect(new InetSocketAddress(uri.getHost(), getPort()));

  while (this.running) {
    try {
      selector.select();
      Set<SelectionKey> keys = selector.selectedKeys();
      Iterator<SelectionKey> i = keys.iterator();

      while (i.hasNext()) {
        SelectionKey key = i.next();
        i.remove();

        if (key.isConnectable()) {
          finishConnect();
        }

        if (key.isReadable()) {
          conn.handleRead();
        }
      }
    } catch (IOException ex) {
  	  onIOError(conn, ex);
    } catch (NoSuchAlgorithmException ex) {
      ex.printStackTrace();
    }
  }

  //System.err.println("WebSocketClient thread ended!");
}

static Response execute(Connection.Request req) throws IOException {
    Validate.notNull(req, "Request must not be null");
    String protocol = req.url().getProtocol();
    Validate
        .isTrue(protocol.equals("http") || protocol.equals("https"), "Only http & https protocols supported");

    // set up the request for execution
    if (req.method() == Connection.Method.GET && req.data().size() > 0)
        serialiseRequestUrl(req); // appends query string
    HttpURLConnection conn = createConnection(req);
    conn.connect();
    if (req.method() == Connection.Method.POST)
        writePost(req.data(), conn.getOutputStream());          

    // todo: error handling options, allow user to get !200 without exception
    int status = conn.getResponseCode();
    boolean needsRedirect = false;
    if (status != HttpURLConnection.HTTP_OK) {
        // java url connection will follow redirects on same protocol, but not switch between http & https, so do that here
        if (status == HttpURLConnection.HTTP_MOVED_TEMP || status == HttpURLConnection.HTTP_MOVED_PERM || status == HttpURLConnection.HTTP_SEE_OTHER)
            needsRedirect = true;
        else
            throw new IOException(status + " error loading URL " + req.url().toString());
    }
    Response res = new Response();
    res.setupFromConnection(conn);
    if (needsRedirect) {
        req.url(new URL(res.header("Location")));
        return execute(req);
    }

    InputStream inStream = null;
    try {
        inStream = res.hasHeader("Content-Encoding") && res.header("Content-Encoding").equalsIgnoreCase("gzip") ?
                new BufferedInputStream(new GZIPInputStream(conn.getInputStream())) :
                new BufferedInputStream(conn.getInputStream());
        res.byteData = DataUtil.readToByteBuffer(inStream);
        res.charset = getCharsetFromContentType(res.contentType); // may be null, readInputStream deals with it
    } finally {
        if (inStream != null) inStream.close();
    }

    res.executed = true;
    return res;
}

