	@Override
	public HandshakeState acceptHandshakeAsServer( ClientHandshake handshakedata ) throws InvalidHandshakeException {
		int v = readVersion( handshakedata );
		if( v != 13 ) {
			log.trace("acceptHandshakeAsServer - Wrong websocket version.");
			return HandshakeState.NOT_MATCHED;
		}
		HandshakeState extensionState = HandshakeState.NOT_MATCHED;
		String requestedExtension = handshakedata.getFieldValue(SEC_WEB_SOCKET_EXTENSIONS);
        for( IExtension knownExtension : knownExtensions ) {
            if( knownExtension.acceptProvidedExtensionAsServer( requestedExtension ) ) {
                extension = knownExtension;
                extensionState = HandshakeState.MATCHED;
                log.trace("acceptHandshakeAsServer - Matching extension found: {}", extension);
                break;
            }
        }
		HandshakeState protocolState = containsRequestedProtocol(handshakedata.getFieldValue(SEC_WEB_SOCKET_PROTOCOL));
		if (protocolState == HandshakeState.MATCHED && extensionState == HandshakeState.MATCHED) {
			return HandshakeState.MATCHED;
		}
		log.trace("acceptHandshakeAsServer - No matching extension or protocol found.");
		return HandshakeState.NOT_MATCHED;
	}

public void run() {
	if( selectorthread != null )
		throw new IllegalStateException( "This instance of " + getClass().getSimpleName() + " can only be started once the same time." );
	selectorthread = Thread.currentThread();
	try {
		server = ServerSocketChannel.open();
		server.configureBlocking( false );
		server.socket().bind( address );
		// InetAddress.getLocalHost()
		selector = Selector.open();
		server.register( selector, server.validOps() );
	} catch ( IOException ex ) {
		onWebsocketError( null, ex );
		return;
	}
	try {
		while ( !selectorthread.isInterrupted() ) {
			SelectionKey key = null;
			WebSocket conn = null;
			try {
				selector.select();
				Set<SelectionKey> keys = selector.selectedKeys();
				Iterator<SelectionKey> i = keys.iterator();

				while ( i.hasNext() ) {
					key = i.next();

					if( !key.isValid() ) {
						// Object o = key.attachment();
						continue;
					}

					if( key.isAcceptable() ) {
						SocketChannel client = server.accept();
						client.configureBlocking( false );
						WebSocket c = new WebSocket( this, Collections.singletonList( draft ), client );
						client.register( selector, SelectionKey.OP_READ, c );
						i.remove();
					} else if( key.isReadable() ) {
						conn = (WebSocket) key.attachment();
						if( asyncQueueRead( conn ) ) {
							i.remove();
						}
					}
				}
			} catch ( IOException ex ) {
				if( key != null )
					key.cancel();
				handleIOException( conn, ex );
			}
		}
	} catch ( RuntimeException e ) {
		// should hopefully never occur
		handleFatal( null, e );
	}
}

boolean process(Token t, HtmlTreeBuilder tb) {
    switch (t.type) {
        case Character: {
            Token.Character c = t.asCharacter();
            if (c.getData().equals(nullString)) {
                // todo confirm that check
                tb.error(this);
                return false;
            } else if (tb.framesetOk() && isWhitespace(c)) { // don't check if whitespace if frames already closed
                tb.reconstructFormattingElements();
                tb.insert(c);
            } else {
                tb.reconstructFormattingElements();
                tb.insert(c);
                tb.framesetOk(false);
            }
            break;
        }
        case Comment: {
            tb.insert(t.asComment());
            break;
        }
        case Doctype: {
            tb.error(this);
            return false;
        }
        case StartTag:
            return inBodyStartTag(t, tb);
        case EndTag:
            return inBodyEndTag(t, tb);
        case EOF:
            // todo: error if stack contains something not dd, dt, li, p, tbody, td, tfoot, th, thead, tr, body, html
            // stop parsing
            break;
    }
    return true;
}

static void escape(Appendable accum, String string, OutputSettings out,
                   boolean forText, boolean forAttribute, boolean normaliseWhite, boolean stripLeadingWhite, boolean trimTrailing) throws IOException {

    boolean lastWasWhite = false;
    boolean reachedNonWhite = false;
    final EscapeMode escapeMode = out.escapeMode();
    final CharsetEncoder encoder = out.encoder();
    final CoreCharset coreCharset = out.coreCharset; // init in out.prepareEncoder()
    final int length = string.length();

    int codePoint;
    boolean skipped = false;
    for (int offset = 0; offset < length; offset += Character.charCount(codePoint)) {
        codePoint = string.codePointAt(offset);

        if (normaliseWhite) {
            if (StringUtil.isWhitespace(codePoint)) {
                if (stripLeadingWhite && !reachedNonWhite) continue;
                if (lastWasWhite) continue;
                if (trimTrailing) {
                    skipped = true;
                    continue;
                }
                accum.append(' ');
                lastWasWhite = true;
                continue;
            } else {
                lastWasWhite = false;
                reachedNonWhite = true;
                if (skipped) {
                    accum.append(' '); // wasn't the end, so need to place a normalized space
                    skipped = false;
                }
            }
        }
        // surrogate pairs, split implementation for efficiency on single char common case (saves creating strings, char[]):
        if (codePoint < Character.MIN_SUPPLEMENTARY_CODE_POINT) {
            final char c = (char) codePoint;
            // html specific and required escapes:
            switch (c) {
                case '&':
                    accum.append("&amp;");
                    break;
                case 0xA0:
                    if (escapeMode != EscapeMode.xhtml)
                        accum.append("&nbsp;");
                    else
                        accum.append("&#xa0;");
                    break;
                case '<':
                    // escape when in character data or when in a xml attribute val or XML syntax; not needed in html attr val
                    if (forText || escapeMode == EscapeMode.xhtml || out.syntax() == Syntax.xml)
                        accum.append("&lt;");
                    else
                        accum.append(c);
                    break;
                case '>':
                    if (forText)
                        accum.append("&gt;");
                    else
                        accum.append(c);
                    break;
                case '"':
                    if (forAttribute)
                        accum.append("&quot;");
                    else
                        accum.append(c);
                    break;
                case '\'':
                    if (forAttribute && forText) { // special case for the Entities.escape(string) method when we are maximally escaping. Otherwise, because we output attributes in "", there's no need to escape.
                        if (escapeMode == EscapeMode.xhtml)
                            accum.append("&#x27;");
                        else
                            accum.append("&apos;");
                    }
                    else
                        accum.append(c);
                    break;
                // we escape ascii control <x20 (other than tab, line-feed, carriage return)  for XML compliance (required) and HTML ease of reading (not required) - https://www.w3.org/TR/xml/#charsets
                case 0x9:
                case 0xA:
                case 0xD:
                    accum.append(c);
                    break;
                default:
                    if (c < 0x20 || !canEncode(coreCharset, c, encoder))
                        appendEncoded(accum, escapeMode, codePoint);
                    else
                        accum.append(c);
            }
        } else {
            final String c = new String(Character.toChars(codePoint));
            if (encoder.canEncode(c)) // uses fallback encoder for simplicity
                accum.append(c);
            else
                appendEncoded(accum, escapeMode, codePoint);
        }
    }
}

/**
 * If this InputStream is not already a ControllableInputStream, let it be one.
 * @param in the input stream to (maybe) wrap
 * @param bufferSize the buffer size to use when reading
 * @param maxSize the maximum size to allow to be read. 0 == infinite.
 * @return a controllable input stream
 */
public static ControllableInputStream wrap(InputStream in, int bufferSize, int maxSize) {
    if (in instanceof ControllableInputStream)
        return (ControllableInputStream) in;
    else if (in instanceof BufferedInputStream)
        return new ControllableInputStream((BufferedInputStream) in, maxSize);
    else
        return new ControllableInputStream(new BufferedInputStream(in, bufferSize), maxSize);
}
